window.PEPP_DATA = {"manifest":{"id":"pepp","title":"PEPP — Pediatric Education for Prehospital Professionals","subtitle":"The Ultimate Provider Course Reviewer","version":"1.0.0","edition":"Based on the AAP PEPP, 4th Edition","description":"A comprehensive, self-contained study reviewer for Pediatric Education for Prehospital Professionals. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, decision trees, high-yield flashcards, PEPP-style quiz questions, and realistic pediatric scenarios. Built around the Pediatric Assessment Triangle, spanning both BLS- and ALS-level prehospital pediatric care, for EMTs, AEMTs, paramedics, and other prehospital providers.","icon":"baby","color":"#2ea043","accentColor":"#e06090","estimatedHours":14,"difficulty":"Beginner to Advanced","certification":"AAP PEPP Provider (BLS or ALS track)","examLink":"https://www.aap.org/en/pedialink/pediatric-education-for-prehospital-professionals/","audience":["EMT","AEMT","Paramedic","EMS Student"],"prerequisites":["Current BLS provider competency","PALS knowledge helpful but not required"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Why Children Are Different: Developmental & Anatomic Considerations","section":"Foundations","difficulty":"Beginner"},{"id":"c02","number":2,"title":"The Pediatric Assessment Triangle","section":"Foundations","difficulty":"Beginner"},{"id":"c03","number":3,"title":"Primary Assessment (ABCDE) & Scene Size-Up","section":"Foundations","difficulty":"Intermediate"},{"id":"c04","number":4,"title":"History Taking, Secondary Assessment & Family-Centered Communication","section":"Foundations","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Respiratory Distress & Respiratory Failure","section":"Respiratory","difficulty":"Intermediate"},{"id":"c06","number":6,"title":"Shock Recognition & Field Management","section":"Circulation","difficulty":"Intermediate"},{"id":"c07","number":7,"title":"Cardiac Emergencies & Rhythm Recognition","section":"Circulation","difficulty":"Intermediate"},{"id":"c08","number":8,"title":"Neurologic Emergencies: Altered Mental Status & Seizures","section":"Neurologic","difficulty":"Intermediate"},{"id":"c09","number":9,"title":"Trauma: Assessment & Field Stabilization","section":"Trauma","difficulty":"Advanced"},{"id":"c10","number":10,"title":"Toxic Exposures & Environmental Emergencies","section":"Medical","difficulty":"Intermediate"},{"id":"c11","number":11,"title":"Neonatal Care & Resuscitation Basics","section":"Neonatal","difficulty":"Advanced"},{"id":"c12","number":12,"title":"Child Maltreatment Recognition","section":"Special Populations","difficulty":"Intermediate"},{"id":"c13","number":13,"title":"Children With Special Healthcare Needs & Technology Dependence","section":"Special Populations","difficulty":"Intermediate"},{"id":"c14","number":14,"title":"EMS Operations: Transport Decisions, Disaster & MCI Triage Involving Children","section":"Operations","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Why Children Are Different: Developmental & Anatomic Considerations","shortTitle":"Why Children Are Different","estimatedStudyTime":26,"difficulty":"Beginner","learningObjectives":["Explain why 'children are not small adults' as an organizing principle of pediatric prehospital care.","Describe key airway anatomic differences between children and adults.","Describe key differences in pediatric breathing mechanics and metabolic demand.","Describe key differences in pediatric circulating blood volume and compensatory capacity.","Relate developmental stage to communication and cooperation during assessment.","Use age-banded normal vital signs as a baseline for recognizing abnormal findings."],"summary":[{"title":"Children Are Not Small Adults","content":"The single organizing idea behind PEPP is that children differ from adults anatomically, physiologically, developmentally, and psychosocially — not just in size. A treatment or assessment approach scaled down from an adult protocol without accounting for these differences will miss findings or cause harm. This chapter lays the anatomic and developmental groundwork that every later PEPP chapter builds on."},{"title":"Airway: Small, Anterior, and Easily Obstructed","content":"A child's tongue is proportionally larger relative to the oropharynx, the airway is narrower at every level, and the larynx sits more anterior and cephalad (higher in the neck) than in an adult. The narrowest part of the pediatric airway is subglottic (below the vocal cords) in young children, unlike the adult airway, which narrows at the cords. These differences make children more prone to airway obstruction from secretions, a large tongue, or swelling, and require different airway-positioning and equipment-sizing approaches than adult care."},{"title":"Breathing: Higher Demand, Less Reserve","content":"Children have a higher metabolic rate and oxygen consumption per kilogram than adults, but smaller functional residual capacity (oxygen reserve in the lungs). Infants are primarily diaphragmatic breathers with a more compliant (flexible) chest wall, meaning they generate less effective negative pressure and fatigue faster during increased work of breathing. The practical result: children desaturate faster than adults when breathing is compromised, and respiratory problems are the leading pathway to pediatric cardiac arrest."},{"title":"Circulation: Small Volume, Strong Compensation, Then Collapse","content":"A child's absolute circulating blood volume is small, so even modest-seeming blood or fluid losses represent a larger percentage of total volume than the same loss would in an adult. Children compensate remarkably well for volume loss through tachycardia and vasoconstriction, often maintaining a normal blood pressure until a large percentage of volume is lost — meaning blood pressure is a late and unreliable early warning sign in children. When compensation fails, children can decompensate rapidly and with little warning."},{"title":"Developmental Stage Shapes the Encounter","content":"How a child responds to assessment, and how a provider should approach them, changes by developmental stage: infants respond to caregivers' calm presence and are assessed largely by observation; toddlers and preschoolers fear separation from caregivers and unfamiliar equipment, and benefit from keeping the caregiver close and demonstrating equipment on a doll or the caregiver first; school-age children can usually cooperate with direct, honest explanation; adolescents want privacy, respect, and honesty, and may be interviewed partly apart from caregivers. Matching the approach to developmental stage improves both cooperation and the accuracy of the assessment."},{"title":"Why Age-Banded Vital Signs Matter","content":"Because normal heart rate, respiratory rate, and blood pressure change substantially across childhood, a single 'normal vitals' reference is useless in pediatrics. Every vital sign must be interpreted against the age-appropriate normal range (see the table in this chapter), and — critically — trends and the overall clinical picture (the Pediatric Assessment Triangle, covered next chapter) matter more than any single vital sign in isolation."}],"clinicalPearls":["'Children are not small adults' — anatomic, physiologic, developmental, and psychosocial differences change assessment and care at every step.","The pediatric airway's narrowest point is subglottic, below the vocal cords, unlike the adult airway.","Respiratory problems are the leading pathway to pediatric cardiac arrest — protecting breathing protects the whole child.","Blood pressure is a late sign in pediatric shock; children compensate well, then decompensate fast.","Match your approach to developmental stage — a toddler and an adolescent need very different communication styles."],"redFlags":["Using an unmodified adult mental model for airway, breathing, or circulation assessment in a child.","Reassurance from a 'normal' blood pressure in a child with tachycardia and other perfusion concerns.","Approaching a toddler by separating them from a caregiver or leading with unfamiliar equipment."],"commonMistakes":["Treating a single vital sign as normal or abnormal without checking it against the age-appropriate range.","Assuming a calm-appearing infant is not working hard to breathe, when diaphragmatic breathing and chest-wall compliance mask early distress.","Ignoring developmental stage and using the same communication approach for a toddler and a teenager."],"memoryAids":["Children are not small adults — different anatomy, physiology, development, and psychosocial needs.","Pediatric airway = narrow, anterior, subglottic narrowest point.","Compensate hard, then collapse fast — blood pressure lags in pediatric shock.","Match communication to developmental stage, not just to age in years."],"decisionTrees":[{"title":"Applying Age-Appropriate Context to Any Finding","content":"Vital sign or exam finding obtained\n  → Identify the child's age band (see Age-Banded Normal Vital Signs table)\n  → Compare the finding to that age band's normal range — NOT an adult or generic pediatric range\n  → Consider developmental stage for how the assessment itself was obtained (cooperative vs. observed-only)\n  → Weigh the finding within the overall clinical gestalt (Pediatric Assessment Triangle), not in isolation"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Developmental and Anatomic Considerations","courses/pals/data/pals/tables/c01.json — Age-Banded Normal Pediatric Vital Signs (reused exactly)"]},"c02":{"id":"c02","title":"The Pediatric Assessment Triangle","shortTitle":"Pediatric Assessment Triangle","estimatedStudyTime":35,"difficulty":"Beginner","learningObjectives":["Define the Pediatric Assessment Triangle (PAT) and its three legs.","Assess Appearance using observable behavioral characteristics.","Assess Work of Breathing using visual and auditory cues, without a stethoscope.","Assess Circulation to Skin using color and temperature cues.","Use the PAT to form a general impression of 'sick vs. not sick' and likely physiologic category.","Explain why the PAT is performed before, not instead of, hands-on primary assessment."],"summary":[{"title":"What the PAT Is","content":"The Pediatric Assessment Triangle (PAT) is PEPP's signature tool: a rapid, hands-off, across-the-room visual and auditory assessment performed within the first seconds of encountering a child, before you ever touch the patient. It has three legs — Appearance, Work of Breathing, and Circulation to Skin — assessed together to form a general impression of how sick the child is and which body system is likely involved, guiding the pace and priority of everything that follows."},{"title":"Leg 1 — Appearance","content":"Appearance captures the child's overall level of interaction with the environment and is often summarized with the mnemonic TICLS: Tone (moving spontaneously or limp), Interactiveness (alert and engaged, or uninterested), Consolability (can they be comforted, or are they inconsolable), Look/Gaze (do they fix their gaze on you or a caregiver, or stare blankly), and Speech/Cry (strong and appropriate for age, or weak/muffled/absent). Appearance is the single most sensitive PAT leg for detecting adequacy of oxygenation, ventilation, brain perfusion, and CNS function — an abnormal Appearance is a red flag even when the other two legs look normal."},{"title":"Leg 2 — Work of Breathing","content":"Work of Breathing is assessed by listening and looking, without a stethoscope: abnormal airway sounds (stridor, grunting, wheezing, muffled voice), abnormal positioning (tripod position, sniffing position, refusal to lie down), retractions (visible pulling in at the suprasternal, intercostal, or subcostal areas), and nasal flaring or head bobbing. Work of Breathing reflects the child's effort to compensate for an oxygenation or ventilation problem, and increases before oxygen saturation necessarily falls — it is an early window into respiratory status."},{"title":"Leg 3 — Circulation to Skin","content":"Circulation to Skin assesses perfusion by looking at skin and mucous membrane color: pallor (pale, poor perfusion), mottling (patchy discoloration), and cyanosis (bluish, indicating significant hypoxemia), assessed against the child's baseline skin tone in adequate lighting. This leg reflects how well the core is perfusing the periphery and is an early clue to shock, sometimes appearing before other perfusion signs are measurable."},{"title":"Putting the Three Legs Together","content":"No single leg is assessed in isolation — the pattern across all three legs points toward a likely physiologic category. Abnormal Appearance with normal Work of Breathing and Circulation suggests a primarily CNS/metabolic problem. Abnormal Appearance and Work of Breathing with normal Circulation suggests a respiratory problem. Abnormal Appearance and Circulation with normal Work of Breathing suggests a circulatory/shock problem. Abnormal findings across all three legs suggest a severe, multi-system problem (cardiopulmonary failure) requiring the most urgent response. This pattern recognition takes seconds and drives the pace of everything that follows."},{"title":"The PAT Comes First, Not Instead","content":"The PAT is completed before hands-on primary assessment (ABCDE) begins — it sets the general impression and urgency level that shapes how quickly and in what order the primary assessment proceeds, but it does not replace it. A child who looks fine on PAT still gets a full primary assessment; a child who looks critically ill on PAT gets that primary assessment started immediately and rapidly, potentially with simultaneous life-saving interventions. The PAT is the 'from the doorway' first 15 seconds of every pediatric encounter in PEPP."}],"clinicalPearls":["PAT = Appearance + Work of Breathing + Circulation to Skin — hands-off, done from across the room, in the first seconds of contact.","TICLS for Appearance: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","Abnormal Appearance alone, even with normal breathing and circulation, is a red flag — it's the most sensitive PAT leg.","The PAT sets your pace; it never replaces the hands-on primary assessment that follows it."],"redFlags":["An inconsolable, limp, or gaze-unfocused child (abnormal Appearance) — treat as high acuity regardless of vital signs not yet obtained.","Retractions, grunting, or head bobbing (abnormal Work of Breathing) — signs of significant respiratory effort, act before full desaturation occurs.","Mottled or cyanotic skin (abnormal Circulation to Skin) — a perfusion problem is already underway."],"commonMistakes":["Reaching for a stethoscope or BP cuff before completing the hands-off PAT.","Treating one PAT leg as the whole picture instead of reading the pattern across all three.","Skipping the primary assessment because the PAT looked reassuring."],"memoryAids":["PAT legs: Appearance, Work of Breathing, Circulation to Skin.","TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","1 abnormal leg = CNS/metabolic; 2 legs (Appearance+WOB) = respiratory; 2 legs (Appearance+Circ) = shock; all 3 = cardiopulmonary failure.","PAT is the first 15 seconds — from the doorway, before you touch the child."],"decisionTrees":[{"title":"Pediatric Assessment Triangle Pattern Recognition","content":"From across the room, assess all three legs simultaneously:\n  Appearance (TICLS) | Work of Breathing | Circulation to Skin\n\nPattern → Likely category:\n  Abnormal Appearance ONLY → CNS/metabolic problem\n  Abnormal Appearance + Work of Breathing → Respiratory problem\n  Abnormal Appearance + Circulation → Shock (circulatory problem)\n  Abnormal ALL THREE → Cardiopulmonary failure (highest urgency)\n  All THREE normal → Stable general impression, proceed to routine primary assessment\n\n  → In every case, PAT sets urgency, then proceed to full ABCDE primary assessment"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — The Pediatric Assessment Triangle","courses/pals/data/pals/tables/c01.json — Pediatric Assessment Triangle: Components and Findings (cross-referenced, not duplicated verbatim)"]},"c03":{"id":"c03","title":"Primary Assessment (ABCDE) & Scene Size-Up","shortTitle":"Primary Assessment (ABCDE)","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Perform a pediatric-appropriate scene size-up.","Perform the hands-on primary assessment in ABCDE order.","Identify and immediately treat life threats found during the primary assessment.","Explain the relationship between the PAT and the primary assessment.","Determine an overall patient priority (high vs. low acuity) from the primary assessment."],"summary":[{"title":"Scene Size-Up in the Pediatric Setting","content":"Scene size-up for a pediatric call includes standard precautions and hazard assessment, plus pediatric-specific attention: the mechanism of injury or nature of illness, the number of patients (children are frequently involved in multi-victim events like car crashes or household incidents), and early clues from the environment (medication bottles, home safety hazards, caregiver affect). Involving a calm caregiver early, when safe to do so, often improves both scene safety and the child's cooperation."},{"title":"The Primary Assessment: ABCDE","content":"After the PAT gives a general impression, the hands-on primary assessment follows the ABCDE sequence: Airway (patent? maintainable?), Breathing (rate, effort, breath sounds, oxygen saturation), Circulation (pulse rate/quality, skin perfusion, capillary refill, external bleeding), Disability (rapid neurologic check — AVPU or similar, pupils, blood glucose if altered), and Exposure (undress as needed to assess for injury/rash/other findings, then keep the child warm). This is the same spine used in PALS, but PEPP frames it as a field assessment and transport-decision tool rather than a resuscitation-team algorithm — see the PALS reviewer for cardiac-arrest-specific ABCDE depth."},{"title":"Treating Life Threats Immediately","content":"Any life threat identified during the primary assessment — an obstructed airway, absent or grossly inadequate breathing, uncontrolled hemorrhage — is treated the moment it is found, before moving to the next letter of ABCDE. The primary assessment is not a checklist to complete before acting; it is an ordered scan that triggers immediate intervention at whichever step reveals the problem."},{"title":"How the PAT and Primary Assessment Fit Together","content":"The PAT (previous chapter) is the hands-off, from-the-doorway general impression; the primary assessment is the hands-on, structured ABCDE exam that follows it. A high-acuity PAT (e.g., cardiopulmonary failure pattern) means the primary assessment proceeds immediately and rapidly, often with simultaneous interventions rather than a strict sequential exam. A reassuring PAT means the primary assessment proceeds at a calmer, still-thorough pace. Neither tool substitutes for the other."},{"title":"Assigning Priority","content":"The primary assessment concludes with an overall priority determination: high-priority (unstable PAT and/or ABCDE findings, needing rapid transport and possibly ALS intercept) versus low-priority (stable findings, allowing a more complete secondary assessment on scene). This priority decision — not a specific diagnosis — is the primary assessment's main deliverable, and it directly drives the pace of everything in the next chapter (history-taking and secondary assessment)."}],"clinicalPearls":["Scene size-up for pediatric calls includes hazard assessment plus early attention to mechanism/nature of illness and caregiver affect.","ABCDE: Airway, Breathing, Circulation, Disability, Exposure — treat each life threat the moment it's found, don't wait to finish the checklist.","The PAT sets the pace; the primary assessment is the hands-on exam that follows it — neither replaces the other.","The primary assessment's main output is a priority decision (high vs. low), not a diagnosis."],"redFlags":["An obstructed or threatened airway found during 'A' — stop and treat before continuing to 'B'.","Absent breath sounds or grossly inadequate breathing found during 'B' — treat immediately.","Uncontrolled external hemorrhage found during 'C' — control it before moving on."],"commonMistakes":["Completing the entire ABCDE sequence before treating a life threat found early in the exam.","Skipping the primary assessment because the PAT looked reassuring.","Failing to reassess priority as new findings emerge."],"memoryAids":["ABCDE: Airway, Breathing, Circulation, Disability, Exposure.","Find it, fix it — treat the life threat the moment you find it, not after finishing the alphabet.","PAT sets the pace, ABCDE does the exam.","Primary assessment's job: decide priority, not diagnosis."],"decisionTrees":[{"title":"Pediatric Primary Assessment Sequence","content":"Scene size-up (safety, precautions, MOI/NOI, patient count)\n  → PAT (from previous chapter) sets urgency\n  → Primary assessment, ABCDE, in order:\n     A — Airway: patent? maintainable? → fix immediately if not\n     B — Breathing: rate, effort, sounds, SpO2 → fix immediately if inadequate\n     C — Circulation: pulse, perfusion, cap refill, bleeding → fix immediately if compromised\n     D — Disability: rapid neuro check, glucose if altered\n     E — Exposure: assess for injury/rash, then keep warm\n  → Assign priority: HIGH (rapid transport/ALS intercept) or LOW (proceed to secondary assessment on scene)"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Primary Assessment","courses/pals/ — ABCDE spine cross-referenced, not duplicated for cardiac-arrest-specific depth"]},"c04":{"id":"c04","title":"History Taking, Secondary Assessment & Family-Centered Communication","shortTitle":"History & Secondary Assessment","estimatedStudyTime":28,"difficulty":"Intermediate","learningObjectives":["Obtain a pediatric-focused history using SAMPLE and event-specific questions.","Perform a developmentally appropriate secondary assessment/focused exam.","Apply family-centered care principles during assessment and treatment.","Recognize special communication needs (hearing-impaired, non-English-speaking, developmentally delayed).","Explain how caregiver presence and involvement can improve both assessment and the child's experience."],"summary":[{"title":"SAMPLE History in Children","content":"The SAMPLE history — Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading up to the incident — applies to pediatric patients with added emphasis on birth history and developmental milestones for infants, immunization status, and growth/weight trends for medication dosing. Caregivers are usually the primary historians for young children, but school-age children and adolescents should be asked directly whenever possible, with the caregiver's account used to confirm or supplement rather than replace the child's own report."},{"title":"The Secondary Assessment: Focused or Detailed Exam","content":"The secondary assessment follows the primary assessment and history, and is either a focused exam (targeted to the chief complaint, for stable/low-priority patients) or a rapid, more limited exam (for high-priority patients, performed en route). The physical exam order itself is often developmentally adjusted: for infants and toddlers, a toe-to-head sequence (least threatening areas first) improves cooperation, while school-age children and adolescents can typically tolerate a standard head-to-toe sequence."},{"title":"Family-Centered Care","content":"Family-centered care treats the caregiver as a partner in the child's care rather than an obstacle to manage. In most situations, allowing a caregiver to remain present (including during many procedures and even resuscitation, with a dedicated support person when feasible) reduces the child's distress and improves cooperation, without meaningfully slowing care. Explaining what you are doing and why, in age-appropriate and caregiver-appropriate language, builds trust and improves the accuracy of the history you receive."},{"title":"Special Communication Needs","content":"Some encounters require adapted communication: for a hearing-impaired child or caregiver, face the person directly, speak clearly (not necessarily loudly), and use written notes or an interpreter service as needed; for a non-English-speaking family, use professional interpretation services rather than relying on a child to interpret for their own care; for a child with developmental delay or autism spectrum differences, take cues from the caregiver about the child's usual communication style, minimize sensory overload where possible, and allow extra time. Adapting communication is a clinical skill, not an optional courtesy — it materially affects the quality of the history and exam you obtain."},{"title":"Building the Full Picture","content":"History-taking and secondary assessment together answer the question the primary assessment could not: not just 'how sick is this child right now,' but 'why, and what has been happening.' Combined with the PAT and primary assessment, this completes PEPP's four-part assessment sequence — PAT, primary assessment, history, secondary assessment — which then informs the treatment and transport decisions covered later in this course."}],"clinicalPearls":["SAMPLE in pediatrics adds emphasis on birth history/milestones (infants), immunizations, and growth/weight for dosing.","Ask school-age children and adolescents directly; use caregiver accounts to supplement, not replace, the child's own report.","Toe-to-head exam order reduces distress in infants/toddlers; head-to-toe works for school-age children and adolescents.","Family-centered care — keeping a caregiver present, including during many procedures — reduces distress without slowing care."],"redFlags":["Relying on a child to interpret medical information for their own non-English-speaking caregiver.","Excluding a calm, cooperative caregiver from the room by default rather than by clinical necessity.","Ignoring a caregiver's guidance on a developmentally different child's usual communication style."],"commonMistakes":["Using a head-to-toe exam order on a frightened toddler when toe-to-head would improve cooperation.","Treating the caregiver's account as automatically more reliable than an age-appropriate child's own report.","Skipping professional interpretation services when a family member could 'informally translate.'"],"memoryAids":["SAMPLE: Signs/Symptoms, Allergies, Medications, Past history, Last intake, Events.","Toe-to-head for the young and scared; head-to-toe for the older and cooperative.","Family-centered care: partner with the caregiver, don't just tolerate them.","Interpretation services, not a frightened child, translate for a non-English-speaking parent."],"decisionTrees":[{"title":"History & Secondary Assessment Sequence","content":"After primary assessment and priority assignment:\n  → Obtain SAMPLE history (ask child directly if age-appropriate; caregiver supplements)\n  → Choose exam order by development: infant/toddler → toe-to-head; school-age/adolescent → head-to-toe\n  → Perform focused (stable) or rapid (high-priority) secondary exam accordingly\n  → Apply family-centered care: keep caregiver present/involved when feasible\n  → Adapt communication for special needs: interpretation services, hearing-impaired accommodations, developmental differences\n  → Integrate findings with PAT + primary assessment to finalize treatment/transport plan"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — History Taking and Secondary Assessment","AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Family-Centered Care and Communication"]},"c05":{"id":"c05","title":"Respiratory Distress & Respiratory Failure","shortTitle":"Respiratory Distress & Failure","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Distinguish respiratory distress from respiratory failure.","Recognize the four categories of pediatric respiratory compromise.","Identify early PAT/exam findings that predict impending respiratory failure.","Describe field management appropriate for respiratory distress and failure.","Explain why respiratory problems are the leading pathway to pediatric cardiac arrest."],"summary":[{"title":"Distress vs Failure","content":"Respiratory distress describes a child who is working hard to breathe but is still compensating — increased work of breathing (retractions, nasal flaring, grunting), often with tachypnea, but generally adequate oxygenation and mental status. Respiratory failure describes a child whose compensation has failed — inadequate oxygenation and/or ventilation is now present, marked by altered mental status, cyanosis, bradypnea or irregular breathing, and profound fatigue. The transition from distress to failure can happen quickly, and PEPP teaches recognizing the early warning signs of that transition as a top priority."},{"title":"The Four Categories of Pediatric Respiratory Compromise","content":"Pediatric respiratory problems are organized into four categories by the level of the problem. Upper airway obstruction (e.g., croup, foreign body, epiglottitis) typically causes stridor. Lower airway disease (e.g., asthma, bronchiolitis) typically causes wheezing and prolonged expiration. Lung tissue (parenchymal) disease (e.g., pneumonia, pulmonary edema) typically causes grunting, crackles, and diminished breath sounds. Disordered control of breathing (e.g., from a CNS problem, toxin, or neuromuscular disease) causes an irregular rate/pattern without the classic sounds of the other three categories. Categorizing by mechanism guides both what to expect on exam and which field treatment is appropriate."},{"title":"Early Warning Signs of Impending Failure","content":"Signals that a child is approaching respiratory failure, even before oxygen saturation drops: worsening or new grunting, decreasing (not increasing) work of breathing in a child who was previously struggling hard — reflecting exhaustion rather than improvement — a change in Appearance on the PAT (from anxious/agitated to lethargic), and a falling or irregular respiratory rate after a period of tachypnea. Any of these should prompt immediate escalation of support, since they often precede a measurable drop in SpO2."},{"title":"Field Management","content":"For respiratory distress, field management is generally positioning of comfort, supplemental oxygen, and treatment targeted to the likely category (e.g., nebulized bronchodilator for suspected lower-airway disease), with close monitoring for any sign of transition toward failure. For respiratory failure, field management is assisted ventilation — bag-mask ventilation with high-flow oxygen — and rapid transport; PEPP frames this as the field recognition and initial stabilization step, with drug-assisted airway management and cardiac-arrest-specific ventilation parameters covered in depth by the PALS reviewer."},{"title":"Why This Matters So Much in Pediatrics","content":"Respiratory problems are the leading pathway to pediatric cardiac arrest — unlike adults, where a primary cardiac event is more common. This means that recognizing and treating respiratory distress before it becomes failure is one of the single highest-yield interventions in all of pediatric prehospital care, and is a recurring theme across nearly every later chapter in this course."}],"clinicalPearls":["Respiratory distress = compensating; respiratory failure = compensation has failed. The transition can happen fast.","Four categories: upper airway (stridor), lower airway (wheeze), lung tissue (grunting/crackles), disordered control of breathing (irregular pattern, no classic sounds).","Decreasing work of breathing in a previously struggling child can mean exhaustion, not improvement — a dangerous, easily misread sign.","Respiratory problems are the leading pathway to pediatric cardiac arrest — early recognition and treatment prevent the arrest, not just treat it."],"redFlags":["A child who was struggling hard to breathe now appears calmer and less effortful — verify this isn't exhaustion before feeling reassured.","New or worsening grunting.","Appearance shifting from anxious/agitated to lethargic on repeat PAT."],"commonMistakes":["Mistaking a fatiguing child's 'calmer' appearance for genuine improvement.","Treating all four respiratory categories the same way instead of matching treatment to the likely mechanism.","Waiting for SpO2 to fall before escalating support, when other findings already signal deterioration."],"memoryAids":["Distress compensates, failure collapses.","Stridor = upper, wheeze = lower, grunt/crackles = tissue, irregular-no-sound = control problem.","'Calmer' after struggling hard is a red flag, not relief — check for exhaustion.","Respiratory first, cardiac second — that's the pediatric arrest pathway."],"decisionTrees":[{"title":"Respiratory Distress vs Failure Recognition and Management","content":"Respiratory complaint\n  → Categorize: Upper airway (stridor) | Lower airway (wheeze) | Lung tissue (grunt/crackles) | Disordered control (irregular, no classic sound)\n  → Assess for distress vs failure signs:\n     Distress: increased WOB, tachypnea, adequate oxygenation/mentation → position of comfort, O2, category-targeted treatment, close monitoring\n     Failure (or transitioning): altered mentation, cyanosis, bradypnea/irregular pattern, exhaustion (including 'improving' WOB after struggling) → assist ventilation (BVM + high-flow O2), rapid transport\n  → For arrest-level airway/ventilation depth beyond field stabilization: see PALS reviewer"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Respiratory Emergencies","courses/pals/data/pals/tables/c04.json — Four Categories of Pediatric Respiratory Compromise (cross-referenced terminology)"]},"c06":{"id":"c06","title":"Shock Recognition & Field Management","shortTitle":"Shock Recognition & Management","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Define shock as inadequate tissue perfusion rather than a specific blood pressure value.","Distinguish compensated from decompensated (hypotensive) shock in children.","Recognize the major categories of pediatric shock and their field-relevant distinguishing features.","Identify the PAT and vital sign findings that suggest shock.","Describe field management priorities for compensated and decompensated shock."],"summary":[{"title":"Shock Is a Perfusion Problem, Not a Blood Pressure Number","content":"Shock is inadequate delivery of oxygen and nutrients to meet tissue demands — it is a clinical diagnosis based on perfusion, not a specific blood pressure. Children compensate for shock remarkably well through tachycardia and vasoconstriction, which means blood pressure can remain normal well into shock. By the time hypotension appears, a child has exhausted their compensatory mechanisms and is decompensating rapidly. This is why PEPP emphasizes recognizing compensated shock from perfusion signs — capillary refill, skin color/temperature, pulse quality, mental status — rather than waiting for a low blood pressure reading."},{"title":"Compensated vs Decompensated Shock","content":"Compensated shock: tachycardia, delayed capillary refill, cool/mottled skin (or warm/flushed in early distributive/septic shock), narrowed pulse pressure, and a normal systolic blood pressure for age. Decompensated shock: the same perfusion findings plus hypotension for age, and typically altered mental status. The transition from compensated to decompensated shock can be abrupt, and hypotension in a child is a late and ominous sign, not an early warning."},{"title":"Major Categories of Pediatric Shock","content":"Hypovolemic shock (most common in children overall) results from fluid or blood loss — vomiting/diarrhea with dehydration, hemorrhage, or burns. Distributive shock results from abnormal vessel tone/permeability — septic shock, anaphylactic shock, and neurogenic shock (rare in children). Cardiogenic shock results from pump failure — congenital heart disease, myocarditis, or arrhythmia. Obstructive shock results from a physical obstruction to blood flow — tension pneumothorax, cardiac tamponade, or massive pulmonary embolism (rare in children). Recognizing the likely category from history and exam guides field treatment (e.g., fluid resuscitation for hypovolemic shock versus needle decompression for obstructive shock from tension pneumothorax)."},{"title":"Field Recognition","content":"On the PAT, shock often first appears as an Appearance abnormality (irritability progressing to lethargy) with normal-appearing work of breathing, or as abnormal Circulation to Skin (pallor, mottling, cyanosis). On the primary assessment, look for tachycardia out of proportion to fever/anxiety, delayed capillary refill (over 2 seconds), weak or absent peripheral pulses with strong central pulses, cool extremities with a temperature gradient, and narrowed pulse pressure. Fever plus poor perfusion with warm, flushed skin and bounding pulses suggests early septic (distributive) shock rather than hypovolemic shock."},{"title":"Field Management","content":"General priorities: supplemental oxygen, positioning (supine, legs elevated if tolerated), keep the child warm, and rapid transport. For suspected hypovolemic or septic shock, isotonic fluid boluses are indicated per local protocol. For suspected anaphylactic shock, epinephrine is the priority treatment. For suspected obstructive shock from tension pneumothorax, needle decompression is indicated per protocol/scope of practice. PEPP frames this chapter as field recognition and initial stabilization; drug dosing tables and advanced resuscitation algorithms for shock and arrest are the domain of the PALS reviewer."}],"clinicalPearls":["Shock is a perfusion problem — blood pressure can be normal in compensated shock. Don't wait for hypotension to recognize shock.","Hypotension in a child is a late, ominous sign — it means decompensation, not the first sign of shock.","Warm, flushed skin with bounding pulses and fever can be shock too — early distributive (septic) shock often looks different from cold, mottled hypovolemic shock.","Match treatment to category: fluids for hypovolemic/septic, epinephrine for anaphylactic, needle decompression for obstructive tension pneumothorax."],"redFlags":["Delayed capillary refill (>2 seconds) with normal blood pressure — compensated shock until proven otherwise.","Tachycardia out of proportion to fever or anxiety.","Any hypotension for age — this represents decompensated shock and is a late finding."],"commonMistakes":["Waiting for hypotension before recognizing and treating shock.","Assuming all shock presents as cold and mottled, missing warm, flushed early septic shock.","Treating every shock category with fluids alone, without considering epinephrine (anaphylactic) or needle decompression (obstructive) when indicated."],"memoryAids":["Normal BP does not mean no shock — compensated shock hides behind a normal number.","Cold and mottled or warm and flushed — both can be shock.","Four categories: low volume (hypovolemic), bad tone (distributive), bad pump (cardiogenic), blocked flow (obstructive).","Hypotension = decompensating now, not a warning of shock to come — it already arrived."],"decisionTrees":[{"title":"Pediatric Shock Recognition and Category-Matched Management","content":"Suspect shock from PAT/primary assessment (abnormal Appearance and/or Circulation to Skin, tachycardia, delayed cap refill, weak pulses)\n  → Check blood pressure for age:\n     Normal BP + perfusion signs → Compensated shock\n     Low BP for age + perfusion signs (+ often altered mentation) → Decompensated shock (late, ominous)\n  → Identify likely category from history/exam:\n     Fluid/blood loss history → Hypovolemic → isotonic fluid bolus per protocol\n     Fever + warm/flushed or cold/mottled + poor perfusion → Distributive/septic → isotonic fluid bolus per protocol\n     Allergen exposure + rash/angioedema/wheeze → Anaphylactic (distributive) → epinephrine priority\n     Cardiac history/muffled heart sounds/JVD → Cardiogenic → cautious fluids, avoid overload\n     Trauma + unilateral absent breath sounds/tracheal deviation → Obstructive (tension pneumothorax) → needle decompression per protocol\n  → Supportive care: oxygen, positioning, keep warm, rapid transport\n  → For advanced shock/arrest resuscitation depth: see PALS reviewer"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Shock","courses/pals/data/pals — cross-referenced for advanced shock/arrest management depth"]},"c07":{"id":"c07","title":"Cardiac Emergencies & Rhythm Recognition","shortTitle":"Cardiac Emergencies","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Explain why primary cardiac events are rare in children compared to adults.","Recognize field presentations of pediatric bradycardia, tachycardia, and cardiac arrest.","Identify congenital heart disease as a risk factor for pediatric cardiac emergencies.","Describe the field priority of treating the underlying cause of bradycardia (usually hypoxia) rather than the rhythm alone.","Understand when to defer to the PALS reviewer for arrest algorithms and drug dosing."],"summary":[{"title":"Primary Cardiac Events Are Rare in Children","content":"Unlike adults, where primary cardiac events (e.g., myocardial infarction, primary ventricular fibrillation) are a common cause of sudden collapse, primary cardiac disease is a rare cause of pediatric emergencies. Most pediatric cardiac problems are secondary — bradycardia from hypoxia, or arrhythmia in a child with known congenital heart disease. This chapter focuses on field recognition of these secondary presentations; it does not replace the PALS reviewer's depth on arrest rhythms, defibrillation, and drug dosing."},{"title":"Bradycardia: Treat the Cause, Not Just the Rhythm","content":"The most common serious pediatric dysrhythmia encountered in the field is bradycardia, and it is almost always caused by hypoxia (or less commonly, increased vagal tone, hypothermia, or increased intracranial pressure). The field priority for symptomatic bradycardia is to address the underlying cause — oxygenate and ventilate first — rather than treating the rhythm number in isolation. A bradycardic, poorly perfusing infant is usually a respiratory or hypoxia problem until proven otherwise."},{"title":"Tachycardia: Sinus vs Supraventricular","content":"Sinus tachycardia is a compensatory response (fever, pain, anxiety, dehydration, shock) and resolves as the underlying cause is treated; rates are usually variable and rarely exceed about 220 bpm in infants. Supraventricular tachycardia (SVT) is a primary rhythm disturbance with a fixed, very rapid rate (often >220 bpm in infants, >180 bpm in older children) that does not vary with stimulation, and can itself cause poor perfusion if sustained. Distinguishing the two by history (fever/pain/dehydration vs sudden onset with no clear trigger) and rate pattern guides field urgency."},{"title":"Congenital Heart Disease as a Risk Factor","content":"Children with known congenital heart disease (repaired or unrepaired) are at elevated risk for arrhythmia, heart failure, and cardiogenic shock, and may have baseline vital signs or oxygen saturations that differ from typical pediatric norms — always ask caregivers about the child's 'normal' baseline. Family history clues (sudden unexplained death in young relatives) can also suggest an underlying cardiac channelopathy risk in an otherwise unexplained pediatric collapse."},{"title":"Field Recognition and Initial Stabilization","content":"Field priorities are recognition (PAT + primary assessment + monitor/rhythm strip if available), identifying reversible causes (especially hypoxia), and rapid transport with continuous reassessment. This chapter deliberately does not reproduce arrest algorithms, defibrillation/cardioversion energy doses, or antiarrhythmic drug dosing — these are covered in full depth in the PALS reviewer, which should be used for any patient in or approaching cardiac arrest."}],"clinicalPearls":["Primary cardiac events are rare in children — most pediatric bradycardia is caused by hypoxia, not primary heart disease.","Treat the cause of bradycardia (usually oxygenation/ventilation) before treating the number.","Sinus tachycardia varies with the underlying cause and stimulation; SVT is fixed, very rapid, and doesn't vary.","Ask about a child's known congenital heart disease and their personal 'normal' baseline vitals/SpO2 — it changes what's abnormal for them."],"redFlags":["Bradycardia with poor perfusion in an infant — treat as a hypoxia/respiratory emergency until proven otherwise.","A fixed, very rapid heart rate that does not vary with stimulation — suspect SVT.","Family history of sudden unexplained death in a young relative, in a child with unexplained collapse or syncope."],"commonMistakes":["Treating bradycardia as a primary cardiac rhythm problem without first addressing oxygenation/ventilation.","Failing to distinguish sinus tachycardia (variable, has a clear trigger) from SVT (fixed, very rapid).","Not asking about a child's baseline vitals/SpO2 when they have known congenital heart disease."],"memoryAids":["Bradycardia in a child = hypoxia until proven otherwise — fix the airway/breathing first.","Sinus tachy varies with the cause; SVT doesn't vary and is very fast.","Know their normal — congenital heart disease patients may have a different baseline.","For arrest rhythms and drug doses, go to PALS — this chapter is recognition, not resuscitation depth."],"decisionTrees":[{"title":"Pediatric Cardiac Emergency Field Recognition","content":"Abnormal heart rate or rhythm noted\n  → Bradycardia + poor perfusion → Suspect hypoxia (or vagal tone/hypothermia/increased ICP) → prioritize oxygenation/ventilation, treat underlying cause\n  → Tachycardia:\n     Variable rate, clear trigger (fever/pain/dehydration/shock) → Sinus tachycardia → treat underlying cause\n     Fixed, very rapid rate, no clear trigger, does not vary with stimulation → Suspect SVT → rapid transport, notify receiving facility\n  → Known congenital heart disease or family history of sudden unexplained death → heightened suspicion for cardiac cause, ask caregiver for patient's normal baseline\n  → Any patient in or approaching cardiac arrest → transition immediately to PALS arrest algorithms (not covered in this chapter)"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Cardiac Emergencies","courses/pals/data/pals — authoritative source for arrest algorithms, defibrillation/cardioversion dosing, and antiarrhythmic drug dosing (not duplicated here)"]},"c08":{"id":"c08","title":"Neurologic Emergencies: Altered Mental Status & Seizures","shortTitle":"Neurologic Emergencies","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Apply the AVPU scale and PAT Appearance findings to recognize altered mental status in children.","List the common reversible causes of pediatric altered mental status using the AEIOU-TIPS framework.","Describe field management of active pediatric seizures, including status epilepticus.","Recognize febrile seizures as generally benign and distinguish them from more concerning seizure presentations.","Identify field priorities for a child with suspected increased intracranial pressure."],"summary":[{"title":"Recognizing Altered Mental Status","content":"The PAT's Appearance leg is often the first clue to altered mental status, before a formal AVPU (Alert, Voice, Pain, Unresponsive) assessment is completed. Any child who is not appropriately alert and interactive for their developmental stage — or who has an abnormal TICLS finding such as poor eye contact or an abnormal cry — should prompt a full neurologic assessment. Serial reassessment matters: a trend toward decreasing responsiveness is more concerning than a single snapshot value."},{"title":"Reversible Causes: AEIOU-TIPS","content":"A useful framework for reversible causes of pediatric altered mental status is AEIOU-TIPS: Alcohol/substance use, Epilepsy/seizure (postictal state), Infection, Overdose/opioids, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke. Hypoglycemia deserves particular emphasis in children because it is common, rapidly reversible, and easily checked in the field with a glucose meter — every altered child should have a glucose check when available."},{"title":"Seizures: Field Management","content":"Most pediatric seizures are brief and self-limited. Field priorities during an active seizure are protecting the airway (positioning, suction as needed — do not put anything in the mouth), protecting the child from injury, checking glucose, and timing the seizure. A seizure lasting more than 5 minutes, or repeated seizures without return to baseline between them, meets the definition of status epilepticus and is a time-critical emergency requiring rapid escalation of care and transport; benzodiazepine dosing for status epilepticus is detailed in the PALS reviewer."},{"title":"Febrile Seizures","content":"Febrile seizures are the most common pediatric seizure type, typically occurring in children 6 months to 5 years with a rapidly rising fever. A simple febrile seizure is generalized, lasts less than 15 minutes, and does not recur within 24 hours — these are generally benign, and the child typically returns to baseline mental status afterward. A complex febrile seizure (focal features, lasting more than 15 minutes, or recurring within 24 hours) or any seizure in a child who does not return to baseline warrants a higher level of concern and should not be assumed to be a simple febrile seizure."},{"title":"Suspected Increased Intracranial Pressure","content":"Signs suggesting increased intracranial pressure include a bulging fontanelle (infants), a decreasing level of consciousness, an irregular respiratory pattern, and — as a late and ominous finding — the Cushing triad (hypertension, bradycardia, irregular respirations). Field priorities are avoiding hypoxia and hypotension (both worsen secondary brain injury), positioning to avoid jugular venous compression, and rapid transport; specific hyperventilation/hyperosmolar therapy parameters are beyond this chapter's field-recognition scope."}],"clinicalPearls":["Every altered child gets a glucose check when available — hypoglycemia is common and rapidly reversible.","AEIOU-TIPS is a useful recall framework for reversible causes of altered mental status.","A seizure lasting more than 5 minutes, or repeated seizures without return to baseline, is status epilepticus — a time-critical emergency.","Simple febrile seizures are generalized, under 15 minutes, don't recur in 24 hours, and the child returns to baseline — anything more should raise concern."],"redFlags":["Any altered child without a glucose check performed when a meter is available.","Seizure activity lasting more than 5 minutes or recurring without return to baseline (status epilepticus).","Bulging fontanelle, irregular respirations, or the Cushing triad (hypertension, bradycardia, irregular respirations) suggesting increased intracranial pressure."],"commonMistakes":["Assuming all pediatric seizures with fever are simple febrile seizures without checking duration/recurrence/focality.","Delaying a glucose check in an altered child when a meter is available.","Placing an object in the mouth of a seizing child (unnecessary and can cause injury)."],"memoryAids":["AEIOU-TIPS: reversible causes of altered mental status.","5 minutes = status epilepticus — the clock matters.","Simple febrile seizure: generalized, under 15 minutes, no recurrence in 24 hours, back to baseline after.","Cushing triad = late and bad: high BP, low HR, irregular breathing."],"decisionTrees":[{"title":"Pediatric Altered Mental Status and Seizure Field Approach","content":"Altered mental status noted (PAT Appearance abnormal / AVPU below Alert)\n  → Check glucose when available → treat hypoglycemia per protocol if present\n  → Consider AEIOU-TIPS causes: Alcohol/substance, Epilepsy/postictal, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke\n  → If actively seizing:\n     Protect airway/position, protect from injury, time the seizure, check glucose\n     <5 minutes and resolves, returns to baseline, fits simple febrile seizure pattern → supportive care, transport for evaluation\n     ≥5 minutes OR repeated seizures without return to baseline → Status epilepticus → time-critical emergency, escalate immediately (see PALS reviewer for benzodiazepine dosing)\n  → If signs of increased intracranial pressure (bulging fontanelle, irregular respirations, Cushing triad) → avoid hypoxia/hypotension, position to avoid jugular compression, rapid transport"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Neurologic Emergencies","courses/pals/data/pals — cross-referenced for status epilepticus drug dosing and advanced resuscitation depth"]},"c09":{"id":"c09","title":"Pediatric Trauma","shortTitle":"Trauma","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Explain why children have distinct injury patterns compared to adults.","Identify the anatomic and physiologic factors that make children uniquely vulnerable to specific injuries.","Recognize the field presentation of pediatric head, chest, abdominal, and extremity trauma.","Describe why children can maintain normal vital signs despite significant blood loss.","Apply appropriate spinal motion restriction and immobilization considerations for children."],"summary":[{"title":"Why Pediatric Trauma Patterns Differ","content":"A child's larger head-to-body ratio, more pliable ribcage, less protected abdominal organs, and thinner subcutaneous tissue create injury patterns distinct from adults. Falls and motor vehicle collisions more often produce head injury as the dominant problem in children because of the relatively larger, heavier head. The pliable, elastic ribcage means significant internal chest injury (pulmonary contusion) can occur without rib fractures — the absence of fractures does not exclude serious injury."},{"title":"Blood Loss Compensation Mirrors Shock Physiology","content":"Because children compensate for volume loss so effectively (as discussed in the shock chapter), a child can lose a significant percentage of circulating blood volume while maintaining a normal blood pressure. Tachycardia, delayed capillary refill, and cool extremities may be the only clues to significant hemorrhage before hypotension appears — treat these perfusion findings as seriously as you would hypotension in an adult trauma patient."},{"title":"Head, Chest, and Abdominal Trauma","content":"Head trauma: the proportionally larger head increases both injury risk and the leverage effect on the cervical spine; watch for a bulging fontanelle (infants) or decreasing mental status as signs of evolving intracranial injury. Chest trauma: rib fractures are less common than in adults due to ribcage pliability, but their presence signals a high-energy mechanism and raises concern for significant underlying pulmonary or cardiac injury. Abdominal trauma: the abdominal organs (liver, spleen) are proportionally larger and less protected by the ribcage in children, making blunt abdominal trauma a common source of occult hemorrhage — a soft, non-tender abdomen does not exclude significant injury, especially early after the event."},{"title":"Spinal Motion Restriction Considerations","content":"A child's proportionally larger head can force the neck into flexion when lying flat on a standard adult backboard; padding under the torso (not just the head) helps maintain neutral alignment. Selective spinal motion restriction criteria (mechanism, mental status, distracting injury, midline tenderness, neurologic complaint) are applied thoughtfully in children, recognizing that young children may not reliably report pain or tenderness, so mechanism and mental status carry more weight in the decision."},{"title":"Field Management Priorities","content":"Standard trauma priorities apply — scene safety, hemorrhage control, airway/breathing/circulation support, and rapid transport to an appropriate (ideally pediatric-capable) trauma center — with attention to the pediatric-specific patterns above. Recognize evolving shock from perfusion signs, not blood pressure alone, and maintain a high index of suspicion for internal injury even when external findings appear minor."}],"clinicalPearls":["A child's proportionally larger head drives both head-injury risk and cervical spine leverage — pad under the torso for neutral spinal alignment.","No rib fractures does not mean no chest injury — the pliable pediatric ribcage can allow significant pulmonary contusion without fractures.","A soft, non-tender abdomen does not exclude serious abdominal injury — the liver and spleen are proportionally larger and less protected in children.","Perfusion signs (tachycardia, delayed cap refill, cool extremities) can signal major blood loss well before blood pressure falls."],"redFlags":["Any rib fracture in a child — signals a high-energy mechanism and raises concern for underlying injury.","Tachycardia and delayed capillary refill after trauma, even with normal blood pressure.","A bulging fontanelle or decreasing mental status after head trauma in an infant."],"commonMistakes":["Assuming the absence of rib fractures rules out significant chest injury.","Reassuring a caregiver based on a normal blood pressure alone after significant trauma.","Placing a young child flat on a standard backboard without torso padding, forcing neck flexion."],"memoryAids":["Big head, big risk — head injury and cervical spine leverage go together in young children.","Bendy ribs hide big injuries — no fracture doesn't mean no contusion.","Soft belly, hidden bleed — abdominal exam can look reassuring despite real injury.","Pad the torso, not just the head, to keep the spine neutral."],"decisionTrees":[{"title":"Pediatric Trauma Field Assessment","content":"Trauma mechanism identified\n  → Scene safety, hemorrhage control\n  → Primary assessment (ABCDE) with attention to pediatric patterns:\n     Head: check fontanelle (infants), mental status trend\n     Chest: any rib fracture = high suspicion for underlying injury even if breath sounds seem normal\n     Abdomen: soft/non-tender does not exclude occult injury — reassess serially\n  → Assess perfusion (heart rate, capillary refill, skin) — do not rely on blood pressure alone\n  → Apply selective spinal motion restriction criteria, weighting mechanism/mental status heavily in young children; pad torso for neutral alignment if restricting\n  → Rapid transport to appropriate (ideally pediatric-capable) trauma center with continuous reassessment"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Trauma","courses/pepp/data/pepp/chapters/c06.json — cross-referenced shock/perfusion recognition principles"]},"c10":{"id":"c10","title":"Toxic Exposures & Environmental Emergencies","shortTitle":"Toxic & Environmental Emergencies","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Explain why toddlers are the peak age group for unintentional poisoning.","Describe field assessment and management of a suspected pediatric ingestion or exposure.","Recognize field presentations of pediatric heat-related and cold-related illness.","Identify pediatric-specific risk factors for drowning and submersion injury.","Describe field management priorities for common pediatric environmental emergencies."],"summary":[{"title":"Toxic Exposures: Toddlers at Peak Risk","content":"Toddlers (roughly 1-3 years) are at peak risk for unintentional poisoning because of their mobility, curiosity, and tendency to put objects in their mouths, combined with household medications and chemicals often within reach. Common household exposures include medications (especially caregivers' or grandparents' medications), cleaning products, and button batteries. Field assessment focuses on identifying the substance, amount, and time of exposure when possible (bring containers/pills to the hospital), and recognizing toxidrome patterns (e.g., altered mental status plus pinpoint pupils and respiratory depression suggesting opioid exposure) rather than waiting for a definitive substance identification."},{"title":"Button Battery Ingestion — A Time-Critical Exposure","content":"Button battery ingestion deserves special emphasis because a lodged battery in the esophagus can cause severe tissue injury within hours through an electrical current effect, not just direct chemical burn. Any suspected button battery ingestion is treated as a time-critical emergency requiring rapid transport and hospital notification, regardless of the child's current symptoms, since the child may appear asymptomatic early on despite a lodged, actively injuring battery."},{"title":"Heat-Related and Cold-Related Illness","content":"Children are more vulnerable to heat illness than adults because of a higher surface-area-to-mass ratio, less efficient sweating, and reliance on caregivers to remove them from hot environments — including the specific and preventable risk of a child left in a hot vehicle, where internal temperatures can become life-threatening within minutes. Cold-related illness (hypothermia) is similarly amplified by the same surface-area-to-mass ratio, plus limited ability to generate heat through shivering in infants. Field management for both is rapid recognition, removal from the environmental extreme, and temperature-appropriate supportive care (cooling measures for heat illness, gentle rewarming for hypothermia) alongside standard ABC support."},{"title":"Drowning and Submersion","content":"Drowning is a leading cause of unintentional death in young children, particularly toddlers (bathtubs, pools) and adolescents (open water, often associated with risk-taking or alcohol). Field priorities after submersion are airway/breathing support (drowning is fundamentally a respiratory event — hypoxia is the primary problem), spinal motion restriction only if the mechanism suggests trauma (e.g., diving injury), and rewarming if hypothermic, with transport for observation even in an apparently well-appearing child, since pulmonary complications can evolve over hours."},{"title":"Field Management Priorities","content":"Across toxic and environmental emergencies, field priorities are: identify the exposure/mechanism when possible, support the ABCs, remove the child from the ongoing hazard (contaminated environment, hot/cold environment, water), bring relevant materials (pill bottles, chemical containers) to the hospital, and transport promptly — with a lower threshold for transport/observation than might apply to an adult, given children's capacity to appear deceptively well before deteriorating."}],"clinicalPearls":["Toddlers are the peak age group for unintentional poisoning due to mobility, curiosity, and mouthing behavior.","Button battery ingestion is time-critical regardless of current symptoms — electrical injury can progress within hours even in an asymptomatic child.","Children left in hot vehicles can develop life-threatening hyperthermia within minutes — this is a preventable, high-stakes scenario.","Drowning is fundamentally a respiratory event — hypoxia, not water in the lungs mechanically, is the core problem to treat."],"redFlags":["Any suspected button battery ingestion, regardless of current symptoms.","A child found in a hot vehicle, even if currently appearing alert.","Any submersion event, even in an apparently well-appearing child — observe for delayed pulmonary complications."],"commonMistakes":["Delaying transport for a suspected button battery ingestion because the child seems asymptomatic.","Underestimating heat illness severity in a child due to their smaller size.","Assuming a well-appearing post-submersion child does not need transport/evaluation."],"memoryAids":["Toddlers + curiosity + mouths = peak poisoning risk.","Button battery: time-critical no matter how the child looks right now.","Hot car, minutes matter — pediatric heat illness escalates fast.","Drowning is a breathing problem first — treat hypoxia, transport even if 'fine.'"],"decisionTrees":[{"title":"Pediatric Toxic Exposure and Environmental Emergency Field Approach","content":"Suspected exposure or environmental emergency\n  → Toxic ingestion/exposure suspected:\n     Identify substance/amount/time if possible; bring containers to hospital\n     Button battery suspected → treat as time-critical regardless of symptoms → rapid transport, hospital notification\n     Recognize toxidrome patterns (e.g., altered mental status + pinpoint pupils + resp depression → opioid) to guide urgency\n  → Heat illness suspected → remove from hot environment, cooling measures, ABC support, rapid transport\n  → Cold illness (hypothermia) suspected → remove from cold environment, gentle rewarming, ABC support, rapid transport\n  → Submersion/drowning → prioritize airway/breathing (hypoxia is the core problem), spinal motion restriction only if trauma mechanism suspected, transport even if well-appearing"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Toxic Exposures and Environmental Emergencies"]},"c11":{"id":"c11","title":"Neonatal Care & Resuscitation Basics","shortTitle":"Neonatal Care","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Describe the normal physiologic transition a newborn undergoes at birth.","Identify the three initial questions used to assess a newborn's need for resuscitation.","Describe the initial steps of newborn stabilization in the field.","Recognize when positive-pressure ventilation is indicated for a newborn.","Explain why warmth and drying are high-priority interventions for every newborn."],"summary":[{"title":"Normal Newborn Transition","content":"At birth, a newborn must transition from placental gas exchange to independent breathing, with fluid clearing from the lungs and a shift in circulation as fetal shunts close. Most newborns make this transition without assistance — vigorous crying, good tone, and pink color within the first minute are the expected pattern. A field delivery requires the provider to assess this transition promptly and be ready to intervene if it does not proceed normally."},{"title":"The Three Initial Questions","content":"Immediately after delivery, three rapid questions guide the need for resuscitation: Is the newborn term gestation? Does the newborn have good tone? Is the newborn breathing or crying? If the answer to all three is yes, the newborn can stay with the mother for routine care (dry, warm, skin-to-skin). If any answer is no, the newborn is moved to a warmer for the initial steps of stabilization."},{"title":"Initial Steps of Stabilization","content":"The initial steps are: provide warmth, position the airway (sniffing position), clear secretions only if needed (suction is not routine), dry the newborn thoroughly, and stimulate (rubbing the back, flicking the soles of the feet). These steps take about 30 seconds, after which breathing and heart rate are reassessed to determine the next step. Keeping the newborn warm is a high priority throughout — a wet, uncovered newborn loses heat extremely rapidly, and hypothermia worsens outcomes."},{"title":"When Positive-Pressure Ventilation Is Indicated","content":"If, after the initial steps, the newborn is apneic, gasping, or has a heart rate below 100 beats per minute, positive-pressure ventilation (PPV) with a bag-mask device is indicated — this is the single most important intervention in newborn resuscitation. Chest compressions are added only if the heart rate remains below 60 beats per minute despite 30 seconds of effective PPV; this progression (ventilation first, compressions only if ventilation alone is insufficient) differs from the compressions-first emphasis common in adult and older-child cardiac arrest and reflects that most newborn compromise originates from inadequate ventilation, not a primary cardiac problem."},{"title":"Field Priorities and Scope","content":"This chapter covers field recognition and the initial steps of newborn stabilization. Detailed neonatal resuscitation algorithms (including medication dosing, umbilical line considerations, and advanced airway specifics) are beyond this chapter's scope; providers should follow their local neonatal resuscitation protocol and refer to the PALS reviewer for related pediatric-arrest-adjacent concepts where applicable, while recognizing that dedicated neonatal resuscitation training (e.g., NRP) is the authoritative source for this specific skill set."}],"clinicalPearls":["Three initial questions: term gestation? good tone? breathing/crying? All yes = routine care; any no = move to warmer for initial steps.","Warmth is a top priority for every newborn — a wet, uncovered newborn loses heat extremely rapidly.","Positive-pressure ventilation is the single most important intervention in newborn resuscitation — most newborn compromise is a ventilation problem, not a primary cardiac one.","Chest compressions are added only if the heart rate stays below 60 bpm despite 30 seconds of effective PPV."],"redFlags":["A newborn who is not vigorous, not breathing/crying well, or has poor tone at birth.","Heart rate below 100 bpm after the initial steps of stabilization.","A wet, uncovered newborn — heat loss risk requires immediate attention."],"commonMistakes":["Routine deep suctioning of every newborn regardless of need.","Delaying positive-pressure ventilation while focusing on other interventions first.","Starting chest compressions before ensuring ventilation is effective."],"memoryAids":["Term? Tone? Breathing/crying? — the three questions.","Warm, position, clear (if needed), dry, stimulate — the initial steps.","Ventilation first, compressions only if HR stays under 60 despite good PPV.","Newborn problems are usually breathing problems, not heart problems."],"decisionTrees":[{"title":"Newborn Resuscitation Initial Steps","content":"Delivery occurs\n  → Ask: Term gestation? Good tone? Breathing/crying?\n     All yes → Routine care: dry, warm, skin-to-skin with mother\n     Any no → Move to warmer, begin initial steps (warmth, position airway, clear secretions if needed, dry, stimulate) — about 30 seconds\n  → Reassess breathing and heart rate:\n     Breathing well, HR ≥100 → Routine care, monitor\n     Apneic/gasping OR HR <100 → Begin positive-pressure ventilation (PPV)\n  → Reassess after 30 seconds of effective PPV:\n     HR ≥60 → Continue PPV, reassess frequently\n     HR <60 → Begin chest compressions coordinated with PPV\n  → For detailed neonatal resuscitation algorithm/medication depth: follow local neonatal resuscitation protocol"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Neonatal Care","American Academy of Pediatrics Neonatal Resuscitation Program (NRP) — authoritative source for detailed neonatal resuscitation depth"]},"c12":{"id":"c12","title":"Child Maltreatment Recognition","shortTitle":"Child Maltreatment","estimatedStudyTime":25,"difficulty":"Advanced","learningObjectives":["Describe the role of the EMS provider in recognizing possible child maltreatment.","Identify general categories of findings that may raise concern for maltreatment.","Explain why history-injury inconsistency is a key concern-raising factor.","Describe appropriate, non-judgmental communication when maltreatment is suspected.","Understand mandatory reporting as a professional responsibility, in general terms."],"summary":[{"title":"The EMS Role: Recognize and Report, Not Investigate","content":"EMS providers are not investigators — their role is to recognize findings that raise concern, document objectively, and report through appropriate channels (mandatory reporting requirements, medical direction, and receiving facility handoff). This chapter covers only general, educational recognition concepts; it does not provide a checklist for accusing caregivers or a substitute for local mandatory-reporting law, agency policy, or child protective services training, all of which vary by jurisdiction and must be followed directly."},{"title":"General Categories That May Raise Concern","content":"Concern-raising categories, in general terms, include: an injury inconsistent with the stated mechanism or the child's developmental stage (e.g., a injury pattern implausible for a non-mobile infant), a history that changes between tellings or between different caregivers, a delay in seeking care that is not otherwise explained, and patterns of injury in unusual locations or of unusual types. No single finding is diagnostic on its own — providers document what they observe and let the appropriate professionals evaluate the full picture."},{"title":"Why History-Injury Inconsistency Matters","content":"A central, widely taught concept is comparing the stated mechanism to the child's developmental capability and the injury pattern itself. A history that a non-mobile young infant 'rolled off the couch and broke their leg,' for example, is inconsistent with that infant's developmental stage. This kind of mismatch — not the injury itself — is what should raise concern and prompt careful, objective documentation."},{"title":"Non-Judgmental Communication and Documentation","content":"Regardless of suspicion level, EMS providers should maintain calm, professional, non-accusatory communication with caregivers throughout the encounter — providers are not there to confront or accuse, and doing so can compromise both the child's ongoing care and any subsequent investigation. Objective documentation (exact quotes, observed findings, scene details) is more useful than subjective conclusions, and should be factual rather than speculative."},{"title":"Mandatory Reporting as a Professional Responsibility","content":"EMS providers are mandatory reporters in essentially all jurisdictions, meaning they are legally required to report reasonable suspicion of child maltreatment through the appropriate channel. This chapter does not specify particular jurisdictional reporting mechanics or thresholds, since these vary by location — providers must know and follow their own agency's policy and local/state law, and should involve medical direction and receiving-facility staff when suspicion arises."}],"clinicalPearls":["The EMS role is to recognize and report, not to investigate or accuse.","History-injury inconsistency — mechanism not matching developmental stage or injury pattern — is a key concern-raising factor.","No single finding is diagnostic; document objectively and let appropriate professionals evaluate the full picture.","EMS providers are mandatory reporters in essentially all jurisdictions — know your local law and agency policy."],"redFlags":["An injury inconsistent with the stated mechanism or the child's developmental capability.","A history that changes between tellings or between different caregivers.","An unexplained delay in seeking care for a significant injury or illness."],"commonMistakes":["Confronting or accusing caregivers directly on scene.","Documenting subjective conclusions instead of objective, factual observations.","Assuming a single unusual finding is diagnostic of maltreatment without considering the full picture."],"memoryAids":["Recognize and report — not investigate or accuse.","Does the story match the injury and the child's stage of development?","Document facts, not conclusions.","Mandatory reporter — know your jurisdiction's process."],"decisionTrees":[{"title":"General Approach When Maltreatment Is a Concern","content":"Concerning finding noted (history-injury mismatch, changing history, unexplained delay in care, unusual injury pattern)\n  → Maintain calm, professional, non-accusatory communication with caregivers\n  → Document objectively: exact quotes, observed findings, scene details — avoid speculative conclusions\n  → Provide standard medical care for the child's presenting condition\n  → Report reasonable suspicion through appropriate channels per local mandatory-reporting law and agency policy\n  → Communicate findings factually during receiving-facility handoff\n  → Involve medical direction as appropriate per local protocol"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Child Maltreatment","Local/state mandatory reporting law and agency policy — authoritative source for jurisdiction-specific reporting requirements (not detailed in this general educational chapter)"]},"c13":{"id":"c13","title":"Children With Special Healthcare Needs","shortTitle":"Special Healthcare Needs","estimatedStudyTime":25,"difficulty":"Intermediate","learningObjectives":["Define children with special healthcare needs (CSHCN) and explain why caregivers are a critical information resource.","Identify common medical technology encountered in the field (tracheostomy, gastrostomy tube, ventriculoperitoneal shunt, central venous catheter, home ventilator).","Describe general field troubleshooting priorities for a malfunctioning tracheostomy.","Recognize field presentations suggesting ventriculoperitoneal (VP) shunt malfunction.","Explain why baseline function matters more than population norms when assessing a CSHCN patient."],"summary":[{"title":"Who Are Children With Special Healthcare Needs?","content":"Children with special healthcare needs (CSHCN) have or are at increased risk for a chronic physical, developmental, behavioral, or emotional condition, and often require health and related services beyond what is typical for children generally. This population is broad — from a child with well-controlled asthma to a child with complex technology dependence (tracheostomy, home ventilator, feeding tube). Caregivers of CSHCN are frequently the most knowledgeable resource on scene about the child's baseline, equipment, and typical emergency presentation, and should be engaged as partners in care from the start."},{"title":"Common Medical Technology in the Field","content":"Tracheostomy: a surgical airway that bypasses the upper airway; problems include mucus plugging, accidental decannulation, and tube malposition. Gastrostomy (G-) tube: provides enteral feeding directly into the stomach; field concerns include tube dislodgement and leakage, rarely acute emergencies unless associated with peritoneal signs. Ventriculoperitoneal (VP) shunt: diverts cerebrospinal fluid to treat hydrocephalus; malfunction can cause increased intracranial pressure. Central venous catheter: provides vascular access for children needing frequent IV therapy; field concerns include infection signs and line malfunction. Home ventilator: provides mechanical ventilation via tracheostomy for children with chronic respiratory failure; caregivers are typically expert in troubleshooting their specific device."},{"title":"Tracheostomy Troubleshooting","content":"For a child in respiratory distress with a tracheostomy, field priorities are: attempt suctioning to clear a possible mucus plug, check for accidental decannulation (tube fully or partially out) and replace with a same-size trach tube or appropriately sized endotracheal tube if trained and equipped to do so, and provide supplemental oxygen/ventilation via the tracheostomy stoma if the tube cannot be quickly replaced. Caregivers can often assist rapidly with troubleshooting since they manage this equipment daily."},{"title":"Recognizing VP Shunt Malfunction","content":"VP shunt malfunction should be suspected in a child with a known shunt who presents with signs of increased intracranial pressure — headache, vomiting, altered mental status, irritability (infants), or a bulging fontanelle (infants with open fontanelles) — since shunt failure prevents normal cerebrospinal fluid drainage. Field management is standard increased-ICP precautions (avoid hypoxia/hypotension, positioning) and rapid transport; shunt-specific interventions are a hospital-level intervention."},{"title":"Baseline Function Over Population Norms","content":"For CSHCN, the single most useful assessment reference point is often the child's own personal baseline — reported by the caregiver — rather than typical pediatric norms. A CSHCN patient's 'normal' resting SpO2, respiratory pattern, or level of interactiveness may differ substantially from a typically developing child of the same age, and providers should always ask 'what is normal for this child?' before deciding whether a finding represents an acute change."}],"clinicalPearls":["Caregivers of CSHCN are often the most knowledgeable resource on scene — engage them as partners, not bystanders.","For tracheostomy distress: suction first, check for decannulation, replace the tube or ventilate via the stoma if needed.","Suspect VP shunt malfunction in a child with a known shunt and signs of increased intracranial pressure (headache, vomiting, altered mental status, bulging fontanelle).","Always ask 'what is normal for this child?' — baseline function matters more than population norms for CSHCN."],"redFlags":["Respiratory distress in a child with a tracheostomy — assess for mucus plug or decannulation immediately.","Headache, vomiting, altered mental status, or bulging fontanelle in a child with a known VP shunt.","Any acute change from a CSHCN patient's caregiver-reported baseline."],"commonMistakes":["Comparing a CSHCN patient's vitals/findings only to typical population norms instead of their known personal baseline.","Not engaging the caregiver early as a resource for equipment troubleshooting and baseline information.","Failing to consider VP shunt malfunction in a child with a known shunt presenting with vague neurologic symptoms."],"memoryAids":["Ask the expert in the room — the caregiver usually knows this child's equipment and baseline best.","Trach distress: suction, check decannulation, replace or ventilate via stoma.","Known shunt + headache/vomiting/altered mental status = suspect shunt malfunction.","Normal for THIS child, not normal for children in general."],"decisionTrees":[{"title":"CSHCN Field Assessment Approach","content":"Child with special healthcare needs encountered\n  → Engage caregiver early: ask about baseline function, equipment, and typical emergency presentation\n  → If tracheostomy present and in distress: attempt suctioning → check for decannulation → replace tube or ventilate via stoma if needed\n  → If known VP shunt and signs of increased ICP (headache, vomiting, altered mental status, bulging fontanelle): suspect shunt malfunction → standard increased-ICP precautions, rapid transport\n  → If G-tube or central venous catheter related concern: assess for infection signs, dislodgement, or malfunction; treat any associated acute presentation per general principles\n  → Compare all findings to the child's caregiver-reported personal baseline, not population norms, before determining significance\n  → Transport with caregiver involvement maintained throughout when feasible"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Children With Special Healthcare Needs"]},"c14":{"id":"c14","title":"EMS Operations: Transport Decisions, Disaster & MCI Triage","shortTitle":"EMS Operations & MCI Triage","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Describe factors that guide pediatric transport destination decisions.","Explain why children require specific consideration in disaster planning.","Describe the JumpSTART pediatric MCI triage algorithm and how it differs from adult START triage.","Identify pediatric-specific challenges in mass casualty incident (MCI) management.","Describe general principles of family reunification after a pediatric-involving MCI."],"summary":[{"title":"Pediatric Transport Destination Decisions","content":"Transport destination decisions weigh the severity and type of the child's condition against the capabilities of nearby facilities — not every hospital has pediatric-specific resources (pediatric trauma center, pediatric ICU, pediatric surgical subspecialists). Local protocols typically define which conditions or severity thresholds require bypass to a pediatric-capable or pediatric trauma center, even if a closer general facility is available. When in doubt, providers should follow local protocol and consult medical direction rather than defaulting to the nearest facility for a child with significant illness or injury."},{"title":"Why Children Need Specific Disaster Planning Consideration","content":"Children are not simply small adults in a disaster context — they have unique vulnerabilities (increased susceptibility to chemical/radiological exposure due to surface-area-to-mass ratio and breathing zone proximity to the ground, dependence on caregivers for evacuation and decision-making, psychological vulnerability, and equipment/medication needs that differ from adult supplies). Disaster and MCI plans that do not explicitly address pediatric patients risk inadequate pediatric-sized equipment, medication dosing errors under stress, and prolonged, traumatic family separation."},{"title":"JumpSTART: Pediatric MCI Triage","content":"JumpSTART is a pediatric-specific adaptation of the adult START (Simple Triage and Rapid Treatment) MCI triage algorithm, developed because children's physiologic norms and injury/arrest patterns differ enough from adults to require adjusted triage criteria. Key JumpSTART-specific adjustments include: a different respiratory rate threshold for triage category assignment (using pediatric norms rather than the adult cutoff), a step for apneic children with a pulse to receive five rescue breaths before being categorized as expectant (reflecting that pediatric arrest is often respiratory in origin and may be reversible), and use of the AVPU scale (rather than command-following) to assess mental status appropriately for developmental stage."},{"title":"Pediatric-Specific MCI Challenges","content":"MCIs involving children present distinct operational challenges: distinguishing a child's baseline developmental behavior from a triage-relevant abnormal finding under chaotic conditions, ensuring pediatric-sized equipment and correctly dosed medications are available at the scene, and managing the emotional and logistical complexity of children separated from caregivers during the incident. Triage personnel should be familiar with JumpSTART specifically, since applying adult START criteria to pediatric patients can misclassify children (e.g., under standard adult respiratory rate thresholds)."},{"title":"Family Reunification","content":"Reunifying separated children with caregivers after an MCI is a recognized priority within disaster response, typically coordinated through a designated reunification process (tracking systems, designated reunification points) established by incident command or emergency management partners rather than improvised individually by field providers. Field providers should document identifying information for unaccompanied children when possible and follow the established incident reunification process rather than attempting ad hoc reunification during active response operations."}],"clinicalPearls":["Not every hospital has pediatric-specific capabilities — follow local protocol for pediatric-capable/pediatric trauma center bypass decisions.","Children have unique disaster vulnerabilities: exposure risk, evacuation dependence, psychological impact, and pediatric-specific equipment/medication needs.","JumpSTART adapts adult START triage for pediatric physiology: different RR thresholds, five rescue breaths for the apneic-with-pulse child, AVPU for mental status.","Family reunification after an MCI follows an established incident process, not ad hoc field-level matching."],"redFlags":["Applying adult START triage criteria directly to a pediatric patient without adjustment.","An apneic child with a pulse triaged as expectant without first attempting five rescue breaths per JumpSTART.","Any unaccompanied child at an MCI scene without identifying documentation for reunification."],"commonMistakes":["Defaulting to the nearest hospital for a significantly ill/injured child without considering pediatric-capable destination requirements per local protocol.","Treating pediatric disaster/MCI planning as identical to adult planning without pediatric-specific equipment, dosing, and psychological considerations.","Attempting individual, ad hoc caregiver reunification during active MCI response instead of following the incident's established process."],"memoryAids":["Pediatric-capable destination, not just nearest destination.","JumpSTART = START adapted for kids: different RR cutoffs, 5 rescue breaths, AVPU.","Kids aren't small adults in a disaster — plan for their specific needs.","Reunification follows the incident process, not individual improvisation."],"decisionTrees":[{"title":"JumpSTART Pediatric MCI Triage Overview","content":"Pediatric patient at MCI scene\n  → Able to walk? → Yes → Minor (green)\n  → Not walking → Assess breathing:\n     Breathing → Assess respiratory rate (pediatric-specific threshold) → Normal for age → assess perfusion/mental status → Perfusion/AVPU abnormal → Immediate (red); Normal → Delayed (yellow)\n     Abnormal RR for age → Immediate (red)\n     Not breathing → Position airway, reassess:\n        Breathing resumes → Immediate (red)\n        Still apneic, no pulse → Expectant (black/gray)\n        Still apneic, pulse present → Give 5 rescue breaths → Breathing resumes → Immediate (red); Still apneic → Expectant (black/gray)\n  → Continue reassessment as resources allow"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — EMS Operations","JumpSTART Pediatric MCI Triage Tool — Lou Romig, MD (original developer); widely adopted pediatric MCI triage standard"]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What is the single organizing principle behind PEPP's approach to pediatric care?","answer":"Children are not small adults — they differ anatomically, physiologically, developmentally, and psychosocially, not just in size.","category":"Core Concepts"},{"id":"c01_fc02","question":"Where is the narrowest point of a young child's airway?","answer":"Subglottic (below the vocal cords) — unlike the adult airway, which narrows at the vocal cords.","category":"Airway"},{"id":"c01_fc03","question":"Why is a child's tongue an airway concern?","answer":"It is proportionally larger relative to the oropharynx than an adult's, making obstruction more likely.","category":"Airway"},{"id":"c01_fc04","question":"How does a child's metabolic rate/oxygen consumption compare to an adult's?","answer":"Higher per kilogram, combined with smaller functional residual capacity (oxygen reserve) — children desaturate faster.","category":"Breathing"},{"id":"c01_fc05","question":"What type of breathers are infants primarily?","answer":"Diaphragmatic breathers, with a more compliant (flexible) chest wall than older children/adults.","category":"Breathing"},{"id":"c01_fc06","question":"What is the leading pathway to pediatric cardiac arrest?","answer":"Respiratory problems — unlike adults, where cardiac causes predominate.","category":"Breathing"},{"id":"c01_fc07","question":"Why is blood pressure a late sign of shock in children?","answer":"Children compensate well for volume loss via tachycardia and vasoconstriction, maintaining normal BP until a large percentage of volume is lost.","category":"Circulation"},{"id":"c01_fc08","question":"What happens once a child's compensatory mechanisms for shock fail?","answer":"Rapid decompensation with little warning.","category":"Circulation"},{"id":"c01_fc09","question":"How should you approach a toddler or preschooler during assessment?","answer":"Keep the caregiver close, demonstrate equipment on a doll or the caregiver first, minimize separation anxiety triggers.","category":"Assessment"},{"id":"c01_fc10","question":"How should you approach an adolescent during assessment?","answer":"With privacy, respect, and honesty; consider interviewing partly apart from caregivers.","category":"Assessment"},{"id":"c01_fc11","question":"Why is a single 'normal vitals' reference useless in pediatrics?","answer":"Normal heart rate, respiratory rate, and blood pressure change substantially across childhood age bands.","category":"Assessment"},{"id":"c01_fc12","question":"What matters more than any single vital sign in isolation?","answer":"Trends over time and the overall clinical picture (the Pediatric Assessment Triangle).","category":"Assessment"},{"id":"c01_fc13","question":"Why can a child's absolute blood volume loss seem 'modest' but still be dangerous?","answer":"A child's total circulating blood volume is small, so the same absolute loss represents a larger percentage of total volume than in an adult.","category":"Circulation"},{"id":"c01_fc14","question":"How does the pediatric larynx position differ from an adult's?","answer":"It sits more anterior and cephalad (higher in the neck).","category":"Airway"}]},"c02":{"chapter":"c02","cards":[{"id":"c02_fc01","question":"What are the three legs of the Pediatric Assessment Triangle (PAT)?","answer":"Appearance, Work of Breathing, and Circulation to Skin.","category":"PAT"},{"id":"c02_fc02","question":"What does TICLS stand for?","answer":"Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry — the components of Appearance.","category":"PAT"},{"id":"c02_fc03","question":"Why is Appearance the most sensitive PAT leg?","answer":"It reflects adequacy of oxygenation, ventilation, brain perfusion, and CNS function — abnormal Appearance is a red flag even with normal breathing/circulation.","category":"PAT"},{"id":"c02_fc04","question":"How is Work of Breathing assessed?","answer":"By looking and listening without a stethoscope: abnormal sounds, abnormal positioning, retractions, nasal flaring, head bobbing.","category":"PAT"},{"id":"c02_fc05","question":"How is Circulation to Skin assessed?","answer":"By skin/mucous membrane color: pallor, mottling, or cyanosis, compared to the child's baseline in adequate lighting.","category":"PAT"},{"id":"c02_fc06","question":"What does abnormal Appearance alone (normal WOB and Circulation) suggest?","answer":"A primarily CNS/metabolic problem.","category":"PAT"},{"id":"c02_fc07","question":"What does abnormal Appearance + Work of Breathing suggest?","answer":"A respiratory problem.","category":"PAT"},{"id":"c02_fc08","question":"What does abnormal Appearance + Circulation suggest?","answer":"A shock/circulatory problem.","category":"PAT"},{"id":"c02_fc09","question":"What does abnormality across all three PAT legs suggest?","answer":"Cardiopulmonary failure — the most urgent category.","category":"PAT"},{"id":"c02_fc10","question":"When is the PAT performed relative to the primary assessment?","answer":"Before it — the PAT is hands-off and sets the pace/urgency, but does not replace the hands-on primary (ABCDE) assessment that follows.","category":"PAT"},{"id":"c02_fc11","question":"Is the PAT performed with a stethoscope or BP cuff?","answer":"No — it is entirely hands-off, done visually and by listening from across the room.","category":"PAT"},{"id":"c02_fc12","question":"What does 'retractions' mean in the Work of Breathing assessment?","answer":"Visible pulling in of the chest wall at the suprasternal, intercostal, or subcostal areas during breathing effort.","category":"PAT"},{"id":"c02_fc13","question":"Why does Work of Breathing increase before oxygen saturation falls?","answer":"Increased effort reflects the body's compensation for an oxygenation/ventilation problem, occurring before desaturation is measurable.","category":"PAT"},{"id":"c02_fc14","question":"A child looks completely normal on PAT. What should you still do?","answer":"Proceed to a full hands-on primary assessment — a normal PAT does not skip that step, it just sets a calmer pace.","category":"PAT"}]},"c03":{"chapter":"c03","cards":[{"id":"c03_fc01","question":"What does ABCDE stand for in the pediatric primary assessment?","answer":"Airway, Breathing, Circulation, Disability, Exposure.","category":"Primary Assessment"},{"id":"c03_fc02","question":"When is a life threat found during ABCDE treated?","answer":"Immediately, the moment it is found — not after completing the rest of the checklist.","category":"Primary Assessment"},{"id":"c03_fc03","question":"What is assessed under 'Disability' in pediatric ABCDE?","answer":"A rapid neurologic check (e.g., AVPU), pupils, and blood glucose if mental status is altered.","category":"Primary Assessment"},{"id":"c03_fc04","question":"What is assessed under 'Exposure'?","answer":"Undressing as needed to check for injury or rash, then keeping the child warm.","category":"Primary Assessment"},{"id":"c03_fc05","question":"How does the PAT relate to the primary assessment?","answer":"The PAT (hands-off) comes first and sets urgency/pace; the primary assessment (hands-on ABCDE) follows and does not get skipped even with a reassuring PAT.","category":"Assessment"},{"id":"c03_fc06","question":"What is the main deliverable of the primary assessment?","answer":"An overall priority decision — high vs. low acuity — not a specific diagnosis.","category":"Primary Assessment"},{"id":"c03_fc07","question":"What pediatric-specific factors are added to scene size-up?","answer":"Mechanism of injury/nature of illness, number of patients (multi-victim events are common), and environmental clues (medications, hazards, caregiver affect).","category":"Scene Size-Up"},{"id":"c03_fc08","question":"What determines whether the primary assessment proceeds rapidly with simultaneous interventions vs. at a calmer pace?","answer":"The urgency level established by the preceding PAT.","category":"Assessment"},{"id":"c03_fc09","question":"What are components of the 'Circulation' step in ABCDE?","answer":"Pulse rate/quality, skin perfusion, capillary refill, and external bleeding.","category":"Primary Assessment"},{"id":"c03_fc10","question":"What are components of the 'Breathing' step in ABCDE?","answer":"Rate, effort, breath sounds, and oxygen saturation.","category":"Primary Assessment"},{"id":"c03_fc11","question":"Where should a provider look for depth on cardiac-arrest-specific ABCDE content?","answer":"The PALS reviewer — PEPP's ABCDE is a field assessment/transport-decision tool, not a resuscitation-team algorithm.","category":"Cross-Reference"},{"id":"c03_fc12","question":"Why should priority be reassessed throughout the encounter?","answer":"New findings can emerge as the exam and treatment proceed, changing the acuity picture.","category":"Assessment"},{"id":"c03_fc13","question":"Why involve a calm caregiver early in the scene, when safe?","answer":"It often improves both scene safety and the child's cooperation during assessment.","category":"Scene Size-Up"},{"id":"c03_fc14","question":"What is assessed under 'Airway' in pediatric ABCDE?","answer":"Patency — whether the airway is open, maintainable, or requires positioning/intervention.","category":"Primary Assessment"},{"id":"c03_fc15","question":"What pediatric-specific consideration applies during the scene size-up for a suspected multi-victim event?","answer":"Actively count and account for all children present, since multi-victim pediatric events (e.g., daycare, school, family incidents) are common and easy to under-triage.","category":"Scene Size-Up"}]},"c04":{"chapter":"c04","cards":[{"id":"c04_fc01","question":"What does the SAMPLE history mnemonic stand for?","answer":"Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading up to the incident.","category":"History"},{"id":"c04_fc02","question":"What pediatric-specific elements are added to SAMPLE?","answer":"Birth history and developmental milestones (infants), immunization status, and growth/weight trends for dosing.","category":"History"},{"id":"c04_fc03","question":"Who should be asked directly for history whenever possible?","answer":"School-age children and adolescents — caregiver accounts should supplement, not replace, the child's own report.","category":"History"},{"id":"c04_fc04","question":"What exam order is preferred for infants and toddlers?","answer":"Toe-to-head — starting with less threatening areas improves cooperation.","category":"Secondary Assessment"},{"id":"c04_fc05","question":"What exam order is typically used for school-age children and adolescents?","answer":"Standard head-to-toe sequence.","category":"Secondary Assessment"},{"id":"c04_fc06","question":"What is family-centered care?","answer":"Treating the caregiver as a partner in the child's care, including allowing presence during many procedures and even resuscitation with a support person.","category":"Family-Centered Care"},{"id":"c04_fc07","question":"Does keeping a caregiver present typically slow down care?","answer":"No — it usually reduces the child's distress and improves cooperation without meaningfully slowing care.","category":"Family-Centered Care"},{"id":"c04_fc08","question":"How should you communicate with a family that doesn't speak English?","answer":"Use professional interpretation services rather than relying on a child to interpret for their own care.","category":"Communication"},{"id":"c04_fc09","question":"How should you approach a child with developmental delay or autism spectrum differences?","answer":"Take cues from the caregiver about the child's usual communication style, minimize sensory overload, and allow extra time.","category":"Communication"},{"id":"c04_fc10","question":"How should you communicate with a hearing-impaired child or caregiver?","answer":"Face them directly, speak clearly (not necessarily loudly), and use written notes or interpreter services as needed.","category":"Communication"},{"id":"c04_fc11","question":"What is the focused exam used for?","answer":"A targeted exam for stable/low-priority patients, directed at the chief complaint.","category":"Secondary Assessment"},{"id":"c04_fc12","question":"What is the rapid exam used for?","answer":"A more limited exam for high-priority patients, often performed en route to the hospital.","category":"Secondary Assessment"},{"id":"c04_fc13","question":"What four steps make up PEPP's complete assessment sequence?","answer":"PAT, primary assessment, history, secondary assessment.","category":"Assessment"},{"id":"c04_fc14","question":"Why is adapting communication considered a clinical skill rather than a courtesy?","answer":"It materially affects the quality of the history and exam obtained, directly impacting patient care.","category":"Communication"},{"id":"c04_fc15","question":"Why is growth/weight trend information relevant to a pediatric SAMPLE history?","answer":"It informs weight-based medication dosing considerations that may apply during subsequent care.","category":"History"}]},"c05":{"chapter":"c05","cards":[{"id":"c05_fc01","question":"What is respiratory distress?","answer":"A state where a child is working hard to breathe (increased work of breathing) but is still compensating, generally with adequate oxygenation and mental status.","category":"Respiratory"},{"id":"c05_fc02","question":"What is respiratory failure?","answer":"A state where compensation has failed — inadequate oxygenation and/or ventilation, marked by altered mental status, cyanosis, bradypnea/irregular breathing, and profound fatigue.","category":"Respiratory"},{"id":"c05_fc03","question":"What are the four categories of pediatric respiratory compromise?","answer":"Upper airway obstruction, lower airway disease, lung tissue (parenchymal) disease, and disordered control of breathing.","category":"Respiratory"},{"id":"c05_fc04","question":"What sound is classically associated with upper airway obstruction?","answer":"Stridor.","category":"Respiratory"},{"id":"c05_fc05","question":"What sound is classically associated with lower airway disease?","answer":"Wheezing, with prolonged expiration.","category":"Respiratory"},{"id":"c05_fc06","question":"What findings are classically associated with lung tissue (parenchymal) disease?","answer":"Grunting, crackles, and diminished breath sounds.","category":"Respiratory"},{"id":"c05_fc07","question":"What characterizes disordered control of breathing?","answer":"An irregular rate/pattern without the classic sounds of the other three categories, often from a CNS problem, toxin, or neuromuscular disease.","category":"Respiratory"},{"id":"c05_fc08","question":"Give two examples of causes of upper airway obstruction.","answer":"Croup and foreign body aspiration (also epiglottitis).","category":"Respiratory"},{"id":"c05_fc09","question":"Give two examples of causes of lower airway disease.","answer":"Asthma and bronchiolitis.","category":"Respiratory"},{"id":"c05_fc10","question":"Why is decreasing work of breathing in a previously struggling child a red flag?","answer":"It can reflect exhaustion rather than improvement — a dangerous, easily misread sign of impending respiratory failure.","category":"Respiratory"},{"id":"c05_fc11","question":"What PAT change signals impending respiratory failure?","answer":"A shift in Appearance from anxious/agitated to lethargic on repeat assessment.","category":"Respiratory"},{"id":"c05_fc12","question":"Should a provider wait for SpO2 to fall before escalating support in a deteriorating child?","answer":"No — other findings (grunting, decreasing WOB after struggling, altered Appearance) often precede a measurable drop in SpO2 and should prompt escalation first.","category":"Respiratory"},{"id":"c05_fc13","question":"What is the field management for respiratory distress?","answer":"Positioning of comfort, supplemental oxygen, and treatment targeted to the likely category (e.g., nebulized bronchodilator for suspected lower-airway disease), with close monitoring.","category":"Field Management"},{"id":"c05_fc14","question":"What is the field management for respiratory failure?","answer":"Assisted ventilation with bag-mask ventilation and high-flow oxygen, plus rapid transport; drug-assisted airway management and arrest-specific ventilation are covered in depth by the PALS reviewer.","category":"Field Management"},{"id":"c05_fc15","question":"Why do respiratory problems matter so much in pediatric prehospital care?","answer":"They are the leading pathway to pediatric cardiac arrest, unlike adults where a primary cardiac event is more common.","category":"Respiratory"}]},"c06":{"chapter":"c06","cards":[{"id":"c06_fc01","question":"How is shock best defined?","answer":"Inadequate delivery of oxygen and nutrients to meet tissue demands — a perfusion problem, not a specific blood pressure value.","category":"Shock"},{"id":"c06_fc02","question":"Can a child be in shock with a normal blood pressure?","answer":"Yes — this is compensated shock; children compensate well via tachycardia and vasoconstriction, keeping BP normal until late.","category":"Shock"},{"id":"c06_fc03","question":"What does hypotension mean in a pediatric shock patient?","answer":"It signals decompensated shock — a late, ominous sign meaning compensatory mechanisms have been exhausted.","category":"Shock"},{"id":"c06_fc04","question":"List the perfusion findings used to recognize compensated shock.","answer":"Tachycardia, delayed capillary refill, abnormal skin color/temperature (cool/mottled or warm/flushed), weak/narrowed pulses, narrowed pulse pressure.","category":"Shock"},{"id":"c06_fc05","question":"What are the four major categories of pediatric shock?","answer":"Hypovolemic, distributive, cardiogenic, and obstructive.","category":"Shock"},{"id":"c06_fc06","question":"What is the most common category of shock in children overall?","answer":"Hypovolemic shock (from fluid or blood loss, e.g., dehydration, hemorrhage, burns).","category":"Shock"},{"id":"c06_fc07","question":"Name three types of distributive shock.","answer":"Septic shock, anaphylactic shock, and neurogenic shock (rare in children).","category":"Shock"},{"id":"c06_fc08","question":"What causes cardiogenic shock in children?","answer":"Pump failure from congenital heart disease, myocarditis, or arrhythmia.","category":"Shock"},{"id":"c06_fc09","question":"What causes obstructive shock?","answer":"A physical obstruction to blood flow, such as tension pneumothorax, cardiac tamponade, or massive pulmonary embolism (rare in children).","category":"Shock"},{"id":"c06_fc10","question":"How might early septic (distributive) shock differ in appearance from hypovolemic shock?","answer":"Early septic shock can present with warm, flushed skin and bounding pulses (rather than cold/mottled skin), despite poor perfusion.","category":"Shock"},{"id":"c06_fc11","question":"What PAT findings suggest shock?","answer":"Abnormal Appearance (irritability progressing to lethargy) and/or abnormal Circulation to Skin (pallor, mottling, cyanosis), often with normal-appearing work of breathing.","category":"Shock"},{"id":"c06_fc12","question":"What is the priority field treatment for suspected anaphylactic shock?","answer":"Epinephrine.","category":"Field Management"},{"id":"c06_fc13","question":"What is the priority field treatment for suspected obstructive shock from tension pneumothorax?","answer":"Needle decompression per protocol/scope of practice.","category":"Field Management"},{"id":"c06_fc14","question":"What is the general supportive field management for shock regardless of category?","answer":"Supplemental oxygen, positioning (supine, legs elevated if tolerated), keep the child warm, and rapid transport.","category":"Field Management"},{"id":"c06_fc15","question":"Where should providers look for drug dosing tables and advanced shock/arrest resuscitation algorithms?","answer":"The PALS reviewer — PEPP covers field recognition and initial stabilization only.","category":"Field Management"}]},"c07":{"chapter":"c07","cards":[{"id":"c07_fc01","question":"Are primary cardiac events common in children?","answer":"No — unlike adults, primary cardiac disease is a rare cause of pediatric emergencies; most cardiac problems are secondary.","category":"Cardiac"},{"id":"c07_fc02","question":"What is the most common cause of pediatric bradycardia?","answer":"Hypoxia.","category":"Cardiac"},{"id":"c07_fc03","question":"Besides hypoxia, what else can cause pediatric bradycardia?","answer":"Increased vagal tone, hypothermia, or increased intracranial pressure.","category":"Cardiac"},{"id":"c07_fc04","question":"What is the field priority for symptomatic bradycardia in a child?","answer":"Address the underlying cause — oxygenate and ventilate first — rather than treating the rhythm number alone.","category":"Cardiac"},{"id":"c07_fc05","question":"How does sinus tachycardia typically behave?","answer":"It is a compensatory response (fever, pain, anxiety, dehydration, shock) with a variable rate that resolves as the underlying cause is treated.","category":"Cardiac"},{"id":"c07_fc06","question":"How does supraventricular tachycardia (SVT) typically behave?","answer":"It is a primary rhythm disturbance with a fixed, very rapid rate that does not vary with stimulation and can itself cause poor perfusion.","category":"Cardiac"},{"id":"c07_fc07","question":"What infant heart rate threshold is often used to raise suspicion for SVT?","answer":">220 bpm in infants (compared to >180 bpm in older children), as a fixed rate not varying with stimulation.","category":"Cardiac"},{"id":"c07_fc08","question":"Why should a provider ask about a child's known congenital heart disease?","answer":"Because such children may have a baseline vital signs or oxygen saturation that differs from typical pediatric norms, and are at elevated risk for arrhythmia, heart failure, and cardiogenic shock.","category":"Cardiac"},{"id":"c07_fc09","question":"What family history clue raises suspicion for an underlying cardiac cause of unexplained pediatric collapse?","answer":"Sudden unexplained death in a young relative (suggesting a possible cardiac channelopathy).","category":"Cardiac"},{"id":"c07_fc10","question":"What are the field priorities for a pediatric cardiac emergency?","answer":"Recognition (PAT + primary assessment + monitor/rhythm strip if available), identifying reversible causes (especially hypoxia), and rapid transport with continuous reassessment.","category":"Field Management"},{"id":"c07_fc11","question":"Does this PEPP chapter cover arrest algorithms and antiarrhythmic drug dosing in depth?","answer":"No — those are covered in full depth by the PALS reviewer; this chapter covers field recognition and initial stabilization only.","category":"Field Management"},{"id":"c07_fc12","question":"What is a poor-perfusion bradycardic infant most likely to represent until proven otherwise?","answer":"A respiratory or hypoxia problem, not a primary cardiac rhythm problem.","category":"Cardiac"},{"id":"c07_fc13","question":"What older-child heart rate threshold is often used to raise suspicion for SVT?","answer":">180 bpm in older children (compared to >220 bpm in infants), as a fixed rate not varying with stimulation.","category":"Cardiac"},{"id":"c07_fc14","question":"Why does PEPP avoid reproducing PALS's arrest-algorithm and drug-dosing content in this chapter?","answer":"To avoid duplicating PALS's authoritative resuscitation depth, keeping this chapter scoped to field recognition and initial stabilization.","category":"Field Management"}]},"c08":{"chapter":"c08","cards":[{"id":"c08_fc01","question":"What PAT leg often gives the first clue to altered mental status?","answer":"Appearance (e.g., poor eye contact, abnormal cry, decreased interactiveness).","category":"Neurologic"},{"id":"c08_fc02","question":"What does AVPU stand for?","answer":"Alert, Voice, Pain, Unresponsive.","category":"Neurologic"},{"id":"c08_fc03","question":"What does the AEIOU-TIPS mnemonic help recall?","answer":"Reversible causes of altered mental status: Alcohol/substance, Epilepsy/postictal, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke.","category":"Neurologic"},{"id":"c08_fc04","question":"Why should every altered child get a glucose check when available?","answer":"Hypoglycemia is a common, rapidly reversible cause of altered mental status in children.","category":"Neurologic"},{"id":"c08_fc05","question":"What are the field priorities during an active pediatric seizure?","answer":"Protect the airway (positioning, suction as needed, nothing in the mouth), protect from injury, check glucose, and time the seizure.","category":"Seizures"},{"id":"c08_fc06","question":"What defines status epilepticus?","answer":"A seizure lasting more than 5 minutes, or repeated seizures without return to baseline between them.","category":"Seizures"},{"id":"c08_fc07","question":"Is status epilepticus a time-critical emergency?","answer":"Yes — it requires rapid escalation of care and transport; benzodiazepine dosing is detailed in the PALS reviewer.","category":"Seizures"},{"id":"c08_fc08","question":"What age range is most typical for febrile seizures?","answer":"6 months to 5 years, with a rapidly rising fever.","category":"Seizures"},{"id":"c08_fc09","question":"What defines a simple febrile seizure?","answer":"Generalized, lasts less than 15 minutes, does not recur within 24 hours, and the child returns to baseline mental status afterward.","category":"Seizures"},{"id":"c08_fc10","question":"What defines a complex febrile seizure?","answer":"Focal features, lasting more than 15 minutes, or recurring within 24 hours — warrants a higher level of concern.","category":"Seizures"},{"id":"c08_fc11","question":"What are signs suggesting increased intracranial pressure in an infant?","answer":"A bulging fontanelle, decreasing level of consciousness, and an irregular respiratory pattern.","category":"Neurologic"},{"id":"c08_fc12","question":"What is the Cushing triad?","answer":"Hypertension, bradycardia, and irregular respirations — a late and ominous sign of increased intracranial pressure.","category":"Neurologic"},{"id":"c08_fc13","question":"What two physiologic states should be avoided in a child with suspected increased intracranial pressure, and why?","answer":"Hypoxia and hypotension — both worsen secondary brain injury.","category":"Neurologic"},{"id":"c08_fc14","question":"Should a trend of decreasing responsiveness on serial reassessment be treated as more or less concerning than a single snapshot?","answer":"More concerning — trends over time matter more than a single value.","category":"Neurologic"}]},"c09":{"chapter":"c09","cards":[{"id":"c09_fc01","question":"Why do children have distinct trauma injury patterns compared to adults?","answer":"A larger head-to-body ratio, more pliable ribcage, less protected abdominal organs, and thinner subcutaneous tissue create different vulnerabilities.","category":"Trauma"},{"id":"c09_fc02","question":"Why does head injury tend to dominate in pediatric trauma?","answer":"The relatively larger, heavier head increases both injury risk and force absorbed in falls/collisions.","category":"Trauma"},{"id":"c09_fc03","question":"Why can significant chest injury occur in children without rib fractures?","answer":"The pediatric ribcage is more pliable/elastic, allowing energy transmission (e.g., pulmonary contusion) without fracturing ribs.","category":"Trauma"},{"id":"c09_fc04","question":"Does the absence of rib fractures rule out significant chest injury in a child?","answer":"No — absence of fractures does not exclude serious underlying injury.","category":"Trauma"},{"id":"c09_fc05","question":"Why are abdominal organs more vulnerable to blunt trauma in children?","answer":"The liver and spleen are proportionally larger and less protected by the ribcage than in adults.","category":"Trauma"},{"id":"c09_fc06","question":"Does a soft, non-tender abdomen exclude significant abdominal injury in a child?","answer":"No — significant injury can be present despite a falsely reassuring abdominal exam, especially early after the event.","category":"Trauma"},{"id":"c09_fc07","question":"Can a child maintain a normal blood pressure despite significant blood loss?","answer":"Yes — children compensate effectively, so tachycardia and delayed capillary refill may appear well before hypotension.","category":"Trauma"},{"id":"c09_fc08","question":"What perfusion findings should be treated as seriously as hypotension after pediatric trauma?","answer":"Tachycardia, delayed capillary refill, and cool extremities.","category":"Trauma"},{"id":"c09_fc09","question":"Why does a child's head shape matter for spinal positioning on a backboard?","answer":"The proportionally larger head can force the neck into flexion when lying flat, so torso padding (not just head padding) helps maintain neutral alignment.","category":"Trauma"},{"id":"c09_fc10","question":"Why does mechanism/mental status carry more weight than reported pain in pediatric spinal motion restriction decisions?","answer":"Young children may not reliably report pain or tenderness, making mechanism and mental status more dependable decision factors.","category":"Trauma"},{"id":"c09_fc11","question":"What signs in an infant after head trauma suggest evolving intracranial injury?","answer":"A bulging fontanelle or decreasing mental status.","category":"Trauma"},{"id":"c09_fc12","question":"What is the field management priority for pediatric trauma overall?","answer":"Scene safety, hemorrhage control, ABC support, and rapid transport to an appropriate (ideally pediatric-capable) trauma center, with attention to pediatric-specific injury patterns.","category":"Field Management"},{"id":"c09_fc13","question":"Why is rib fracture presence itself clinically important in a child, apart from its direct pain?","answer":"It signals a high-energy mechanism, raising suspicion for significant underlying pulmonary or cardiac injury even without other obvious findings.","category":"Trauma"},{"id":"c09_fc14","question":"What criteria factor most heavily into selective spinal motion restriction decisions in young children?","answer":"Mechanism of injury and mental status, since pain/tenderness reporting is less reliable in this age group.","category":"Trauma"}]},"c10":{"chapter":"c10","cards":[{"id":"c10_fc01","question":"Which age group is at peak risk for unintentional poisoning?","answer":"Toddlers (roughly 1-3 years), due to mobility, curiosity, and mouthing behavior.","category":"Toxicology"},{"id":"c10_fc02","question":"What are common household sources of pediatric poisoning?","answer":"Medications (including caregivers'/grandparents' medications), cleaning products, and button batteries.","category":"Toxicology"},{"id":"c10_fc03","question":"What should field assessment of a suspected ingestion focus on?","answer":"Identifying the substance, amount, and time of exposure when possible, and bringing containers/pills to the hospital.","category":"Toxicology"},{"id":"c10_fc04","question":"What toxidrome pattern suggests opioid exposure?","answer":"Altered mental status plus pinpoint pupils and respiratory depression.","category":"Toxicology"},{"id":"c10_fc05","question":"Why is button battery ingestion especially dangerous?","answer":"A lodged battery in the esophagus can cause severe tissue injury within hours through an electrical current effect, not just direct chemical burn.","category":"Toxicology"},{"id":"c10_fc06","question":"How should a suspected button battery ingestion be treated, regardless of symptoms?","answer":"As a time-critical emergency requiring rapid transport and hospital notification, since injury can progress even in an asymptomatic child.","category":"Toxicology"},{"id":"c10_fc07","question":"Why are children more vulnerable to heat illness than adults?","answer":"Higher surface-area-to-mass ratio, less efficient sweating, and reliance on caregivers to remove them from hot environments.","category":"Environmental"},{"id":"c10_fc08","question":"Why is a child left in a hot vehicle especially dangerous?","answer":"Internal vehicle temperatures can become life-threatening within minutes.","category":"Environmental"},{"id":"c10_fc09","question":"Why are children more vulnerable to hypothermia than adults?","answer":"The same higher surface-area-to-mass ratio, plus limited ability to generate heat through shivering in infants.","category":"Environmental"},{"id":"c10_fc10","question":"Which age groups are at highest risk for drowning?","answer":"Toddlers (bathtubs, pools) and adolescents (open water, often with risk-taking or alcohol).","category":"Drowning"},{"id":"c10_fc11","question":"What is the core physiologic problem in drowning?","answer":"Hypoxia — drowning is fundamentally a respiratory event.","category":"Drowning"},{"id":"c10_fc12","question":"When should spinal motion restriction be applied after a submersion event?","answer":"Only if the mechanism suggests trauma (e.g., a diving injury).","category":"Drowning"},{"id":"c10_fc13","question":"Should a well-appearing child be transported after a submersion event?","answer":"Yes — pulmonary complications can evolve over hours even in an apparently well-appearing child.","category":"Drowning"},{"id":"c10_fc14","question":"What is the general field management framework for toxic/environmental emergencies?","answer":"Identify the exposure/mechanism, support the ABCs, remove the child from the ongoing hazard, bring relevant materials to the hospital, and transport promptly with a lower threshold than for adults.","category":"Field Management"}]},"c11":{"chapter":"c11","cards":[{"id":"c11_fc01","question":"What physiologic transition must a newborn undergo at birth?","answer":"Transition from placental gas exchange to independent breathing, with lung fluid clearing and fetal circulatory shunts closing.","category":"Neonatal"},{"id":"c11_fc02","question":"What are the three initial questions asked immediately after delivery?","answer":"Is the newborn term gestation? Does the newborn have good tone? Is the newborn breathing or crying?","category":"Neonatal"},{"id":"c11_fc03","question":"What happens if the answer to all three initial questions is yes?","answer":"The newborn can stay with the mother for routine care (dry, warm, skin-to-skin).","category":"Neonatal"},{"id":"c11_fc04","question":"What happens if any of the three initial questions is answered no?","answer":"The newborn is moved to a warmer for the initial steps of stabilization.","category":"Neonatal"},{"id":"c11_fc05","question":"What are the initial steps of newborn stabilization?","answer":"Provide warmth, position the airway, clear secretions only if needed, dry thoroughly, and stimulate.","category":"Neonatal"},{"id":"c11_fc06","question":"Is routine deep suctioning recommended for every newborn?","answer":"No — suction is not routine; secretions are cleared only if needed.","category":"Neonatal"},{"id":"c11_fc07","question":"Why is keeping a newborn warm a high priority?","answer":"A wet, uncovered newborn loses heat extremely rapidly, and hypothermia worsens outcomes.","category":"Neonatal"},{"id":"c11_fc08","question":"When is positive-pressure ventilation (PPV) indicated for a newborn?","answer":"If, after the initial steps, the newborn is apneic, gasping, or has a heart rate below 100 bpm.","category":"Neonatal"},{"id":"c11_fc09","question":"What is the single most important intervention in newborn resuscitation?","answer":"Positive-pressure ventilation.","category":"Neonatal"},{"id":"c11_fc10","question":"When are chest compressions added during newborn resuscitation?","answer":"Only if the heart rate remains below 60 bpm despite 30 seconds of effective PPV.","category":"Neonatal"},{"id":"c11_fc11","question":"How does the newborn resuscitation sequence differ from adult/older-child arrest sequences?","answer":"Ventilation comes first and is prioritized; compressions are added only if ventilation alone fails to raise the heart rate above 60 bpm, reflecting that most newborn compromise is a ventilation problem.","category":"Neonatal"},{"id":"c11_fc12","question":"Where should providers look for detailed neonatal resuscitation algorithms, medication dosing, and advanced airway specifics?","answer":"Their local neonatal resuscitation protocol / the Neonatal Resuscitation Program (NRP), the authoritative source for this skill set.","category":"Field Management"},{"id":"c11_fc13","question":"What does 'vigorous' typically describe about a newborn who does not need the initial stabilization steps?","answer":"Strong cry, good tone, and pink/appropriate color within the first minute after birth.","category":"Neonatal"},{"id":"c11_fc14","question":"Roughly how long do the initial steps of newborn stabilization take before reassessment?","answer":"About 30 seconds.","category":"Neonatal"}]},"c12":{"chapter":"c12","cards":[{"id":"c12_fc01","question":"What is the EMS provider's role regarding suspected child maltreatment?","answer":"To recognize concerning findings, document objectively, and report through appropriate channels — not to investigate or accuse.","category":"Maltreatment"},{"id":"c12_fc02","question":"What is a central concept for recognizing possibly concerning injuries?","answer":"Comparing the stated mechanism/history to the child's developmental capability and the injury pattern itself — inconsistency raises concern.","category":"Maltreatment"},{"id":"c12_fc03","question":"Give an example of a history-injury inconsistency.","answer":"A non-mobile young infant reportedly 'rolled off the couch' and sustained a fracture — inconsistent with that infant's developmental stage.","category":"Maltreatment"},{"id":"c12_fc04","question":"Besides mechanism inconsistency, what other general categories may raise concern?","answer":"A history that changes between tellings/caregivers, an unexplained delay in seeking care, and unusual injury locations or types.","category":"Maltreatment"},{"id":"c12_fc05","question":"Is any single finding diagnostic of maltreatment on its own?","answer":"No — providers document what they observe and let appropriate professionals evaluate the full picture.","category":"Maltreatment"},{"id":"c12_fc06","question":"How should providers communicate with caregivers when maltreatment is suspected?","answer":"Calmly, professionally, and non-accusatorially — confrontation can compromise the child's care and any subsequent investigation.","category":"Maltreatment"},{"id":"c12_fc07","question":"What kind of documentation is most useful when maltreatment is suspected?","answer":"Objective documentation — exact quotes, observed findings, and scene details — rather than subjective conclusions.","category":"Maltreatment"},{"id":"c12_fc08","question":"Are EMS providers mandatory reporters of suspected child maltreatment?","answer":"Yes, in essentially all jurisdictions — they are legally required to report reasonable suspicion through the appropriate channel.","category":"Maltreatment"},{"id":"c12_fc09","question":"Does this chapter specify jurisdiction-specific reporting mechanics?","answer":"No — reporting mechanics vary by location; providers must follow their own agency policy and local/state law.","category":"Maltreatment"},{"id":"c12_fc10","question":"Who should be involved when suspicion of maltreatment arises during a call?","answer":"Medical direction and receiving-facility staff, per local protocol.","category":"Maltreatment"},{"id":"c12_fc11","question":"Should EMS providers confront caregivers directly about suspected maltreatment on scene?","answer":"No — this is a common mistake; the EMS role is recognition and reporting, not confrontation or accusation.","category":"Maltreatment"},{"id":"c12_fc12","question":"What is the appropriate balance between providing medical care and addressing suspicion of maltreatment on scene?","answer":"Continue providing standard medical care for the child's presenting condition while separately documenting objectively and reporting through appropriate channels.","category":"Maltreatment"},{"id":"c12_fc13","question":"Why does an unexplained delay in seeking care raise concern in pediatric injury assessment?","answer":"It is a recognized general category that, alongside other findings, may prompt objective documentation and reporting per policy — though it alone is not diagnostic.","category":"Maltreatment"},{"id":"c12_fc14","question":"Why does this chapter avoid providing a definitive maltreatment checklist?","answer":"Because no single finding is diagnostic and jurisdiction-specific reporting/legal processes vary, so providers rely on local training, agency policy, and law.","category":"Maltreatment"}]},"c13":{"chapter":"c13","cards":[{"id":"c13_fc01","question":"What does CSHCN stand for?","answer":"Children with special healthcare needs.","category":"Special Needs"},{"id":"c13_fc02","question":"Why are caregivers of CSHCN a critical information resource?","answer":"They are frequently the most knowledgeable resource on scene about the child's baseline, equipment, and typical emergency presentation.","category":"Special Needs"},{"id":"c13_fc03","question":"What is a tracheostomy, and what are common field problems with one?","answer":"A surgical airway bypassing the upper airway; common problems include mucus plugging, accidental decannulation, and tube malposition.","category":"Technology"},{"id":"c13_fc04","question":"What is a gastrostomy (G-) tube used for?","answer":"Enteral feeding directly into the stomach.","category":"Technology"},{"id":"c13_fc05","question":"What condition does a ventriculoperitoneal (VP) shunt treat, and how?","answer":"Hydrocephalus, by diverting cerebrospinal fluid.","category":"Technology"},{"id":"c13_fc06","question":"What is the field priority for a child with a tracheostomy in respiratory distress?","answer":"Attempt suctioning first, then check for accidental decannulation and replace the tube (or ventilate via the stoma) if needed.","category":"Technology"},{"id":"c13_fc07","question":"Who can often assist rapidly with tracheostomy troubleshooting?","answer":"The caregiver, who manages this equipment daily.","category":"Special Needs"},{"id":"c13_fc08","question":"What signs suggest VP shunt malfunction in a child with a known shunt?","answer":"Headache, vomiting, altered mental status, irritability (infants), or a bulging fontanelle (infants).","category":"Technology"},{"id":"c13_fc09","question":"Why does VP shunt malfunction cause signs of increased intracranial pressure?","answer":"Shunt failure prevents normal cerebrospinal fluid drainage.","category":"Technology"},{"id":"c13_fc10","question":"What is the field management for suspected VP shunt malfunction?","answer":"Standard increased-ICP precautions (avoid hypoxia/hypotension, positioning) and rapid transport; shunt-specific fixes are hospital-level.","category":"Technology"},{"id":"c13_fc11","question":"Why is baseline function more useful than population norms when assessing a CSHCN patient?","answer":"A CSHCN patient's 'normal' resting vitals or interactiveness may differ substantially from typically developing children, so their own baseline is the most meaningful reference point.","category":"Special Needs"},{"id":"c13_fc12","question":"What question should providers always ask when assessing a CSHCN patient?","answer":"'What is normal for this child?'","category":"Special Needs"},{"id":"c13_fc13","question":"What does a central venous catheter provide, and what are common field concerns?","answer":"Vascular access for children needing frequent IV therapy; field concerns include infection signs and line malfunction.","category":"Technology"},{"id":"c13_fc14","question":"What is a home ventilator used for, and who is typically expert in troubleshooting it?","answer":"It provides mechanical ventilation via tracheostomy for children with chronic respiratory failure; caregivers are typically expert in troubleshooting their specific device.","category":"Technology"}]},"c14":{"chapter":"c14","cards":[{"id":"c14_fc01","question":"What factors guide pediatric transport destination decisions?","answer":"The severity/type of the child's condition weighed against nearby facilities' pediatric-specific capabilities (pediatric trauma center, PICU, pediatric surgical subspecialists).","category":"EMS Operations"},{"id":"c14_fc02","question":"What should a provider do when a closer general facility lacks pediatric capability for a significantly ill/injured child?","answer":"Follow local protocol for bypass to a pediatric-capable/pediatric trauma center and consult medical direction as needed.","category":"EMS Operations"},{"id":"c14_fc03","question":"Why do children need specific consideration in disaster planning, beyond adult planning?","answer":"Unique vulnerabilities: increased susceptibility to chemical/radiological exposure, dependence on caregivers for evacuation, psychological vulnerability, and different equipment/medication needs.","category":"Disaster Planning"},{"id":"c14_fc04","question":"What is JumpSTART?","answer":"A pediatric-specific adaptation of the adult START MCI triage algorithm.","category":"MCI Triage"},{"id":"c14_fc05","question":"Why was JumpSTART developed instead of using adult START for children?","answer":"Children's physiologic norms and injury/arrest patterns differ enough from adults to require adjusted triage criteria.","category":"MCI Triage"},{"id":"c14_fc06","question":"What special step does JumpSTART include for an apneic child with a pulse?","answer":"Give five rescue breaths before categorizing as expectant, reflecting that pediatric arrest is often respiratory in origin and may be reversible.","category":"MCI Triage"},{"id":"c14_fc07","question":"What scale does JumpSTART use to assess mental status, and why?","answer":"AVPU, rather than command-following, since it is more appropriate across pediatric developmental stages.","category":"MCI Triage"},{"id":"c14_fc08","question":"What respiratory rate consideration differs between JumpSTART and adult START?","answer":"JumpSTART uses pediatric-specific respiratory rate thresholds rather than the adult cutoff.","category":"MCI Triage"},{"id":"c14_fc09","question":"What operational challenge exists in distinguishing findings in children at a chaotic MCI scene?","answer":"Distinguishing a child's baseline developmental behavior from a triage-relevant abnormal finding under stressful, chaotic conditions.","category":"MCI Triage"},{"id":"c14_fc10","question":"What equipment/medication risk is heightened in pediatric MCI response?","answer":"Inadequate pediatric-sized equipment and medication dosing errors under stress if not specifically planned for.","category":"Disaster Planning"},{"id":"c14_fc11","question":"How should family reunification after a pediatric-involving MCI be handled?","answer":"Through an established incident reunification process (tracking systems, designated reunification points) coordinated by incident command/emergency management, not ad hoc by individual field providers.","category":"EMS Operations"},{"id":"c14_fc12","question":"What should field providers do for an unaccompanied child during an MCI?","answer":"Document identifying information when possible and follow the established incident reunification process.","category":"EMS Operations"},{"id":"c14_fc13","question":"What are the four JumpSTART triage categories?","answer":"Minor (green), Immediate (red), Delayed (yellow), and Expectant (black/gray).","category":"MCI Triage"},{"id":"c14_fc14","question":"Why should triage personnel avoid applying adult START criteria directly to pediatric MCI patients?","answer":"Doing so risks misclassifying children, since adult thresholds (e.g., respiratory rate) don't match pediatric physiologic norms.","category":"MCI Triage"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"What is the core organizing principle of PEPP's approach to pediatric patients?","options":["A. Children should be treated with scaled-down adult protocols","B. Children differ from adults anatomically, physiologically, developmentally, and psychosocially — not just in size","C. Pediatric care is identical to adult care below a certain weight threshold","D. Only infants require a different assessment approach"],"correct":1,"rationale":"PEPP's foundational premise is that children are not small adults — differences span anatomy, physiology, development, and psychosocial needs, requiring a distinct approach at every stage of care.","difficulty":"Easy"},{"id":"c01_q02","question":"Where is the narrowest point of a young child's airway located?","options":["A. At the vocal cords, same as adults","B. Subglottic, below the vocal cords","C. At the nostrils","D. At the epiglottis only"],"correct":1,"rationale":"Unlike adults, whose airway narrows at the vocal cords, a young child's airway is narrowest below the cords (subglottic), an important anatomic difference for airway management.","difficulty":"Medium"},{"id":"c01_q03","question":"Why do children desaturate faster than adults when breathing is compromised?","options":["A. They have larger oxygen reserves","B. Higher metabolic rate/oxygen consumption combined with smaller functional residual capacity","C. They breathe more slowly than adults","D. Their chest walls are stiffer than adults'"],"correct":1,"rationale":"Children consume more oxygen per kilogram than adults but have less reserve capacity in the lungs, so oxygenation drops faster when ventilation is impaired.","difficulty":"Medium"},{"id":"c01_q04","question":"What is the leading pathway to cardiac arrest in children, distinct from adults?","options":["A. Primary cardiac dysrhythmia","B. Respiratory problems","C. Toxic ingestion","D. Congenital heart disease in all cases"],"correct":1,"rationale":"Unlike adults where primary cardiac events predominate, pediatric arrest is most often the end result of progressive respiratory failure or shock.","difficulty":"Easy"},{"id":"c01_q05","question":"Why is blood pressure considered a late and unreliable early sign of shock in children?","options":["A. Children cannot mount a compensatory response","B. Children compensate well via tachycardia and vasoconstriction, maintaining normal BP until significant volume is lost","C. Blood pressure is always elevated in pediatric shock","D. Children's blood pressure cannot be measured accurately"],"correct":1,"rationale":"Robust compensatory mechanisms keep blood pressure normal-appearing until a substantial percentage of circulating volume is lost, making BP a poor early screening tool in children.","difficulty":"Medium"},{"id":"c01_q06","question":"What happens once a child's shock compensation fails?","options":["A. Gradual, well-tolerated decline","B. Rapid decompensation with little warning","C. Spontaneous recovery","D. No change in clinical status"],"correct":1,"rationale":"Because compensation in children is so effective until it isn't, decompensation — once it begins — tends to occur rapidly, giving little advance warning.","difficulty":"Medium"},{"id":"c01_q07","question":"What is the best approach to assessing a frightened toddler?","options":["A. Separate the child from caregivers immediately for an accurate exam","B. Keep the caregiver close and demonstrate equipment on a doll or the caregiver first","C. Use complex medical terminology to build trust","D. Approach with unfamiliar equipment first to desensitize the child"],"correct":1,"rationale":"Toddlers fear separation and unfamiliar equipment; keeping caregivers close and demonstrating equipment first reduces distress and improves cooperation and assessment accuracy.","difficulty":"Easy"},{"id":"c01_q08","question":"What is the best approach to interviewing an adolescent patient?","options":["A. Always keep a parent present for every question","B. Provide privacy, respect, and honesty, considering some interview time apart from caregivers","C. Speak only to the caregiver, not the patient","D. Use the same approach as with a toddler"],"correct":1,"rationale":"Adolescents value privacy, respect, and direct honesty, and may disclose more accurately when interviewed partly apart from caregivers.","difficulty":"Easy"},{"id":"c01_q09","question":"Why is a single 'normal vital signs' reference not useful in pediatrics?","options":["A. Vital signs don't matter in children","B. Normal heart rate, respiratory rate, and blood pressure vary substantially across pediatric age bands","C. Pediatric vital signs cannot be measured in the field","D. All children have identical vital signs regardless of age"],"correct":1,"rationale":"Because normal ranges shift significantly from neonate through adolescent, every vital sign must be compared against an age-appropriate reference range.","difficulty":"Easy"},{"id":"c01_q10","question":"What matters more than a single isolated vital sign reading in pediatric assessment?","options":["A. The exact numeric value alone","B. Trends over time and the overall clinical picture (e.g., the Pediatric Assessment Triangle)","C. Only the respiratory rate","D. The child's stated pain level alone"],"correct":1,"rationale":"A single vital sign can be misleading in isolation; trends and the broader clinical gestalt provide more reliable information about the child's true status.","difficulty":"Medium"},{"id":"c01_q11","question":"Why does a modest-seeming blood loss matter more in a child than in an adult?","options":["A. Children have larger total blood volumes","B. A child's absolute circulating blood volume is small, so the same loss is a larger percentage of total volume","C. Children's blood clots more slowly","D. This is not actually true — losses are equivalent"],"correct":1,"rationale":"Because total circulating volume is smaller in children, an amount of blood loss that would be minor in an adult can represent a much larger fraction of a child's total volume.","difficulty":"Medium"},{"id":"c01_q12","question":"How does the pediatric larynx position differ anatomically from an adult's?","options":["A. More posterior and lower","B. More anterior and cephalad (higher)","C. Identical position","D. Absent in infants"],"correct":1,"rationale":"The pediatric larynx sits more anterior and cephalad than the adult larynx, an important consideration for airway positioning and visualization.","difficulty":"Medium"},{"id":"c01_q13","question":"Why are infants at particular risk of fatigue during increased work of breathing?","options":["A. They have highly rigid chest walls","B. They are diaphragmatic breathers with a compliant chest wall, generating less effective negative pressure and fatiguing faster","C. Infants never show signs of respiratory distress","D. Infant lungs have unusually large reserve capacity"],"correct":1,"rationale":"The compliant infant chest wall and diaphragm-dependent breathing generate less effective ventilatory force, so infants tire more quickly when working hard to breathe.","difficulty":"Hard"},{"id":"c01_q14","question":"A provider uses an adult mental model unmodified when assessing an infant's airway. What is the risk?","options":["A. No risk — pediatric and adult airways are identical","B. Missing anatomic differences (large tongue, anterior/cephalad larynx, subglottic narrowing) that change positioning and equipment needs","C. Improved outcomes from consistency","D. The risk only applies to children over age 10"],"correct":1,"rationale":"Anatomic differences unique to the pediatric airway change how it should be assessed and managed; applying an unmodified adult model risks missing or mismanaging obstruction.","difficulty":"Hard"}]},"c02":{"chapter":"c02","questions":[{"id":"c02_q01","question":"What are the three legs of the Pediatric Assessment Triangle?","options":["A. Airway, Breathing, Circulation","B. Appearance, Work of Breathing, Circulation to Skin","C. History, Exam, Vital Signs","D. Tone, Color, Cry"],"correct":1,"rationale":"The PAT's three legs are Appearance, Work of Breathing, and Circulation to Skin — assessed together from across the room before any hands-on contact.","difficulty":"Easy"},{"id":"c02_q02","question":"What does the TICLS mnemonic help assess?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance","D. Vital signs"],"correct":2,"rationale":"TICLS (Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry) breaks down the Appearance leg of the PAT into observable components.","difficulty":"Easy"},{"id":"c02_q03","question":"A child is limp, will not make eye contact, and is inconsolable, but breathing appears effortless and skin color is normal. What does this pattern suggest?","options":["A. A respiratory problem","B. A primarily CNS/metabolic problem","C. A shock/circulatory problem","D. Cardiopulmonary failure"],"correct":1,"rationale":"Abnormal Appearance alone, with normal Work of Breathing and Circulation, points toward a CNS/metabolic category rather than a respiratory or circulatory problem.","difficulty":"Medium"},{"id":"c02_q04","question":"A child has abnormal Appearance (lethargic) AND visible retractions with nasal flaring, but normal skin color. What is the likely category?","options":["A. CNS/metabolic problem","B. Respiratory problem","C. Shock","D. Cardiopulmonary failure"],"correct":1,"rationale":"Abnormal Appearance combined with abnormal Work of Breathing (retractions, flaring), with normal circulation, points to a respiratory category.","difficulty":"Medium"},{"id":"c02_q05","question":"A child is lethargic and has mottled, cool skin, but breathing appears unlabored with no retractions. What is the likely category?","options":["A. Respiratory problem","B. Shock/circulatory problem","C. Normal finding","D. Isolated CNS problem only"],"correct":1,"rationale":"Abnormal Appearance plus abnormal Circulation to Skin, with normal Work of Breathing, suggests a shock/circulatory category.","difficulty":"Medium"},{"id":"c02_q06","question":"A child shows abnormal findings across ALL three PAT legs. What does this represent?","options":["A. A mild, self-limited illness","B. Cardiopulmonary failure — the highest-urgency category","C. Normal variation","D. An isolated skin condition"],"correct":1,"rationale":"Abnormality across all three legs indicates a severe, multi-system problem — cardiopulmonary failure — requiring the most urgent response.","difficulty":"Medium"},{"id":"c02_q07","question":"Is the PAT performed with a stethoscope or blood pressure cuff?","options":["A. Yes, both are required","B. No — it is entirely hands-off, visual and auditory, from across the room","C. Only a stethoscope is used","D. Only a BP cuff is used"],"correct":1,"rationale":"The PAT is deliberately hands-off, performed by observation and listening from a distance before any equipment or touching begins.","difficulty":"Easy"},{"id":"c02_q08","question":"A child looks well on the PAT. What should the provider do next?","options":["A. Skip the primary assessment since the PAT was reassuring","B. Proceed to a full hands-on primary assessment at a calmer pace","C. Discharge the patient immediately","D. Only check vital signs, skip any exam"],"correct":1,"rationale":"The PAT never replaces the hands-on primary assessment — a reassuring PAT sets a calmer pace, but the full ABCDE assessment still follows.","difficulty":"Easy"},{"id":"c02_q09","question":"Why is Work of Breathing considered an 'early window' into respiratory status?","options":["A. It only becomes abnormal after the child has already desaturated","B. Increased effort reflects compensation and can appear before oxygen saturation falls","C. It has no relationship to oxygenation","D. It is only useful in adults"],"correct":1,"rationale":"Increased work of breathing is a compensatory response that often precedes a measurable drop in SpO2, making it an early indicator of respiratory compromise.","difficulty":"Medium"},{"id":"c02_q10","question":"Which finding is part of the Circulation to Skin leg of the PAT?","options":["A. Retractions","B. Nasal flaring","C. Mottling","D. Stridor"],"correct":2,"rationale":"Mottling is a skin-color finding assessed under Circulation to Skin; retractions, flaring, and stridor belong to the Work of Breathing leg.","difficulty":"Easy"},{"id":"c02_q11","question":"Why is Appearance considered the most sensitive PAT leg?","options":["A. It is the easiest to measure with equipment","B. It reflects the adequacy of oxygenation, ventilation, brain perfusion, and CNS function all at once","C. It is only relevant in trauma","D. It replaces the need for the other two legs"],"correct":1,"rationale":"Appearance integrates multiple physiologic systems, making it a highly sensitive early indicator — an abnormal Appearance is a red flag even if the other two legs look normal.","difficulty":"Medium"},{"id":"c02_q12","question":"What is meant by assessing the PAT 'from the doorway'?","options":["A. Only assessing patients who are near an actual doorway","B. The PAT is completed within the first seconds of encountering the child, before approaching or touching them","C. The PAT requires the child to be standing in a doorway","D. This phrase has no specific meaning in PEPP"],"correct":1,"rationale":"The 'from the doorway' framing captures how quickly and unobtrusively the PAT is performed — a rapid visual/auditory read taken immediately upon encountering the child.","difficulty":"Medium"},{"id":"c02_q13","question":"A muffled, weak cry in an infant is a finding under which PAT leg?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance (Speech/Cry component of TICLS)","D. None of the legs"],"correct":2,"rationale":"Speech/Cry is one of the five TICLS components under the Appearance leg; a weak or muffled cry is an abnormal Appearance finding.","difficulty":"Medium"},{"id":"c02_q14","question":"Why does the PAT drive 'the pace of everything that follows' rather than the content of care?","options":["A. It determines drug doses directly","B. It sets the general impression and urgency level, shaping how quickly the primary assessment proceeds and whether interventions happen simultaneously","C. It has no influence on subsequent care","D. It replaces vital sign measurement entirely"],"correct":1,"rationale":"The PAT's purpose is to establish urgency and likely category quickly, which shapes the speed and sequencing of the ensuing primary assessment and interventions — not to dictate specific treatments by itself.","difficulty":"Hard"},{"id":"c02_q15","question":"Which combination of PAT findings would most strongly suggest the HIGHEST acuity requiring the most urgent response?","options":["A. Normal Appearance, normal Work of Breathing, normal Circulation","B. Abnormal Appearance, Work of Breathing, AND Circulation to Skin all together","C. Mild nasal flaring only, otherwise normal","D. Slightly pale skin with normal Appearance and breathing"],"correct":1,"rationale":"Abnormalities across all three PAT legs together represent the cardiopulmonary failure category, the highest-urgency PAT pattern.","difficulty":"Medium"},{"id":"c02_q16","question":"How should skin color findings under Circulation to Skin be interpreted?","options":["A. Against a universal standard regardless of the individual child","B. Against the child's own baseline skin tone, in adequate lighting","C. Only cyanosis matters; pallor and mottling are irrelevant","D. Skin color cannot be reliably assessed in the field"],"correct":1,"rationale":"Skin findings are compared to the individual child's baseline tone under good lighting, since a fixed universal standard would not account for normal variation between children.","difficulty":"Medium"}]},"c03":{"chapter":"c03","questions":[{"id":"c03_q01","question":"What does the pediatric primary assessment sequence ABCDE stand for?","options":["A. Appearance, Breathing, Color, Development, Exam","B. Airway, Breathing, Circulation, Disability, Exposure","C. Assessment, Baseline, Care, Documentation, Evaluation","D. Alertness, Body, Chest, Digits, Extremities"],"correct":1,"rationale":"The pediatric primary assessment follows the ABCDE sequence: Airway, Breathing, Circulation, Disability, Exposure — the same spine used across PALS and PEPP.","difficulty":"Easy"},{"id":"c03_q02","question":"During the primary assessment, you find an obstructed airway while assessing 'A'. What should you do?","options":["A. Note it and continue through B, C, D, E first","B. Treat the airway obstruction immediately before proceeding","C. Wait until the secondary assessment to address it","D. Only address it if breathing is also abnormal"],"correct":1,"rationale":"Life threats found at any step of ABCDE are treated immediately, not deferred until the full sequence is complete.","difficulty":"Easy"},{"id":"c03_q03","question":"What is assessed under the 'Disability' step of pediatric ABCDE?","options":["A. Skin color only","B. Rapid neurologic status (e.g., AVPU), pupils, and glucose if altered","C. Chest wall retractions","D. External hemorrhage"],"correct":1,"rationale":"Disability covers a rapid neurologic check, pupillary assessment, and blood glucose measurement when mental status is altered.","difficulty":"Easy"},{"id":"c03_q04","question":"What is the primary assessment's main deliverable?","options":["A. A specific final diagnosis","B. An overall priority decision (high vs. low acuity)","C. A completed transport report","D. A medication administration record"],"correct":1,"rationale":"The primary assessment concludes with a priority determination that drives the pace of subsequent care, rather than a definitive diagnosis.","difficulty":"Medium"},{"id":"c03_q05","question":"How does a high-acuity PAT (e.g., cardiopulmonary failure pattern) change how the primary assessment proceeds?","options":["A. It has no effect on the primary assessment","B. The primary assessment proceeds immediately and rapidly, often with simultaneous interventions","C. The primary assessment is skipped entirely","D. Only the Exposure step is performed"],"correct":1,"rationale":"A high-acuity PAT sets urgency, prompting rapid primary assessment with interventions occurring simultaneously rather than in strict sequence.","difficulty":"Medium"},{"id":"c03_q06","question":"Which additional considerations are part of pediatric scene size-up beyond standard safety and precautions?","options":["A. Only the child's exact age in months","B. Mechanism/nature of illness, patient count, and environmental clues","C. Only the caregiver's insurance information","D. Nothing additional beyond adult scene size-up"],"correct":1,"rationale":"Pediatric scene size-up adds attention to mechanism/nature of illness, potential multiple patients, and environmental clues (medications, hazards, caregiver affect).","difficulty":"Medium"},{"id":"c03_q07","question":"A reassuring PAT is obtained. Should the primary assessment still be performed?","options":["A. No, it can be skipped","B. Yes — the PAT sets pace, it does not replace the hands-on ABCDE exam","C. Only if the caregiver requests it","D. Only for children under 1 year old"],"correct":1,"rationale":"The PAT never substitutes for the primary assessment; a reassuring PAT simply allows the exam to proceed at a calmer pace.","difficulty":"Easy"},{"id":"c03_q08","question":"What is assessed under 'Circulation' in pediatric ABCDE?","options":["A. Pupil size only","B. Pulse rate/quality, skin perfusion, capillary refill, and external bleeding","C. Respiratory rate","D. Level of consciousness"],"correct":1,"rationale":"Circulation assessment covers pulse characteristics, perfusion indicators like capillary refill and skin, and control of external hemorrhage.","difficulty":"Easy"},{"id":"c03_q09","question":"Where should a provider look for cardiac-arrest-specific ABCDE depth beyond field recognition?","options":["A. The PEPP reviewer alone covers this fully","B. The PALS reviewer","C. The BDLS reviewer","D. No resource covers this"],"correct":1,"rationale":"PEPP frames ABCDE as a field assessment/transport-decision tool; resuscitation-team algorithm depth is intentionally deferred to the PALS reviewer to avoid duplicating or contradicting it.","difficulty":"Medium"},{"id":"c03_q10","question":"What should happen to the priority decision as new findings emerge during the encounter?","options":["A. It should never change once set","B. It should be reassessed and updated as new information becomes available","C. Priority is only assigned at the very end of the call","D. Priority does not affect subsequent care"],"correct":1,"rationale":"Priority is not a one-time determination; it should be reassessed as the exam, treatment, and reassessment reveal new findings.","difficulty":"Medium"},{"id":"c03_q11","question":"What is assessed under the 'Exposure' step of ABCDE?","options":["A. Blood glucose","B. Undressing as needed to check for injury/rash, then keeping the child warm","C. Airway patency","D. Pupil reactivity"],"correct":1,"rationale":"Exposure involves assessing the body for injury or rash by undressing as clinically indicated, followed by re-covering the child to prevent heat loss.","difficulty":"Easy"},{"id":"c03_q12","question":"A child has abnormal breath sounds found during the 'B' step. What is the correct action?","options":["A. Continue to 'C' and address breathing at the end","B. Address the breathing problem immediately before continuing","C. Only address it during the secondary assessment","D. Ignore it if the PAT appeared reassuring"],"correct":1,"rationale":"Any abnormal or life-threatening finding at a given ABCDE step is treated immediately rather than deferred, regardless of the preceding PAT impression.","difficulty":"Medium"},{"id":"c03_q13","question":"Why is patient count an important scene size-up consideration in pediatric calls specifically?","options":["A. Children are never involved in multi-victim events","B. Children are frequently involved in multi-victim events (e.g., car crashes, household incidents)","C. Only adult patient counts matter for resource allocation","D. This consideration is unique to adult scenes"],"correct":1,"rationale":"Pediatric events often involve multiple patients (e.g., siblings in a car crash), making early patient-count assessment operationally important.","difficulty":"Medium"},{"id":"c03_q14","question":"Which best describes the relationship between the PAT and primary assessment as a two-step process?","options":["A. They are identical and redundant","B. The PAT is hands-off and sets urgency/pace; the primary assessment is the hands-on ABCDE exam that follows and is never skipped","C. The primary assessment always comes first","D. Only one of the two is ever performed per patient"],"correct":1,"rationale":"The PAT and primary assessment are sequential, complementary steps — the PAT's hands-off impression sets the tone, and the hands-on ABCDE exam always follows.","difficulty":"Hard"}]},"c04":{"chapter":"c04","questions":[{"id":"c04_q01","question":"What does the SAMPLE history mnemonic stand for?","options":["A. Signs/Symptoms, Allergies, Medications, Past history, Last intake, Events","B. Scene, Assessment, Monitoring, Priority, Location, Evaluation","C. Safety, Airway, Motion, Perfusion, Life threats, Exposure","D. Support, Attitude, Medication, Prognosis, Location, Escalation"],"correct":0,"rationale":"SAMPLE stands for Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, and Events leading up to the incident.","difficulty":"Easy"},{"id":"c04_q02","question":"What pediatric-specific elements are added to the standard SAMPLE history?","options":["A. Employment history","B. Birth history/developmental milestones, immunization status, and growth/weight trends","C. Credit history","D. Nothing is added for children"],"correct":1,"rationale":"Pediatric SAMPLE histories add emphasis on birth/developmental history for infants, immunization status, and growth/weight trends relevant to medication dosing.","difficulty":"Medium"},{"id":"c04_q03","question":"Who should be asked directly about their symptoms whenever possible?","options":["A. Only caregivers, never the child","B. School-age children and adolescents, with caregiver accounts supplementing rather than replacing their report","C. Only infants","D. No one should be asked directly; observation alone suffices"],"correct":1,"rationale":"Older children and adolescents can usually provide reliable direct history, and their own report should be sought and supplemented (not replaced) by caregiver information.","difficulty":"Medium"},{"id":"c04_q04","question":"Which exam order is preferred for a frightened toddler?","options":["A. Head-to-toe","B. Toe-to-head","C. Random order","D. Only auscultation, no other exam"],"correct":1,"rationale":"Starting with less threatening body areas (toe-to-head) improves cooperation in young, frightened children compared to the standard head-to-toe order.","difficulty":"Easy"},{"id":"c04_q05","question":"Which exam order is typically appropriate for a cooperative school-age child or adolescent?","options":["A. Toe-to-head only","B. Standard head-to-toe sequence","C. No physical exam is needed","D. Only exam areas the child requests"],"correct":1,"rationale":"Older, more cooperative children can typically tolerate the standard head-to-toe exam sequence used in adult care.","difficulty":"Easy"},{"id":"c04_q06","question":"What is family-centered care?","options":["A. Excluding caregivers from all pediatric encounters","B. Treating the caregiver as a partner in the child's care, including presence during many procedures","C. Allowing caregivers to make all treatment decisions without provider input","D. A billing category unrelated to clinical practice"],"correct":1,"rationale":"Family-centered care partners with caregivers rather than excluding them, recognizing their presence typically benefits the child without meaningfully slowing care.","difficulty":"Easy"},{"id":"c04_q07","question":"Does allowing a caregiver to remain present during care typically slow things down?","options":["A. Yes, significantly","B. No — it usually reduces distress and improves cooperation without meaningfully slowing care","C. Only for infants","D. Only during transport, never during assessment"],"correct":1,"rationale":"Family-centered care research and practice support that caregiver presence generally improves the encounter without materially delaying care.","difficulty":"Medium"},{"id":"c04_q08","question":"A family does not speak English. What is the correct approach to communication?","options":["A. Have the child interpret for their caregiver","B. Use professional interpretation services","C. Speak louder in English","D. Skip history-taking entirely"],"correct":1,"rationale":"Relying on a child to interpret medical information places an inappropriate burden on them and risks inaccurate communication; professional interpretation services are the correct approach.","difficulty":"Easy"},{"id":"c04_q09","question":"How should a provider approach a child with autism spectrum differences?","options":["A. Use the identical approach for every patient regardless of the caregiver's input","B. Take cues from the caregiver about the child's usual communication style, minimize sensory overload, and allow extra time","C. Speak only to the caregiver and ignore the child entirely","D. Rush the exam to minimize contact time"],"correct":1,"rationale":"Individualized communication guided by the caregiver, reduced sensory overload, and allowing extra time improve the encounter for children with developmental differences.","difficulty":"Medium"},{"id":"c04_q10","question":"What is the difference between the focused exam and the rapid exam in secondary assessment?","options":["A. They are identical","B. The focused exam targets the chief complaint for stable/low-priority patients; the rapid exam is more limited, for high-priority patients often performed en route","C. The rapid exam is only for infants","D. The focused exam is only used in the hospital"],"correct":1,"rationale":"The secondary assessment adapts to patient priority: a focused exam for stable patients on scene, versus a rapid, more limited exam for high-priority patients, often continued during transport.","difficulty":"Medium"},{"id":"c04_q11","question":"How should a provider communicate with a hearing-impaired caregiver?","options":["A. Speak as loudly as possible from across the room","B. Face them directly, speak clearly, and use written notes or interpreter services as needed","C. Avoid direct communication entirely","D. Only communicate through the child"],"correct":1,"rationale":"Facing the person directly and speaking clearly (not necessarily loudly), supplemented by written notes or interpreter services, is the appropriate communication approach.","difficulty":"Medium"},{"id":"c04_q12","question":"What four steps make up PEPP's complete pediatric assessment sequence?","options":["A. History, exam, transport, documentation","B. PAT, primary assessment, history, secondary assessment","C. Scene safety, vitals, treatment, discharge","D. Appearance, breathing, circulation, disability"],"correct":1,"rationale":"The full PEPP sequence is: Pediatric Assessment Triangle, primary assessment (ABCDE), history-taking, and secondary assessment — each building on the last.","difficulty":"Medium"},{"id":"c04_q13","question":"Why is growth/weight trend information part of a thorough pediatric SAMPLE history?","options":["A. It is irrelevant to prehospital care","B. It informs weight-based medication dosing considerations","C. It is only used for insurance billing","D. It replaces the need for a chief complaint"],"correct":1,"rationale":"Weight/growth information is directly relevant to weight-based dosing considerations that may apply during subsequent care.","difficulty":"Medium"},{"id":"c04_q14","question":"Why is adapting communication for special needs considered a clinical skill rather than an optional courtesy?","options":["A. It has no effect on care quality","B. It materially affects the quality and accuracy of the history and exam obtained","C. It is only relevant for documentation purposes","D. It is required only by hospital policy, not clinical necessity"],"correct":1,"rationale":"Communication adaptation directly impacts how much accurate, useful clinical information a provider can gather — making it a core clinical skill, not a courtesy.","difficulty":"Hard"}]},"c05":{"chapter":"c05","questions":[{"id":"c05_q01","question":"What best distinguishes respiratory distress from respiratory failure?","options":["A. Distress means compensating with adequate oxygenation/mentation; failure means compensation has failed","B. Distress always requires intubation; failure never does","C. Distress only occurs in infants; failure only in adolescents","D. There is no clinical difference"],"correct":0,"rationale":"Respiratory distress is a compensated state (increased work of breathing but adequate oxygenation/mentation); respiratory failure is a decompensated state where oxygenation/ventilation is now inadequate.","difficulty":"Easy"},{"id":"c05_q02","question":"Which finding is classic for upper airway obstruction?","options":["A. Wheezing","B. Stridor","C. Crackles","D. Irregular rate with no abnormal sound"],"correct":1,"rationale":"Upper airway obstruction (e.g., croup, foreign body, epiglottitis) classically produces stridor.","difficulty":"Easy"},{"id":"c05_q03","question":"Which finding is classic for lower airway disease?","options":["A. Stridor","B. Wheezing with prolonged expiration","C. Grunting","D. Lethargy alone"],"correct":1,"rationale":"Lower airway disease (e.g., asthma, bronchiolitis) classically produces wheezing with prolonged expiration.","difficulty":"Easy"},{"id":"c05_q04","question":"Which findings are classic for lung tissue (parenchymal) disease?","options":["A. Stridor and barking cough","B. Wheezing only","C. Grunting, crackles, and diminished breath sounds","D. No abnormal sounds at all"],"correct":2,"rationale":"Parenchymal disease (e.g., pneumonia, pulmonary edema) classically produces grunting, crackles, and diminished breath sounds.","difficulty":"Medium"},{"id":"c05_q05","question":"What characterizes disordered control of breathing?","options":["A. Stridor with barking cough","B. Wheezing with prolonged expiration","C. An irregular rate/pattern without the classic sounds of the other three categories","D. Grunting and crackles"],"correct":2,"rationale":"Disordered control of breathing (from a CNS problem, toxin, or neuromuscular disease) causes an irregular rate/pattern without the classic sounds seen in the other three categories.","difficulty":"Medium"},{"id":"c05_q06","question":"A child who was struggling hard to breathe now appears to have less work of breathing. What should this prompt?","options":["A. Immediate reassurance that the child is improving","B. Suspicion of exhaustion/impending failure rather than automatic reassurance","C. Discharge from EMS care","D. No further assessment is needed"],"correct":1,"rationale":"Decreasing work of breathing in a previously struggling child can reflect exhaustion rather than improvement — a dangerous, easily misread sign requiring close reassessment.","difficulty":"Hard"},{"id":"c05_q07","question":"Which PAT change suggests impending respiratory failure?","options":["A. Appearance shifting from anxious/agitated to lethargic","B. Appearance shifting from lethargic to anxious","C. Improved skin color","D. No PAT change is relevant"],"correct":0,"rationale":"A shift in Appearance from anxious/agitated to lethargic on repeat PAT is a warning sign of impending respiratory failure.","difficulty":"Medium"},{"id":"c05_q08","question":"Should a provider wait for SpO2 to drop before escalating respiratory support?","options":["A. Yes, SpO2 is the only reliable indicator","B. No — other findings often precede a measurable SpO2 drop and should prompt earlier escalation","C. Only in infants","D. Only during interfacility transport"],"correct":1,"rationale":"Grunting, decreasing WOB after struggling, and PAT Appearance changes often precede a measurable drop in SpO2 and should prompt escalation before saturation falls.","difficulty":"Medium"},{"id":"c05_q09","question":"What is appropriate field management for respiratory distress (not failure)?","options":["A. Immediate bag-mask ventilation for all patients","B. Positioning of comfort, supplemental oxygen, and category-targeted treatment with close monitoring","C. No treatment until arrival at the hospital","D. Immediate advanced airway placement"],"correct":1,"rationale":"Distress is managed with positioning of comfort, oxygen, and treatment targeted to the likely category, with close monitoring for transition to failure.","difficulty":"Easy"},{"id":"c05_q10","question":"What is appropriate field management for respiratory failure?","options":["A. Positioning of comfort and observation only","B. Assisted ventilation (BVM with high-flow oxygen) and rapid transport","C. Withholding oxygen until intubation","D. Discharge at scene"],"correct":1,"rationale":"Respiratory failure requires assisted ventilation with high-flow oxygen and rapid transport; PEPP frames deeper airway/arrest management as PALS-reviewer content.","difficulty":"Easy"},{"id":"c05_q11","question":"Where does PEPP direct providers for drug-assisted airway management and arrest-specific ventilation parameters?","options":["A. The BLS reviewer","B. The PALS reviewer","C. This is fully covered in PEPP itself","D. No resource is referenced"],"correct":1,"rationale":"PEPP frames respiratory failure management as field recognition and initial stabilization, deferring drug-assisted airway management and arrest-specific ventilation depth to the PALS reviewer.","difficulty":"Medium"},{"id":"c05_q12","question":"Why are respiratory problems especially significant in pediatric prehospital care?","options":["A. They are the leading pathway to pediatric cardiac arrest","B. They never progress to failure in children","C. They are less common in children than adults","D. They have no relationship to cardiac arrest in children"],"correct":0,"rationale":"Unlike adults, where a primary cardiac event is more common, respiratory problems are the leading pathway to pediatric cardiac arrest, making early recognition high-yield.","difficulty":"Medium"},{"id":"c05_q13","question":"Why is categorizing a respiratory problem by mechanism (upper airway, lower airway, tissue, control) clinically useful?","options":["A. It has no treatment implications","B. It guides both expected exam findings and which field treatment is appropriate","C. It only matters for documentation","D. It replaces the need for a primary assessment"],"correct":1,"rationale":"Categorizing by mechanism helps providers anticipate exam findings and select the appropriate targeted treatment (e.g., bronchodilator for lower airway disease).","difficulty":"Medium"},{"id":"c05_q14","question":"A toddler has stridor and a barking cough. Which category of respiratory compromise is most likely?","options":["A. Lower airway disease","B. Upper airway obstruction","C. Lung tissue disease","D. Disordered control of breathing"],"correct":1,"rationale":"Stridor with a barking cough is classic for upper airway obstruction, such as croup.","difficulty":"Easy"},{"id":"c05_q15","question":"An infant has an irregular breathing pattern with no wheeze, stridor, grunting, or crackles, following a suspected toxic ingestion. Which category fits best?","options":["A. Upper airway obstruction","B. Lower airway disease","C. Lung tissue disease","D. Disordered control of breathing"],"correct":3,"rationale":"An irregular rate/pattern without classic sounds, especially with a toxin as the suspected cause, fits disordered control of breathing.","difficulty":"Hard"}]},"c06":{"chapter":"c06","questions":[{"id":"c06_q01","question":"How is shock best defined?","options":["A. Systolic blood pressure below a fixed threshold","B. Inadequate delivery of oxygen and nutrients to meet tissue demands","C. Any heart rate above normal for age","D. A specific respiratory rate cutoff"],"correct":1,"rationale":"Shock is a clinical diagnosis based on inadequate tissue perfusion, not a specific blood pressure value.","difficulty":"Easy"},{"id":"c06_q02","question":"Why can a child be in shock despite a normal blood pressure?","options":["A. Children cannot develop shock","B. Children compensate well via tachycardia and vasoconstriction, keeping BP normal until late","C. Blood pressure is not a useful vital sign in children","D. Normal BP always excludes shock"],"correct":1,"rationale":"Pediatric compensatory mechanisms (tachycardia, vasoconstriction) maintain blood pressure well into shock — this is compensated shock.","difficulty":"Medium"},{"id":"c06_q03","question":"What does hypotension indicate in a child with suspected shock?","options":["A. An early warning sign that appears well before other findings","B. Decompensated shock — a late, ominous sign","C. That the child is not in shock","D. A benign finding requiring no action"],"correct":1,"rationale":"Hypotension in pediatric shock is a late finding, indicating exhausted compensatory mechanisms — decompensated shock.","difficulty":"Medium"},{"id":"c06_q04","question":"Which finding is part of recognizing compensated shock?","options":["A. Delayed capillary refill with normal BP","B. Hypotension with bradycardia","C. Normal capillary refill and normal heart rate","D. Hypertension"],"correct":0,"rationale":"Compensated shock presents with perfusion abnormalities like delayed capillary refill while blood pressure remains normal for age.","difficulty":"Easy"},{"id":"c06_q05","question":"Which shock category is most common in children overall?","options":["A. Cardiogenic","B. Hypovolemic","C. Obstructive","D. Neurogenic"],"correct":1,"rationale":"Hypovolemic shock, from fluid or blood loss, is the most common category of pediatric shock overall.","difficulty":"Easy"},{"id":"c06_q06","question":"Which of the following is a type of distributive shock?","options":["A. Hemorrhagic shock","B. Septic shock","C. Tension pneumothorax","D. Myocarditis-related shock"],"correct":1,"rationale":"Septic shock, along with anaphylactic and neurogenic shock, falls under the distributive category (abnormal vessel tone/permeability).","difficulty":"Medium"},{"id":"c06_q07","question":"What causes cardiogenic shock in children?","options":["A. Fluid loss from vomiting/diarrhea","B. Pump failure from congenital heart disease, myocarditis, or arrhythmia","C. Allergen exposure","D. Tension pneumothorax"],"correct":1,"rationale":"Cardiogenic shock results from the heart's failure to pump effectively, due to causes like congenital heart disease, myocarditis, or arrhythmia.","difficulty":"Medium"},{"id":"c06_q08","question":"Which shock category is caused by a physical obstruction to blood flow?","options":["A. Hypovolemic","B. Distributive","C. Obstructive","D. Cardiogenic"],"correct":2,"rationale":"Obstructive shock results from a physical blockage to blood flow, such as tension pneumothorax, cardiac tamponade, or massive pulmonary embolism.","difficulty":"Medium"},{"id":"c06_q09","question":"A febrile child has warm, flushed skin, bounding pulses, and altered mental status. What should this suggest?","options":["A. This cannot be shock since the skin is warm","B. Early septic (distributive) shock, which can present differently from cold, mottled hypovolemic shock","C. Definite hypovolemic shock","D. Normal findings requiring no action"],"correct":1,"rationale":"Early septic shock can present with warm, flushed skin and bounding pulses rather than the cold, mottled presentation typical of hypovolemic shock, despite poor perfusion.","difficulty":"Hard"},{"id":"c06_q10","question":"What PAT findings are most suggestive of shock?","options":["A. Abnormal work of breathing only","B. Abnormal Appearance and/or abnormal Circulation to Skin, often with normal-appearing work of breathing","C. Stridor and wheeze","D. Normal Appearance and normal Circulation to Skin"],"correct":1,"rationale":"Shock often first appears on the PAT as an Appearance abnormality and/or abnormal Circulation to Skin, frequently with normal-appearing work of breathing (distinguishing it from a primary respiratory problem).","difficulty":"Medium"},{"id":"c06_q11","question":"What is the priority field treatment for suspected anaphylactic shock?","options":["A. Isotonic fluid bolus only","B. Epinephrine","C. Needle decompression","D. Oral antihistamine only"],"correct":1,"rationale":"Epinephrine is the priority treatment for anaphylactic shock; fluids and other supportive measures are adjuncts.","difficulty":"Easy"},{"id":"c06_q12","question":"A trauma patient has unilateral absent breath sounds, tracheal deviation, and signs of shock. What is the suspected category and priority intervention?","options":["A. Hypovolemic shock — fluid bolus","B. Obstructive shock from tension pneumothorax — needle decompression per protocol","C. Cardiogenic shock — cautious fluids","D. Anaphylactic shock — epinephrine"],"correct":1,"rationale":"Unilateral absent breath sounds and tracheal deviation in a trauma patient with shock suggest tension pneumothorax (obstructive shock), requiring needle decompression per protocol.","difficulty":"Hard"},{"id":"c06_q13","question":"What is the general supportive field management for a child in shock, regardless of category?","options":["A. Withhold oxygen until cause is confirmed","B. Supplemental oxygen, positioning, keep warm, and rapid transport","C. Cooling measures and fluid restriction","D. No supportive care is needed before hospital arrival"],"correct":1,"rationale":"General shock management includes supplemental oxygen, positioning (supine, legs elevated if tolerated), keeping the child warm, and rapid transport.","difficulty":"Easy"},{"id":"c06_q14","question":"Where does PEPP direct providers for drug dosing and advanced shock/arrest resuscitation algorithms?","options":["A. The BLS reviewer","B. The PALS reviewer","C. This chapter covers it fully","D. No resource is referenced"],"correct":1,"rationale":"PEPP covers field recognition and initial stabilization of shock, deferring drug dosing tables and advanced resuscitation algorithms to the PALS reviewer.","difficulty":"Medium"},{"id":"c06_q15","question":"Why does PEPP emphasize perfusion signs over blood pressure for recognizing shock?","options":["A. Blood pressure cuffs are unreliable in children","B. Perfusion signs (capillary refill, skin findings, pulse quality, mental status) change earlier than blood pressure in pediatric shock","C. Blood pressure is more important than perfusion signs","D. Perfusion signs are only relevant in adults"],"correct":1,"rationale":"Because children compensate so effectively, perfusion signs deteriorate well before blood pressure falls, making them the earlier and more reliable indicators of shock.","difficulty":"Hard"}]},"c07":{"chapter":"c07","questions":[{"id":"c07_q01","question":"How common are primary cardiac events as a cause of pediatric emergencies compared to adults?","options":["A. Equally common","B. More common in children","C. Rare in children compared to adults","D. Primary cardiac events never occur in children"],"correct":2,"rationale":"Unlike adults, where primary cardiac events are a common cause of collapse, primary cardiac disease is a rare cause of pediatric emergencies; most pediatric cardiac problems are secondary.","difficulty":"Easy"},{"id":"c07_q02","question":"What is the most common cause of pediatric bradycardia?","options":["A. Primary conduction system disease","B. Hypoxia","C. Electrolyte imbalance","D. Medication overdose"],"correct":1,"rationale":"Hypoxia is the most common cause of pediatric bradycardia encountered in the field.","difficulty":"Easy"},{"id":"c07_q03","question":"What is the correct field priority for a symptomatic bradycardic infant?","options":["A. Treat the rhythm number directly without addressing breathing","B. Oxygenate and ventilate first, addressing the underlying cause","C. Wait for a 12-lead ECG before any intervention","D. Apply ice to the chest"],"correct":1,"rationale":"Because pediatric bradycardia is usually caused by hypoxia, the priority is oxygenation and ventilation to treat the underlying cause, not treating the rhythm number alone.","difficulty":"Medium"},{"id":"c07_q04","question":"Besides hypoxia, what other factors can cause pediatric bradycardia?","options":["A. Increased vagal tone, hypothermia, increased ICP","B. Dehydration alone","C. Fever alone","D. Anxiety alone"],"correct":0,"rationale":"Increased vagal tone, hypothermia, and increased intracranial pressure are other recognized causes of pediatric bradycardia, in addition to hypoxia.","difficulty":"Medium"},{"id":"c07_q05","question":"How does sinus tachycardia typically present?","options":["A. A fixed, very rapid rate with no clear trigger","B. A variable rate with a clear trigger (fever, pain, anxiety, dehydration, shock) that resolves as the cause is treated","C. Always slower than 150 bpm","D. Only seen in adolescents"],"correct":1,"rationale":"Sinus tachycardia is a compensatory response with a variable rate tied to an identifiable trigger, resolving as that trigger is treated.","difficulty":"Easy"},{"id":"c07_q06","question":"How does SVT typically present, in contrast to sinus tachycardia?","options":["A. A fixed, very rapid rate that does not vary with stimulation","B. A slow, variable rate","C. Identical to sinus tachycardia in every way","D. Only occurs during exercise"],"correct":0,"rationale":"SVT is a primary rhythm disturbance with a fixed, very rapid rate that does not vary with stimulation, distinguishing it from sinus tachycardia.","difficulty":"Medium"},{"id":"c07_q07","question":"An infant has a heart rate fixed at 240 bpm that does not change with stimulation and no clear triggering illness. What should this suggest?","options":["A. Sinus tachycardia from fever","B. Supraventricular tachycardia (SVT)","C. Normal infant heart rate","D. Bradycardia"],"correct":1,"rationale":"A fixed, very rapid rate (often >220 bpm in infants) that does not vary with stimulation and lacks a clear trigger is characteristic of SVT.","difficulty":"Hard"},{"id":"c07_q08","question":"Why should a provider ask about a child's known congenital heart disease?","options":["A. It is not clinically relevant in the field","B. The child may have a baseline vital signs/SpO2 that differs from typical norms, and is at elevated risk for arrhythmia, heart failure, and cardiogenic shock","C. It only matters for billing purposes","D. Congenital heart disease patients never develop arrhythmias"],"correct":1,"rationale":"Children with congenital heart disease may have different baseline vitals/oxygen saturations and are at higher risk for arrhythmia, heart failure, and cardiogenic shock.","difficulty":"Medium"},{"id":"c07_q09","question":"What family history finding raises suspicion for a cardiac channelopathy in a child with unexplained collapse?","options":["A. Family history of diabetes","B. Family history of sudden unexplained death in a young relative","C. Family history of asthma","D. Family history of migraine"],"correct":1,"rationale":"Sudden unexplained death in a young relative is a recognized clue suggesting an underlying cardiac channelopathy risk.","difficulty":"Medium"},{"id":"c07_q10","question":"What are the field priorities for a suspected pediatric cardiac emergency?","options":["A. Recognition, identifying reversible causes (especially hypoxia), and rapid transport with reassessment","B. Immediate antiarrhythmic drug administration without assessment","C. Delaying transport until a definitive diagnosis is made","D. Ignoring the rhythm and focusing only on blood pressure"],"correct":0,"rationale":"Field priorities are recognition via PAT/primary assessment, identifying reversible causes like hypoxia, and rapid transport with ongoing reassessment.","difficulty":"Medium"},{"id":"c07_q11","question":"Where should a provider look for arrest algorithms, defibrillation/cardioversion dosing, and antiarrhythmic drug dosing?","options":["A. This PEPP chapter covers it fully","B. The PALS reviewer","C. The BLS reviewer","D. No resource covers this"],"correct":1,"rationale":"This chapter deliberately does not reproduce arrest algorithms or drug dosing; the PALS reviewer covers this in full depth.","difficulty":"Easy"},{"id":"c07_q12","question":"A bradycardic infant has poor perfusion and diminished respiratory effort. What should the provider suspect first?","options":["A. A primary cardiac conduction disorder requiring immediate cardioversion","B. A respiratory or hypoxia problem, treatable by supporting oxygenation/ventilation","C. Nothing is wrong since bradycardia is normal in infants","D. A toxic ingestion is the only possible cause"],"correct":1,"rationale":"A bradycardic, poorly perfusing infant is usually a respiratory or hypoxia problem until proven otherwise, so oxygenation/ventilation is the priority.","difficulty":"Medium"},{"id":"c07_q13","question":"Why does PEPP limit its cardiac chapter to recognition rather than full resuscitation depth?","options":["A. To avoid duplicating PALS's authoritative arrest-algorithm and drug-dosing content","B. Because cardiac emergencies are not important in pediatrics","C. Because PALS does not cover cardiac arrest","D. Because field providers never encounter cardiac emergencies"],"correct":0,"rationale":"PEPP's guardrail is to avoid duplicating PALS's resuscitation content, focusing instead on field recognition and initial stabilization, with PALS as the authoritative depth resource.","difficulty":"Medium"},{"id":"c07_q14","question":"A school-age child with known repaired congenital heart disease has a caregiver report of a resting SpO2 of 88% at baseline. What does this mean for field assessment?","options":["A. 88% must always be treated as an emergency abnormal finding","B. This may be the child's normal baseline, so it should be compared to their known baseline rather than typical pediatric norms","C. This value should be ignored entirely","D. It indicates the caregiver is providing inaccurate information"],"correct":1,"rationale":"Children with congenital heart disease may have a baseline SpO2 different from typical norms; providers should ask about and compare to the child's known personal baseline.","difficulty":"Hard"}]},"c08":{"chapter":"c08","questions":[{"id":"c08_q01","question":"What does AVPU stand for?","options":["A. Alert, Voice, Pain, Unresponsive","B. Airway, Vitals, Pulse, Unconsciousness","C. Appearance, Ventilation, Perfusion, Urgency","D. Alert, Vital, Perfused, Unstable"],"correct":0,"rationale":"AVPU is a simple scale for level of consciousness: Alert, responds to Voice, responds to Pain, or Unresponsive.","difficulty":"Easy"},{"id":"c08_q02","question":"Which PAT leg often provides the earliest clue to altered mental status?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance","D. None of the PAT legs relate to mental status"],"correct":2,"rationale":"Appearance findings (eye contact, interactiveness, cry quality) often reveal altered mental status before a formal AVPU assessment.","difficulty":"Easy"},{"id":"c08_q03","question":"What does the AEIOU-TIPS mnemonic help a provider recall?","options":["A. Steps of the primary assessment","B. Reversible causes of altered mental status","C. PAT legs","D. Categories of respiratory compromise"],"correct":1,"rationale":"AEIOU-TIPS recalls reversible causes of altered mental status: Alcohol, Epilepsy, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke.","difficulty":"Medium"},{"id":"c08_q04","question":"Why is a glucose check emphasized for every altered pediatric patient when a meter is available?","options":["A. Hypoglycemia is rare and unimportant in children","B. Hypoglycemia is common and rapidly reversible","C. Glucose checks are only relevant for diabetic patients","D. It is required for billing, not clinical reasons"],"correct":1,"rationale":"Hypoglycemia is a common, easily and rapidly reversible cause of pediatric altered mental status, making a glucose check a high-value, low-cost intervention.","difficulty":"Easy"},{"id":"c08_q05","question":"What are the field priorities during an active pediatric seizure?","options":["A. Place an object in the mouth to prevent tongue biting","B. Protect the airway and from injury, check glucose, time the seizure","C. Restrain the child's limbs firmly","D. Administer oral medication during the seizure"],"correct":1,"rationale":"Correct field management is protecting the airway/positioning, protecting from injury, checking glucose, and timing the seizure — never placing objects in the mouth.","difficulty":"Easy"},{"id":"c08_q06","question":"What defines status epilepticus?","options":["A. Any seizure lasting more than 1 minute","B. A seizure lasting more than 5 minutes, or repeated seizures without return to baseline","C. Only seizures with fever","D. Only seizures in infants under 6 months"],"correct":1,"rationale":"Status epilepticus is defined as a seizure lasting more than 5 minutes, or repeated seizures without the patient returning to baseline between them.","difficulty":"Medium"},{"id":"c08_q07","question":"Where is benzodiazepine dosing for status epilepticus detailed?","options":["A. This PEPP chapter","B. The PALS reviewer","C. The BLS reviewer","D. No resource covers it"],"correct":1,"rationale":"Consistent with PEPP's guardrail against duplicating PALS content, drug dosing for status epilepticus is detailed in the PALS reviewer.","difficulty":"Medium"},{"id":"c08_q08","question":"What is the typical age range for febrile seizures?","options":["A. 6 months to 5 years","B. Birth to 1 month","C. 10 to 18 years","D. Only over age 10"],"correct":0,"rationale":"Febrile seizures are most typical in children 6 months to 5 years, associated with a rapidly rising fever.","difficulty":"Easy"},{"id":"c08_q09","question":"Which description fits a simple febrile seizure?","options":["A. Focal, lasting 20 minutes, recurs within hours","B. Generalized, lasting less than 15 minutes, no recurrence in 24 hours, returns to baseline","C. Any seizure with a fever regardless of duration","D. A seizure that does not return to baseline afterward"],"correct":1,"rationale":"A simple febrile seizure is generalized, brief (under 15 minutes), non-recurrent within 24 hours, with return to baseline mental status afterward.","difficulty":"Medium"},{"id":"c08_q10","question":"A febrile child has a focal seizure lasting 20 minutes. How should this be classified?","options":["A. A simple febrile seizure requiring no special concern","B. A complex febrile seizure, warranting a higher level of concern","C. Not a seizure at all","D. Status epilepticus by definition regardless of duration criteria"],"correct":1,"rationale":"Focal features and duration over 15 minutes meet the definition of a complex febrile seizure, which warrants greater concern than a simple febrile seizure (though it may also cross into status epilepticus if it continues beyond 5 minutes without stopping).","difficulty":"Hard"},{"id":"c08_q11","question":"What signs suggest increased intracranial pressure in an infant?","options":["A. Sunken fontanelle and tachypnea","B. Bulging fontanelle, decreasing consciousness, irregular respiratory pattern","C. Normal fontanelle and improved alertness","D. Warm, flushed skin"],"correct":1,"rationale":"A bulging fontanelle, decreasing level of consciousness, and an irregular respiratory pattern suggest increased intracranial pressure in an infant.","difficulty":"Medium"},{"id":"c08_q12","question":"What is the Cushing triad?","options":["A. Hypotension, tachycardia, tachypnea","B. Hypertension, bradycardia, irregular respirations","C. Fever, rash, vomiting","D. Tachycardia, hypertension, diaphoresis"],"correct":1,"rationale":"The Cushing triad — hypertension, bradycardia, and irregular respirations — is a late and ominous sign of increased intracranial pressure.","difficulty":"Medium"},{"id":"c08_q13","question":"Why should hypoxia and hypotension be avoided in a child with suspected increased intracranial pressure?","options":["A. They have no effect on brain injury","B. Both worsen secondary brain injury","C. They only affect cardiac function, not the brain","D. They are unavoidable and not a treatment priority"],"correct":1,"rationale":"Both hypoxia and hypotension worsen secondary brain injury in a child with elevated intracranial pressure, making their avoidance a key field priority.","difficulty":"Medium"},{"id":"c08_q14","question":"Why does a trend of decreasing responsiveness across serial reassessments matter more than a single mental status snapshot?","options":["A. It doesn't — only the first assessment matters","B. A worsening trend indicates ongoing deterioration that a single value could miss","C. Trends are only relevant in adults","D. Serial reassessment is not recommended in pediatric care"],"correct":1,"rationale":"A single mental status value can miss an evolving problem; a trend toward decreasing responsiveness reveals ongoing deterioration and should prompt escalation.","difficulty":"Hard"}]},"c09":{"chapter":"c09","questions":[{"id":"c09_q01","question":"Why do children have distinct trauma injury patterns compared to adults?","options":["A. Larger head-to-body ratio, more pliable ribcage, less protected abdominal organs, thinner subcutaneous tissue","B. Children have identical anatomy proportions to adults","C. Children never sustain internal injuries","D. Children's bones are less flexible than adults'"],"correct":0,"rationale":"Pediatric anatomic differences — larger head-to-body ratio, more pliable ribcage, less protected abdominal organs, thinner subcutaneous tissue — create distinct injury patterns.","difficulty":"Easy"},{"id":"c09_q02","question":"Why does head injury often dominate in pediatric trauma?","options":["A. Children rarely fall","B. The relatively larger, heavier head increases injury risk and force absorbed","C. Children have thicker skulls than adults","D. Head injury is actually less common in children"],"correct":1,"rationale":"A child's proportionally larger, heavier head increases the likelihood and severity of head injury in falls and collisions.","difficulty":"Medium"},{"id":"c09_q03","question":"Why can a child have significant pulmonary contusion without rib fractures?","options":["A. Children's ribs are more rigid than adults'","B. The pediatric ribcage is more pliable/elastic, transmitting energy to internal structures without fracturing","C. Pulmonary contusion cannot occur in children","D. Rib fractures always occur first in children"],"correct":1,"rationale":"The elastic, pliable pediatric ribcage can allow significant internal chest injury without rib fractures.","difficulty":"Medium"},{"id":"c09_q04","question":"Does the absence of rib fractures rule out significant chest injury in a child?","options":["A. Yes, always","B. No — absence of fractures does not exclude serious injury","C. Only in infants","D. Only if breath sounds are normal"],"correct":1,"rationale":"Because of ribcage pliability, the absence of fractures does not exclude serious underlying chest injury in children.","difficulty":"Medium"},{"id":"c09_q05","question":"Why are the liver and spleen more vulnerable to blunt trauma in children than adults?","options":["A. They are proportionally larger and less protected by the ribcage","B. They are located outside the abdominal cavity in children","C. Children do not have a spleen","D. They are smaller and better protected than in adults"],"correct":0,"rationale":"The pediatric liver and spleen are proportionally larger and less shielded by the ribcage, increasing vulnerability to blunt abdominal trauma.","difficulty":"Medium"},{"id":"c09_q06","question":"Does a soft, non-tender abdominal exam exclude significant abdominal injury after pediatric blunt trauma?","options":["A. Yes, always","B. No — significant injury can be present despite a falsely reassuring exam, especially early after the event","C. Only in adolescents","D. Only if the child is crying"],"correct":1,"rationale":"A soft, non-tender abdomen can be falsely reassuring; occult abdominal injury is common in pediatric blunt trauma and may not be apparent immediately.","difficulty":"Hard"},{"id":"c09_q07","question":"Can a child maintain a normal blood pressure despite significant blood loss?","options":["A. No, hypotension always appears first","B. Yes — effective compensation can maintain BP well into significant hemorrhage","C. Only in adolescents","D. Only if the injury is minor"],"correct":1,"rationale":"Children compensate for blood loss effectively, similar to shock physiology, so normal blood pressure does not exclude significant hemorrhage.","difficulty":"Medium"},{"id":"c09_q08","question":"Which findings should be treated as seriously as hypotension after pediatric trauma?","options":["A. Normal heart rate and warm skin","B. Tachycardia, delayed capillary refill, and cool extremities","C. Slow heart rate and flushed skin","D. Normal capillary refill alone"],"correct":1,"rationale":"Tachycardia, delayed capillary refill, and cool extremities may be the only clues to significant hemorrhage before hypotension develops.","difficulty":"Medium"},{"id":"c09_q09","question":"Why does torso padding matter when placing a young child on a standard backboard?","options":["A. It has no effect on spinal alignment","B. The proportionally larger head can force neck flexion when lying flat; torso padding helps maintain neutral alignment","C. It is only for comfort, not alignment","D. It is only needed for adolescents"],"correct":1,"rationale":"A child's larger head relative to body forces neck flexion on a flat surface; padding under the torso helps achieve neutral spinal alignment.","difficulty":"Medium"},{"id":"c09_q10","question":"Why does mechanism and mental status carry more weight than reported pain in pediatric spinal motion restriction decisions?","options":["A. Young children may not reliably report pain or tenderness","B. Children always overreport pain","C. Pain reporting is more reliable in children than adults","D. Mechanism is irrelevant in pediatric trauma decisions"],"correct":0,"rationale":"Because young children may not reliably communicate pain or tenderness, mechanism of injury and mental status become more heavily weighted in the decision.","difficulty":"Hard"},{"id":"c09_q11","question":"What signs in an infant after head trauma suggest evolving intracranial injury?","options":["A. Bulging fontanelle or decreasing mental status","B. Sunken fontanelle and increased alertness","C. Warm, flushed skin","D. Improved feeding"],"correct":0,"rationale":"A bulging fontanelle and decreasing mental status are concerning signs of evolving intracranial injury in an infant after head trauma.","difficulty":"Medium"},{"id":"c09_q12","question":"What is the appropriate destination consideration for significant pediatric trauma when available?","options":["A. Any facility regardless of pediatric capability","B. An appropriate, ideally pediatric-capable trauma center","C. Only adult trauma centers","D. Destination does not matter for pediatric patients"],"correct":1,"rationale":"Transport to an appropriate, ideally pediatric-capable trauma center is a field management priority for significant pediatric trauma.","difficulty":"Easy"},{"id":"c09_q13","question":"A child struck by a car has normal vital signs but a history of high-energy mechanism and a single rib fracture. What is the appropriate level of concern?","options":["A. Low concern since vital signs are normal","B. High concern — a rib fracture signals a high-energy mechanism and raises suspicion for underlying injury despite normal vitals","C. No concern needed if the child is not in pain","D. Concern only if the abdomen is tender"],"correct":1,"rationale":"Any rib fracture in a child signals a high-energy mechanism and should raise suspicion for underlying pulmonary or cardiac injury, even with reassuring vitals.","difficulty":"Hard"},{"id":"c09_q14","question":"What is the overall field management framework for pediatric trauma?","options":["A. Standard trauma priorities (scene safety, hemorrhage control, ABC support, rapid transport) with attention to pediatric-specific injury patterns","B. A completely different framework unrelated to standard trauma care","C. Delayed transport until all injuries are definitively identified","D. Reliance solely on blood pressure to guide urgency"],"correct":0,"rationale":"Pediatric trauma management follows standard trauma priorities, adapted with awareness of pediatric-specific anatomic and physiologic injury patterns.","difficulty":"Medium"}]},"c10":{"chapter":"c10","questions":[{"id":"c10_q01","question":"Which age group is at peak risk for unintentional poisoning?","options":["A. Neonates","B. Toddlers (1-3 years)","C. School-age children","D. Adolescents"],"correct":1,"rationale":"Toddlers are at peak risk due to their mobility, curiosity, and tendency to mouth objects, combined with accessible household substances.","difficulty":"Easy"},{"id":"c10_q02","question":"What should field assessment of a suspected ingestion prioritize?","options":["A. Waiting for definitive lab identification before any assessment","B. Identifying the substance, amount, and time of exposure, and bringing containers to the hospital","C. Ignoring the exposure if the child appears well","D. Inducing vomiting in all cases"],"correct":1,"rationale":"Field assessment should focus on identifying substance, amount, and timing when possible, and bringing physical evidence (containers/pills) to the hospital.","difficulty":"Easy"},{"id":"c10_q03","question":"A child has altered mental status, pinpoint pupils, and respiratory depression. What toxidrome does this suggest?","options":["A. Anticholinergic","B. Opioid","C. Sympathomimetic","D. Cholinergic"],"correct":1,"rationale":"Pinpoint pupils with respiratory depression and altered mental status is the classic opioid toxidrome.","difficulty":"Medium"},{"id":"c10_q04","question":"Why is button battery ingestion especially dangerous?","options":["A. It only causes minor, self-limited irritation","B. A lodged battery can cause severe tissue injury within hours via an electrical current effect","C. Button batteries pass through the GI tract without any risk","D. It is dangerous only if swallowed with food"],"correct":1,"rationale":"A lodged esophageal button battery can cause severe injury within hours through an electrical current effect, not just direct chemical burn.","difficulty":"Medium"},{"id":"c10_q05","question":"How should a suspected button battery ingestion be managed if the child currently appears asymptomatic?","options":["A. No transport needed since symptoms are absent","B. Still treated as a time-critical emergency requiring rapid transport and hospital notification","C. Wait 24 hours to reassess","D. Manage at home with observation only"],"correct":1,"rationale":"Button battery ingestion is treated as time-critical regardless of current symptoms, since injury can progress even in an asymptomatic child.","difficulty":"Hard"},{"id":"c10_q06","question":"Why are children more vulnerable to heat illness than adults?","options":["A. Higher surface-area-to-mass ratio, less efficient sweating, dependence on caregivers to escape heat","B. Children sweat more efficiently than adults","C. Children have a lower surface-area-to-mass ratio","D. Heat illness does not occur in children"],"correct":0,"rationale":"A higher surface-area-to-mass ratio, less efficient sweating, and reliance on caregivers to remove them from heat increase pediatric heat illness risk.","difficulty":"Medium"},{"id":"c10_q07","question":"Why is a child left in a hot vehicle a particularly dangerous scenario?","options":["A. Vehicle interior temperatures rise slowly, giving ample time to intervene","B. Internal vehicle temperatures can become life-threatening within minutes","C. This scenario poses no unique risk compared to being outdoors","D. Only adults are at risk in hot vehicles"],"correct":1,"rationale":"Vehicle interiors can reach life-threatening temperatures within minutes, making this a high-stakes, preventable pediatric emergency.","difficulty":"Medium"},{"id":"c10_q08","question":"Why are infants especially vulnerable to hypothermia?","options":["A. Higher surface-area-to-mass ratio plus limited ability to shiver for heat generation","B. Infants generate excess body heat compared to adults","C. Infants have thicker subcutaneous fat than adults","D. Hypothermia does not affect infants"],"correct":0,"rationale":"Infants share the pediatric surface-area-to-mass vulnerability and have a limited ability to shiver, increasing hypothermia risk.","difficulty":"Medium"},{"id":"c10_q09","question":"Which age groups are at highest risk for drowning?","options":["A. Toddlers (bathtubs, pools) and adolescents (open water, risk-taking/alcohol)","B. Only neonates","C. Only school-age children","D. Drowning risk is equal across all pediatric ages and contexts"],"correct":0,"rationale":"Toddlers (bathtubs, pools) and adolescents (open water, often with risk-taking or alcohol) represent the highest-risk drowning groups.","difficulty":"Medium"},{"id":"c10_q10","question":"What is the core physiologic problem in drowning?","options":["A. Hypothermia","B. Hypoxia","C. Hypoglycemia","D. Hypertension"],"correct":1,"rationale":"Drowning is fundamentally a respiratory event, with hypoxia as the primary problem to treat.","difficulty":"Easy"},{"id":"c10_q11","question":"When should spinal motion restriction be applied after a submersion event?","options":["A. In every submersion case regardless of mechanism","B. Only if the mechanism suggests trauma, such as a diving injury","C. Never, regardless of mechanism","D. Only in adolescents"],"correct":1,"rationale":"Spinal motion restriction after submersion is applied selectively, based on a mechanism suggesting trauma (e.g., diving into shallow water).","difficulty":"Medium"},{"id":"c10_q12","question":"Should a well-appearing child be transported after a submersion event?","options":["A. No, if the child appears completely normal","B. Yes — pulmonary complications can evolve over hours even in a well-appearing child","C. Only if the child requests transport","D. Only if hypothermia is present"],"correct":1,"rationale":"Delayed pulmonary complications can develop after submersion even in children who appear well initially, so transport for observation is recommended.","difficulty":"Hard"},{"id":"c10_q13","question":"What is the general field management framework across toxic and environmental emergencies?","options":["A. Identify the exposure/mechanism, support ABCs, remove from ongoing hazard, bring materials to hospital, transport promptly","B. Treat only the presenting symptom without further assessment","C. Delay transport until the child is fully asymptomatic","D. Rely solely on caregiver reassurance to determine need for transport"],"correct":0,"rationale":"This bundle of priorities — exposure/mechanism identification, ABC support, hazard removal, bringing evidence, and prompt transport — applies across toxic and environmental emergencies.","difficulty":"Medium"},{"id":"c10_q14","question":"Why does PEPP recommend a lower threshold for transport/observation in pediatric toxic/environmental emergencies compared to adults?","options":["A. Children are more likely to fabricate symptoms","B. Children can appear deceptively well before deteriorating","C. Pediatric transport is always free of cost considerations","D. There is no difference in threshold between children and adults"],"correct":1,"rationale":"Children's capacity to appear well before rapid deterioration (e.g., button battery, submersion, early heat illness) supports a lower threshold for transport/observation.","difficulty":"Hard"}]},"c11":{"chapter":"c11","questions":[{"id":"c11_q01","question":"What must a newborn transition from and to at birth?","options":["A. From placental gas exchange to independent breathing","B. From independent breathing to placental gas exchange","C. No transition occurs at birth","D. From bottle feeding to breastfeeding"],"correct":0,"rationale":"At birth, a newborn transitions from placental gas exchange to independent breathing, with lung fluid clearing and circulatory shunt changes.","difficulty":"Easy"},{"id":"c11_q02","question":"What are the three initial questions asked immediately after delivery?","options":["A. Term gestation? Good tone? Breathing/crying?","B. Weight? Length? Head circumference?","C. Apgar score at 1 minute? 5 minutes? 10 minutes?","D. Male or female? Single or multiple birth? Time of day?"],"correct":0,"rationale":"The three rapid initial questions are: term gestation, good tone, and breathing or crying.","difficulty":"Easy"},{"id":"c11_q03","question":"If the answers to all three initial questions are yes, what is the appropriate action?","options":["A. Move the newborn to a warmer immediately for stabilization","B. Begin positive-pressure ventilation as a precaution","C. The newborn can stay with the mother for routine care (dry, warm, skin-to-skin)","D. Begin chest compressions"],"correct":2,"rationale":"A vigorous, term, breathing/crying newborn can remain with the mother for routine care.","difficulty":"Easy"},{"id":"c11_q04","question":"What are the initial steps of newborn stabilization?","options":["A. Warmth, position airway, clear secretions if needed, dry, stimulate","B. Immediate intubation for all newborns","C. Routine deep suctioning for every newborn","D. Immediate chest compressions"],"correct":0,"rationale":"The initial steps are providing warmth, positioning the airway, clearing secretions only if needed, drying, and stimulating.","difficulty":"Medium"},{"id":"c11_q05","question":"Is routine deep suctioning recommended for every newborn?","options":["A. Yes, for all newborns","B. No — suctioning is performed only if needed","C. Only for preterm newborns","D. Only if the mother requests it"],"correct":1,"rationale":"Clearing secretions is done only if needed, not as a routine step for every newborn.","difficulty":"Medium"},{"id":"c11_q06","question":"Why is keeping a newborn warm such a high priority?","options":["A. A wet, uncovered newborn loses heat extremely rapidly, and hypothermia worsens outcomes","B. Warmth has no effect on newborn outcomes","C. Only preterm newborns are at risk of heat loss","D. Warming is only relevant after the first hour of life"],"correct":0,"rationale":"Newborns lose heat rapidly when wet and uncovered, and hypothermia is associated with worse outcomes, making warmth a top priority.","difficulty":"Medium"},{"id":"c11_q07","question":"When is positive-pressure ventilation indicated for a newborn?","options":["A. Only if the newborn is crying vigorously","B. If, after initial steps, the newborn is apneic, gasping, or has a heart rate below 100 bpm","C. For every newborn regardless of condition","D. Only after chest compressions have been started"],"correct":1,"rationale":"PPV is indicated when the newborn remains apneic, gasping, or has a heart rate below 100 bpm after the initial steps.","difficulty":"Medium"},{"id":"c11_q08","question":"What is the single most important intervention in newborn resuscitation?","options":["A. Chest compressions","B. Positive-pressure ventilation","C. Epinephrine administration","D. Umbilical line placement"],"correct":1,"rationale":"PPV is considered the single most important intervention in newborn resuscitation, since most newborn compromise originates from inadequate ventilation.","difficulty":"Medium"},{"id":"c11_q09","question":"When are chest compressions added during newborn resuscitation?","options":["A. Immediately upon any bradycardia","B. Only if heart rate remains below 60 bpm despite 30 seconds of effective PPV","C. Before ventilation is attempted","D. Compressions are never used in newborns"],"correct":1,"rationale":"Chest compressions are added only if the heart rate stays below 60 bpm despite 30 seconds of effective positive-pressure ventilation.","difficulty":"Medium"},{"id":"c11_q10","question":"How does the newborn resuscitation sequence differ from adult/older-child cardiac arrest management?","options":["A. Ventilation is prioritized first, with compressions added only if ventilation alone is insufficient","B. Compressions are always started first, identical to adult arrest","C. There is no difference between the sequences","D. Defibrillation is the first step in newborn resuscitation"],"correct":0,"rationale":"Newborn resuscitation emphasizes ventilation first, reflecting that most newborn compromise is a ventilation problem rather than a primary cardiac one — unlike the compressions-first emphasis in other arrest contexts.","difficulty":"Hard"},{"id":"c11_q11","question":"A newborn is not vigorous, has poor tone, and is not crying at delivery. What is the correct next step?","options":["A. Leave the newborn with the mother for routine care","B. Move the newborn to a warmer to begin the initial steps of stabilization","C. Begin chest compressions immediately without assessment","D. Wait 5 minutes before taking any action"],"correct":1,"rationale":"Any 'no' answer to the three initial questions (term, tone, breathing/crying) means the newborn should be moved to a warmer for the initial stabilization steps.","difficulty":"Medium"},{"id":"c11_q12","question":"After 30 seconds of effective PPV, the newborn's heart rate is 50 bpm. What is the next step?","options":["A. Continue PPV alone without adding compressions","B. Begin chest compressions coordinated with PPV","C. Stop all resuscitation efforts","D. Switch immediately to medication administration without compressions"],"correct":1,"rationale":"A heart rate below 60 bpm despite 30 seconds of effective PPV is the threshold for adding chest compressions.","difficulty":"Medium"},{"id":"c11_q13","question":"Where should providers turn for detailed neonatal resuscitation algorithms, medication dosing, and advanced airway specifics?","options":["A. This PEPP chapter covers it fully","B. Local neonatal resuscitation protocol / the Neonatal Resuscitation Program (NRP)","C. The BLS reviewer","D. No resource addresses this"],"correct":1,"rationale":"This chapter covers field recognition and initial stabilization; detailed neonatal resuscitation depth is covered by dedicated NRP training and local protocol.","difficulty":"Medium"},{"id":"c11_q14","question":"Why is warmth emphasized even before assessing breathing and heart rate in the initial steps?","options":["A. Warmth is not actually part of the initial steps","B. Heat loss is extremely rapid in newborns and worsens overall resuscitation outcomes, making it a foundational priority alongside assessment","C. Warmth is only relevant after resuscitation is complete","D. Newborns cannot lose heat significantly in the first few minutes"],"correct":1,"rationale":"Because newborns lose heat extremely rapidly and hypothermia worsens outcomes, warmth is treated as a foundational, high-priority step integrated into the initial stabilization sequence.","difficulty":"Hard"}]},"c12":{"chapter":"c12","questions":[{"id":"c12_q01","question":"What is the EMS provider's role regarding suspected child maltreatment?","options":["A. Investigate the case fully before providing care","B. Recognize concerning findings, document objectively, and report through appropriate channels","C. Confront the caregiver directly to obtain a confession","D. Make a final determination of whether maltreatment occurred"],"correct":1,"rationale":"EMS providers recognize and report concerns; they are not investigators and do not make final determinations.","difficulty":"Easy"},{"id":"c12_q02","question":"What is a central concept for recognizing possibly concerning pediatric injuries?","options":["A. The severity of the injury alone","B. Comparing the stated mechanism/history to the child's developmental capability and the injury pattern","C. The caregiver's income level","D. Whether the injury requires hospital transport"],"correct":1,"rationale":"History-injury-developmental consistency is a central recognition concept — mismatches raise concern more than severity alone.","difficulty":"Medium"},{"id":"c12_q03","question":"A caregiver reports a non-mobile 2-month-old 'rolled off the couch' and sustained a femur fracture. What should this raise?","options":["A. No concern, since falls are common in infants","B. Concern, since this mechanism is inconsistent with a non-mobile infant's developmental capability","C. Concern only if the caregiver seems nervous","D. This should be dismissed unless the child has prior injuries"],"correct":1,"rationale":"A non-mobile infant cannot roll off a couch under their own power, making this history inconsistent with the infant's developmental stage and a concern-raising finding.","difficulty":"Hard"},{"id":"c12_q04","question":"Besides mechanism inconsistency, what other general findings may raise concern?","options":["A. A history that changes between tellings/caregivers, or an unexplained delay in seeking care","B. A single bruise on the shin of an active toddler","C. A caregiver who asks many questions about treatment","D. A child who is shy during the assessment"],"correct":0,"rationale":"A changing history and unexplained delay in seeking care are recognized general concern-raising categories, distinct from common, low-concern findings like a toddler's shin bruise.","difficulty":"Medium"},{"id":"c12_q05","question":"Is any single finding diagnostic of child maltreatment on its own?","options":["A. Yes, certain findings are always diagnostic","B. No — providers document objectively and let appropriate professionals evaluate the full picture","C. Only bruising is diagnostic","D. Only fractures are diagnostic"],"correct":1,"rationale":"No single finding is diagnostic; the full clinical and social picture must be evaluated by appropriately trained professionals.","difficulty":"Medium"},{"id":"c12_q06","question":"How should EMS providers communicate with caregivers when maltreatment is suspected?","options":["A. Confront them directly and accusingly","B. Calmly, professionally, and non-accusatorially","C. Refuse to speak with the caregiver at all","D. Interrogate the caregiver extensively before treating the child"],"correct":1,"rationale":"Non-judgmental, professional communication is recommended, since confrontation can compromise the child's care and any subsequent investigation.","difficulty":"Easy"},{"id":"c12_q07","question":"What kind of documentation is recommended when maltreatment is suspected?","options":["A. Subjective conclusions about the caregiver's guilt","B. Objective documentation — exact quotes, observed findings, scene details","C. No documentation, to avoid legal complications","D. Only a checkbox indicating 'suspected abuse'"],"correct":1,"rationale":"Objective, factual documentation (quotes, findings, scene details) is more useful and appropriate than subjective conclusions.","difficulty":"Medium"},{"id":"c12_q08","question":"Are EMS providers mandatory reporters of suspected child maltreatment?","options":["A. No, reporting is always optional","B. Yes, in essentially all jurisdictions","C. Only physicians are mandatory reporters","D. Only if the child requests it"],"correct":1,"rationale":"EMS providers are mandatory reporters in essentially all jurisdictions, legally required to report reasonable suspicion.","difficulty":"Easy"},{"id":"c12_q09","question":"Does this chapter specify exact jurisdiction-specific reporting procedures?","options":["A. Yes, in full detail for every state","B. No — providers must follow their own agency policy and local/state law, which vary by location","C. Reporting procedures are identical everywhere","D. This chapter replaces the need for agency policy"],"correct":1,"rationale":"Reporting mechanics vary by jurisdiction; this chapter is general and educational, and providers must follow their specific local law and agency policy.","difficulty":"Medium"},{"id":"c12_q10","question":"Who should be involved when suspicion of maltreatment arises during a call?","options":["A. No one beyond the treating provider","B. Medical direction and receiving-facility staff, per local protocol","C. Only law enforcement, never medical staff","D. Only the child's school"],"correct":1,"rationale":"Medical direction and receiving-facility staff should be involved per local protocol when maltreatment is suspected.","difficulty":"Medium"},{"id":"c12_q11","question":"Should EMS providers confront caregivers directly about suspected maltreatment on scene?","options":["A. Yes, always","B. No — this can compromise the child's care and any investigation","C. Only if backup is present","D. Only for severe injuries"],"correct":1,"rationale":"Direct confrontation is a common mistake to avoid; recognition and reporting are the provider's role, not confrontation.","difficulty":"Medium"},{"id":"c12_q12","question":"What is the correct balance between medical care and addressing suspicion of maltreatment on scene?","options":["A. Withhold medical care until the suspicion is resolved","B. Continue standard medical care for the presenting condition while separately documenting and reporting through appropriate channels","C. Provide care but omit any documentation of concerning findings","D. Refuse to transport until police arrive"],"correct":1,"rationale":"Medical care continues as usual for the child's condition, with concerning findings addressed separately through objective documentation and appropriate reporting.","difficulty":"Medium"},{"id":"c12_q13","question":"A history changes between what the caregiver initially reported and what they report to the receiving facility. What should this be treated as?","options":["A. Irrelevant, since minor detail changes are always expected","B. A potential concern-raising factor, to be documented objectively","C. Definitive proof of maltreatment","D. Grounds for immediate confrontation of the caregiver"],"correct":1,"rationale":"A changing history is a recognized concern-raising category and should be documented objectively rather than either dismissed or treated as definitive proof.","difficulty":"Hard"},{"id":"c12_q14","question":"Why does PEPP frame this chapter as general and educational rather than providing a definitive checklist for confirming maltreatment?","options":["A. Because maltreatment recognition is not important","B. Because no single finding is diagnostic, and jurisdiction-specific reporting/legal processes vary, requiring providers to rely on local training and policy","C. Because maltreatment never occurs in prehospital patients","D. Because only law enforcement needs this training"],"correct":1,"rationale":"Given the complexity and jurisdictional variation of this topic, and that no single finding is diagnostic, the chapter deliberately stays general and educational, deferring specifics to local law, agency policy, and specialized training.","difficulty":"Hard"}]},"c13":{"chapter":"c13","questions":[{"id":"c13_q01","question":"What does CSHCN stand for?","options":["A. Children with special healthcare needs","B. Critical severity healthcare notification","C. Chronic surgical healthcare network","D. Community special healthcare navigation"],"correct":0,"rationale":"CSHCN stands for children with special healthcare needs.","difficulty":"Easy"},{"id":"c13_q02","question":"Why are caregivers of CSHCN a critical resource on scene?","options":["A. They are legally required to answer all questions","B. They are frequently the most knowledgeable resource about the child's baseline, equipment, and typical presentation","C. They have no relevant medical knowledge","D. They should be excluded from the encounter"],"correct":1,"rationale":"Caregivers of CSHCN typically manage the child's condition and equipment daily and are the best source of baseline information.","difficulty":"Easy"},{"id":"c13_q03","question":"What are common tracheostomy problems encountered in the field?","options":["A. Mucus plugging, accidental decannulation, tube malposition","B. Only infection","C. Tracheostomies never malfunction","D. Only overinflation of the cuff"],"correct":0,"rationale":"Mucus plugging, accidental decannulation, and tube malposition are common tracheostomy problems.","difficulty":"Medium"},{"id":"c13_q04","question":"What is the first step for a child with a tracheostomy in respiratory distress?","options":["A. Immediately remove the tracheostomy tube","B. Attempt suctioning to clear a possible mucus plug","C. Call for a surgical consult before any action","D. Replace the tube regardless of findings"],"correct":1,"rationale":"Suctioning to address a possible mucus plug is the first troubleshooting step for tracheostomy-related respiratory distress.","difficulty":"Medium"},{"id":"c13_q05","question":"If suctioning does not resolve tracheostomy-related distress, what should be checked next?","options":["A. Accidental decannulation (tube fully or partially out)","B. The child's blood type","C. The caregiver's employment status","D. Whether the child has eaten recently"],"correct":0,"rationale":"Checking for accidental decannulation is the next troubleshooting step after suctioning fails to resolve distress.","difficulty":"Medium"},{"id":"c13_q06","question":"What does a ventriculoperitoneal (VP) shunt treat, and how?","options":["A. Hydrocephalus, by diverting cerebrospinal fluid","B. Diabetes, by delivering insulin","C. Asthma, by delivering bronchodilators","D. Seizures, by delivering anticonvulsants"],"correct":0,"rationale":"A VP shunt treats hydrocephalus by diverting cerebrospinal fluid, typically to the peritoneal cavity.","difficulty":"Easy"},{"id":"c13_q07","question":"What signs suggest VP shunt malfunction in a child with a known shunt?","options":["A. Headache, vomiting, altered mental status, bulging fontanelle","B. Improved alertness and appetite","C. Normal fontanelle and no symptoms","D. Isolated mild fever alone"],"correct":0,"rationale":"These findings suggest increased intracranial pressure from shunt malfunction, since the shunt is failing to drain CSF normally.","difficulty":"Medium"},{"id":"c13_q08","question":"What is the appropriate field management for suspected VP shunt malfunction?","options":["A. Standard increased-ICP precautions and rapid transport","B. Attempt to manually adjust the shunt valve in the field","C. No action needed since shunts never malfunction","D. Aggressive fluid restriction only"],"correct":0,"rationale":"Field management is standard increased-ICP precautions (avoiding hypoxia/hypotension, positioning) with rapid transport; shunt-specific intervention is a hospital-level treatment.","difficulty":"Medium"},{"id":"c13_q09","question":"What is a gastrostomy (G-) tube used for?","options":["A. Enteral feeding directly into the stomach","B. Cardiac monitoring","C. Cerebrospinal fluid diversion","D. Mechanical ventilation"],"correct":0,"rationale":"A gastrostomy tube provides enteral (stomach) feeding access.","difficulty":"Easy"},{"id":"c13_q10","question":"Why is baseline function more useful than population norms when assessing a CSHCN patient?","options":["A. Population norms are always more accurate","B. A CSHCN patient's normal vitals/interactiveness may differ substantially from typically developing children","C. Baseline function is irrelevant to assessment","D. CSHCN patients never have an altered baseline"],"correct":1,"rationale":"CSHCN patients can have a baseline that differs meaningfully from population norms, making their own baseline the more useful reference.","difficulty":"Medium"},{"id":"c13_q11","question":"What question should providers always ask when assessing a CSHCN patient?","options":["A. 'What is normal for this child?'","B. 'What grade is this child in?'","C. 'Does this child have insurance?'","D. 'How many siblings does this child have?'"],"correct":0,"rationale":"Asking about the child's personal baseline is the key question for accurately interpreting findings in a CSHCN patient.","difficulty":"Easy"},{"id":"c13_q12","question":"A CSHCN patient with a home ventilator via tracheostomy is in distress. Who is often best positioned to help troubleshoot the specific device quickly?","options":["A. The caregiver, who typically manages the equipment daily","B. A bystander with no medical training","C. No one can help — the equipment must be ignored until hospital arrival","D. Only the original prescribing physician, by phone"],"correct":0,"rationale":"Caregivers of CSHCN typically manage their child's equipment daily and are often the fastest, most knowledgeable troubleshooting resource on scene.","difficulty":"Medium"},{"id":"c13_q13","question":"A child with a known VP shunt has a resting SpO2 of 91% at baseline per the caregiver, with no other acute findings. How should this be interpreted?","options":["A. As an emergency requiring immediate aggressive intervention","B. As the child's reported personal baseline, warranting comparison rather than automatic alarm","C. As proof the shunt is malfunctioning","D. As irrelevant information"],"correct":1,"rationale":"Consistent with the baseline-over-population-norms principle, a caregiver-reported baseline value should be used as the comparison point rather than assumed abnormal on its own.","difficulty":"Hard"},{"id":"c13_q14","question":"Which population is included under 'children with special healthcare needs'?","options":["A. Only children with tracheostomies","B. A broad population, from a child with well-controlled asthma to a child with complex technology dependence","C. Only children with cancer","D. Only children who use a wheelchair"],"correct":1,"rationale":"CSHCN is a broad category encompassing a wide range of chronic conditions and care needs, not limited to any single diagnosis or technology.","difficulty":"Medium"}]},"c14":{"chapter":"c14","questions":[{"id":"c14_q01","question":"What factors guide pediatric transport destination decisions?","options":["A. Only the distance to the nearest hospital","B. The severity/type of condition weighed against nearby facilities' pediatric-specific capabilities","C. The child's insurance status","D. Random assignment among available hospitals"],"correct":1,"rationale":"Transport decisions weigh clinical severity/type against which nearby facilities have pediatric-specific resources.","difficulty":"Easy"},{"id":"c14_q02","question":"What should guide a decision to bypass a closer general hospital for a significantly injured child?","options":["A. Personal preference of the crew","B. Local protocol defining pediatric-capable/pediatric trauma center bypass criteria, with medical direction consultation as needed","C. Always transport to the nearest facility regardless of capability","D. The caregiver's insurance network only"],"correct":1,"rationale":"Local protocols define bypass criteria for pediatric-capable destinations; providers should follow protocol and consult medical direction as needed.","difficulty":"Medium"},{"id":"c14_q03","question":"Why do children require specific consideration in disaster planning?","options":["A. They have identical needs to adults in every respect","B. Unique vulnerabilities including exposure susceptibility, evacuation dependence, psychological impact, and different equipment/medication needs","C. Children are not affected by disasters","D. Disaster planning cannot realistically account for children"],"correct":1,"rationale":"Children have distinct vulnerabilities that must be explicitly planned for in disaster response, beyond simply scaling down adult plans.","difficulty":"Medium"},{"id":"c14_q04","question":"What is JumpSTART?","options":["A. An adult-only MCI triage tool","B. A pediatric-specific adaptation of the adult START MCI triage algorithm","C. A cardiac arrest algorithm","D. A neonatal resuscitation protocol"],"correct":1,"rationale":"JumpSTART adapts the adult START MCI triage tool specifically for pediatric patients.","difficulty":"Easy"},{"id":"c14_q05","question":"Why was JumpSTART developed rather than applying adult START directly to children?","options":["A. Children's physiologic norms and injury/arrest patterns differ enough from adults to need adjusted criteria","B. Adult START works identically well for children","C. JumpSTART was developed before START and adapted for adults","D. There is no meaningful difference between adult and pediatric triage needs"],"correct":0,"rationale":"Pediatric physiologic differences justify a separate, adapted triage tool rather than direct application of adult criteria.","difficulty":"Medium"},{"id":"c14_q06","question":"What special step does JumpSTART include for an apneic child with a pulse?","options":["A. Immediate categorization as expectant with no intervention","B. Five rescue breaths before categorizing as expectant","C. Thirty chest compressions before reassessment","D. Immediate transport with no triage category assigned"],"correct":1,"rationale":"JumpSTART includes five rescue breaths for an apneic child with a pulse before an expectant categorization, since pediatric arrest is often respiratory and reversible.","difficulty":"Medium"},{"id":"c14_q07","question":"Why does JumpSTART include the five-rescue-breaths step, unlike adult START?","options":["A. Because pediatric arrest is often respiratory in origin and may be reversible with ventilation alone","B. Because children never have reversible causes of apnea","C. Because adult START also includes this step identically","D. Because rescue breaths are only for training purposes, not real triage"],"correct":0,"rationale":"This step reflects the pediatric-specific insight that respiratory causes of arrest are common and potentially reversible with ventilation.","difficulty":"Hard"},{"id":"c14_q08","question":"What scale does JumpSTART use for mental status assessment, and why?","options":["A. AVPU, since it is more developmentally appropriate than command-following","B. GCS motor score only","C. Command-following only, identical to adult START","D. No mental status assessment is included in JumpSTART"],"correct":0,"rationale":"JumpSTART uses AVPU rather than command-following, since young children may not reliably follow commands regardless of clinical status.","difficulty":"Medium"},{"id":"c14_q09","question":"What respiratory rate consideration differs between JumpSTART and adult START?","options":["A. JumpSTART ignores respiratory rate entirely","B. JumpSTART uses pediatric-specific respiratory rate thresholds rather than the adult cutoff","C. JumpSTART and adult START use identical respiratory rate thresholds","D. JumpSTART only assesses respiratory rate in adolescents"],"correct":1,"rationale":"JumpSTART adjusts respiratory rate thresholds to reflect normal pediatric ranges rather than using the adult cutoff.","difficulty":"Medium"},{"id":"c14_q10","question":"What operational risk exists if triage personnel apply adult START criteria directly to pediatric MCI patients?","options":["A. No risk — the criteria are interchangeable","B. Misclassification of children, since adult thresholds don't match pediatric physiologic norms","C. Children would automatically be triaged as minor","D. Adult criteria are always more conservative for children"],"correct":1,"rationale":"Applying adult respiratory rate thresholds and other adult criteria to children can misclassify their triage category, since normal pediatric physiology differs.","difficulty":"Hard"},{"id":"c14_q11","question":"What equipment/medication risk is heightened in pediatric MCI response if not planned for in advance?","options":["A. Inadequate pediatric-sized equipment and medication dosing errors under stress","B. No specific pediatric risks exist in MCI response","C. Adult equipment works identically well for pediatric patients","D. Medication dosing is simpler for children than adults"],"correct":0,"rationale":"Without specific pediatric MCI planning, equipment sizing and medication dosing errors become more likely under high-stress conditions.","difficulty":"Medium"},{"id":"c14_q12","question":"How should family reunification after a pediatric-involving MCI generally be handled?","options":["A. Through an established incident reunification process coordinated by incident command/emergency management","B. Ad hoc matching by individual field providers during active response","C. Reunification is not a priority during MCI response","D. Only law enforcement should be involved, with no coordination process"],"correct":0,"rationale":"Reunification is coordinated through an established incident process (tracking systems, designated points) rather than improvised individually.","difficulty":"Medium"},{"id":"c14_q13","question":"What should a field provider do for an unaccompanied child during an MCI?","options":["A. Document identifying information when possible and follow the established incident reunification process","B. Attempt to personally locate the caregiver before continuing triage duties","C. Ignore the child's identification needs entirely","D. Release the child to any adult who claims to be a relative without verification"],"correct":0,"rationale":"Documenting identifying information and following the incident's established reunification process is the appropriate field-level action.","difficulty":"Medium"},{"id":"c14_q14","question":"A triage provider at an MCI applies adult START respiratory rate thresholds to a 2-year-old, missing an abnormal pediatric rate. What does this illustrate?","options":["A. The importance of using JumpSTART's pediatric-specific criteria rather than adult thresholds for children","B. That adult START is equally valid for all ages","C. That respiratory rate is not a useful triage criterion","D. That this child should automatically be triaged as minor"],"correct":0,"rationale":"This scenario demonstrates why JumpSTART's pediatric-specific respiratory rate thresholds exist — using adult criteria on children risks misclassification.","difficulty":"Hard"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"The 'Reassuring' Blood Pressure","presentation":"A 6-year-old boy fell from a bicycle and has an obviously deformed thigh with visible bruising. He is pale and anxious. His blood pressure reads within the normal range for his age, but his heart rate is elevated.","vitals":{"hr":"128 bpm (elevated for age)","bp":"94/62 mmHg (age-normal)","rr":"26 bpm","skin":"Pale, cool"},"question":"How should the 'normal' blood pressure be interpreted?","options":["A: It rules out significant blood loss or shock.","B: It should NOT be reassuring — children compensate well and maintain blood pressure until a large percentage of volume is lost; the tachycardia and pale, cool skin suggest early compensated shock.","C: It means his heart rate reading is inaccurate.","D: It indicates he is anxious only, with no physiologic concern."],"correct":1,"explanation":"Blood pressure is a late sign in pediatric shock. This child's tachycardia and pale, cool skin — despite a numerically normal blood pressure for his age — suggest early compensated shock from his femur fracture, and should prompt close monitoring and volume assessment rather than reassurance from the BP alone.","clinicalPearl":"In children, don't let a 'normal' blood pressure talk you out of what the rest of the exam is telling you."},{"id":"c01_s02","title":"The Screaming Toddler","presentation":"A 2-year-old girl with a fever is screaming and clinging to her mother, arching away whenever you approach with your stethoscope.","vitals":{"temp":"102.6 F","hr":"Elevated, difficult to auscultate due to crying","loc":"Alert, distressed"},"question":"What is the best approach to complete a useful assessment?","options":["A: Separate her from her mother to get a controlled exam.","B: Keep her on her mother's lap, demonstrate the stethoscope on the mother first, and assess from a distance (appearance, work of breathing, color) before hands-on exam.","C: Restrain her firmly to listen to her lungs.","D: Skip the exam since she won't cooperate."],"correct":1,"explanation":"Toddlers fear separation and unfamiliar equipment. Keeping her with her caregiver, demonstrating tools first, and starting with an across-the-room observational assessment (matching the developmental-stage approach in this chapter) both calms the child and yields more reliable findings than forcing a hands-on exam immediately.","clinicalPearl":"With toddlers, the best exam often starts before you ever touch them — watch first, demonstrate second, touch last."},{"id":"c01_s03","title":"Small Loss, Big Percentage","presentation":"A 9 kg infant has been vomiting and having diarrhea for 18 hours. The caregiver estimates about 300 mL of combined fluid loss, which they describe as 'not that much.'","vitals":{"weight":"9 kg","estimated loss":"~300 mL","hr":"elevated","skin":"dry mucous membranes, decreased tears"},"question":"Why is this fluid loss more significant than the caregiver's framing suggests?","options":["A: 300 mL is trivial regardless of the infant's size.","B: A child's absolute circulating blood/fluid volume is small, so 300 mL represents a much larger percentage of this infant's total volume than the same amount would in an adult.","C: Fluid loss is never clinically significant in infants.","D: This amount is only concerning if the infant is over 1 year old."],"correct":1,"explanation":"Because total circulating volume scales with body size, an absolute loss that sounds modest can represent a dangerously large percentage of a small infant's total volume — one of the core anatomic/physiologic reasons children are not small adults when estimating losses.","clinicalPearl":"Always translate an absolute fluid loss into a percentage of THIS child's estimated total volume — the same number means very different things at different weights."}]},"c02":{"chapter":"c02","cases":[{"id":"c02_s01","title":"From the Doorway","presentation":"You enter a home and see a 3-year-old boy sitting quietly in his mother's lap. He is looking around the room, tracking your movement, and reaches for a toy his sister offers. His breathing looks effortless and his skin has a normal pink color.","vitals":{"appearance":"Alert, interactive, tracks movement","wob":"No retractions, no abnormal sounds","circulation":"Normal color"},"question":"What does this PAT pattern suggest, and what should you do next?","options":["A: All three legs normal — this is a reassuring PAT; proceed to a full hands-on primary assessment at a normal pace.","B: This is enough information to clear the child without further assessment.","C: You should immediately begin aggressive interventions given the visit itself is concerning.","D: Skip vital signs since the child looks fine."],"correct":0,"explanation":"All three PAT legs (Appearance, Work of Breathing, Circulation to Skin) appear normal, giving a reassuring general impression. This sets a calmer pace for the encounter, but a full hands-on primary assessment (ABCDE) still follows — the PAT never substitutes for it.","clinicalPearl":"A reassuring PAT buys you time and calm, not an exemption from the primary assessment."},{"id":"c02_s02","title":"Two Legs Down","presentation":"A 5-year-old girl with a history of asthma is sitting in the tripod position, with visible subcostal and intercostal retractions and audible wheezing. She is alert, tracking you, and answering questions appropriately. Her skin color looks normal.","vitals":{"appearance":"Alert, interactive (normal)","wob":"Tripod position, retractions, wheeze (abnormal)","circulation":"Normal color"},"question":"Which PAT category does this pattern suggest, and how urgent is it?","options":["A: CNS/metabolic problem — treat as a neurologic emergency.","B: Respiratory problem (abnormal Work of Breathing with normal Appearance and Circulation) — urgent but with intact compensation reflected by her normal Appearance.","C: Cardiopulmonary failure — the most urgent category.","D: A normal, reassuring PAT."],"correct":1,"explanation":"Only the Work of Breathing leg is abnormal here; her Appearance remaining normal suggests she is still compensating well despite significant respiratory effort. This points to a respiratory category requiring urgent treatment (e.g., bronchodilator therapy) rather than the higher-urgency multi-leg patterns.","clinicalPearl":"A normal Appearance despite visible respiratory effort is a relatively reassuring sign — it means the compensation is still working."},{"id":"c02_s03","title":"All Three Legs Abnormal","presentation":"A 7-month-old infant is limp and unresponsive to his mother's voice, with slow, irregular, gasping-appearing breaths and dusky, mottled skin.","vitals":{"appearance":"Limp, unresponsive (abnormal)","wob":"Irregular, gasping breaths (abnormal)","circulation":"Dusky, mottled (abnormal)"},"question":"What does this pattern indicate, and what is the priority?","options":["A: A mild, self-limited illness requiring routine transport.","B: Cardiopulmonary failure — abnormal findings across all three PAT legs — the highest-acuity pattern, requiring the most immediate, aggressive response.","C: A purely circulatory problem with no respiratory component.","D: This pattern is not clinically meaningful without vital signs first."],"correct":1,"explanation":"Abnormal findings across all three PAT legs (Appearance, Work of Breathing, Circulation to Skin) together indicate cardiopulmonary failure, the most severe PAT pattern, demanding the most urgent, simultaneous life-saving response — this recognition happens before any vital sign is even obtained.","clinicalPearl":"All three legs abnormal is the PAT's loudest alarm — it means go now, with everything, before you've measured a single vital sign."}]},"c03":{"chapter":"c03","cases":[{"id":"c03_s01","title":"Fix It As You Find It","presentation":"A 4-year-old is struck by a car at low speed. Your PAT shows abnormal Appearance and Work of Breathing. On primary assessment, you find her airway is partially obstructed by blood and secretions from a facial injury.","vitals":{"appearance":"Lethargic (abnormal)","wob":"Gurgling respirations (abnormal)","airway":"Partially obstructed"},"question":"What should you do upon finding the airway obstruction during the 'A' step?","options":["A: Note the finding and continue to assess breathing, circulation, disability, and exposure first.","B: Clear the airway immediately before continuing to the next steps of the primary assessment.","C: Wait until the secondary assessment to address the airway.","D: Only address it if her oxygen saturation is also abnormal."],"correct":1,"explanation":"Life threats found during the primary assessment are treated the moment they are identified — an obstructed airway found at 'A' is cleared immediately before proceeding to 'B' and beyond, rather than completing the checklist first.","clinicalPearl":"ABCDE is not a form to fill out top to bottom — it's an ordered scan that stops for treatment the instant it finds a problem."},{"id":"c03_s02","title":"Setting the Pace","presentation":"You respond to two children after a household chemical exposure. The PAT on the first child shows all three legs normal; the PAT on the second child shows abnormal Appearance, Work of Breathing, and Circulation to Skin together.","vitals":{"child1_PAT":"All three legs normal","child2_PAT":"All three legs abnormal (cardiopulmonary failure pattern)"},"question":"How should the primary assessment differ between these two children?","options":["A: Identically — the PAT has no bearing on how the primary assessment proceeds.","B: The second child's primary assessment should proceed immediately and rapidly, potentially with simultaneous interventions, while the first child's primary assessment can proceed at a calmer, still-thorough pace.","C: Only the first child needs a primary assessment.","D: Only the second child needs a primary assessment."],"correct":1,"explanation":"The PAT sets the urgency and pace for the primary assessment that follows. The child with the cardiopulmonary-failure PAT pattern needs an immediate, rapid, simultaneous-intervention approach, while the child with a reassuring PAT can be assessed thoroughly but at a normal pace — both still receive a full ABCDE exam.","clinicalPearl":"The PAT is your triage dial for the primary assessment's speed — it never decides whether the exam happens, only how fast."},{"id":"c03_s03","title":"The Priority Decision","presentation":"After completing ABCDE on an 8-year-old with a minor laceration and stable vital signs across the board, you must decide how to proceed.","vitals":{"airway":"Patent","breathing":"Normal rate/effort","circulation":"Normal perfusion, controlled minor bleeding","disability":"Alert, normal","exposure":"Minor laceration only"},"question":"What is the correct next step based on this primary assessment?","options":["A: Assign a high-priority designation and initiate rapid transport with ALS intercept.","B: Assign a low-priority designation, allowing a more complete secondary assessment (history, focused exam) on scene.","C: Skip the secondary assessment entirely since ABCDE is complete.","D: Repeat the PAT indefinitely instead of proceeding."],"correct":1,"explanation":"Stable findings across the ABCDE primary assessment support a low-priority designation, which allows time for a more complete secondary assessment (history-taking, focused exam) to be performed on scene rather than rushing to transport.","clinicalPearl":"The primary assessment's real output is a priority label — 'high' means move fast and treat en route; 'low' means you can afford the thorough secondary assessment on scene."}]},"c04":{"chapter":"c04","cases":[{"id":"c04_s01","title":"Asking the Teenager Directly","presentation":"A 15-year-old girl comes to the ambulance with her mother after a syncopal episode at school. The mother immediately begins answering all your questions about symptoms and events before the patient can speak.","vitals":{"hr":"88 bpm","bp":"108/68 mmHg","loc":"Alert, oriented"},"question":"What is the best approach to history-taking here?","options":["A: Rely entirely on the mother's account since she is the legal guardian.","B: Direct questions to the teenager herself, using the mother's account to supplement rather than replace her report — and consider some private conversation time.","C: Ignore the mother's input entirely.","D: Skip history-taking since vitals are stable."],"correct":1,"explanation":"Adolescents should be asked directly about their symptoms whenever possible; the caregiver's account supplements rather than replaces the patient's own report. Given adolescents' preference for privacy, some interview time apart from the caregiver may also yield more complete and honest information (e.g., about substance use, stress, or other sensitive factors relevant to a syncopal episode).","clinicalPearl":"A teenager who can speak for herself should be given the chance to — caregivers supplement the history, they don't own it."},{"id":"c04_s02","title":"Keeping Mom in the Room","presentation":"A 3-year-old boy needs an IV start for dehydration. A new EMT suggests asking the mother to step out 'so she doesn't get upset.' The mother is calm and has been comforting the child effectively throughout the encounter.","vitals":{"child":"Anxious but calming with mother present","mother":"Calm, cooperative"},"question":"What does family-centered care recommend here?","options":["A: Ask the mother to leave to avoid her becoming upset.","B: Keep the calm, cooperative mother present during the procedure — family-centered care treats her as a partner, and her presence is likely to reduce the child's distress without slowing the procedure.","C: Only allow the father to be present, not the mother.","D: Perform the procedure in a separate room without any caregiver present."],"correct":1,"explanation":"Family-centered care supports keeping a calm, cooperative caregiver present during most procedures, including IV starts — this typically reduces the child's distress and improves cooperation without meaningfully slowing the procedure. Removing a helpful caregiver by default (rather than for a specific clinical reason) works against this principle.","clinicalPearl":"A calm caregiver is usually your best assistant during a procedure, not an obstacle to remove."},{"id":"c04_s03","title":"Interpreting for the Family","presentation":"A family speaking only Spanish brings in their feverish 6-year-old. Their 10-year-old sibling, who speaks some English, offers to translate for the parents.","vitals":{"patient":"6-year-old, febrile","family":"Spanish-speaking only","sibling":"10-year-old, offers to translate"},"question":"What is the correct approach to communication in this scenario?","options":["A: Use the 10-year-old sibling as the interpreter since they volunteered.","B: Use a professional interpretation service rather than relying on a child family member to interpret medical information.","C: Proceed without any interpretation since the situation seems routine.","D: Wait for the family to learn English before continuing care."],"correct":1,"explanation":"Relying on a child — especially one who is also a family member of the patient — to interpret medical information is inappropriate and risks miscommunication and undue burden on the child. Professional interpretation services should be used to ensure accurate, appropriate communication with the family.","clinicalPearl":"A willing child interpreter is still the wrong interpreter — professional services protect both accuracy and the child from an inappropriate role."}]},"c05":{"chapter":"c05","cases":[{"id":"c05_s01","title":"The 'Calmer' Toddler","presentation":"A 2-year-old with a two-day history of cough and wheeze was working very hard to breathe 20 minutes ago (retractions, tachypnea). On reassessment, the retractions look less pronounced and the child seems 'calmer,' though still tachypneic and now slightly less interactive.","vitals":{"hr":"168 bpm","rr":"44/min","spo2":"93% room air","appearance":"Less interactive than 20 minutes ago"},"question":"How should this change be interpreted?","options":["A: The child is genuinely improving; no action is needed.","B: The apparent decrease in work of breathing combined with decreasing interactivity suggests exhaustion and impending failure, not improvement — escalate support immediately.","C: Discharge from EMS care since the child looks calmer.","D: Wait for SpO2 to fall further before acting."],"correct":1,"explanation":"A previously struggling child who appears 'calmer' but is also less interactive, still tachypneic, and hypoxic is showing signs of exhaustion, not genuine improvement. This should prompt immediate escalation of respiratory support rather than reassurance.","clinicalPearl":"'Calmer' after hard work of breathing is a red flag until proven otherwise — check mental status and oxygenation before you relax."},{"id":"c05_s02","title":"Stridor at Rest","presentation":"A 3-year-old with a barking cough develops audible stridor at rest, with mild suprasternal retractions. The child is alert, interactive, and consolable in the caregiver's lap.","vitals":{"hr":"128 bpm","rr":"32/min","spo2":"97% room air","appearance":"Alert, interactive"},"question":"What category of respiratory compromise does this represent, and what is the appropriate field approach?","options":["A: Lower airway disease — give a nebulized bronchodilator.","B: Upper airway obstruction — keep the child calm and in a position of comfort with the caregiver, minimize agitation, and monitor closely.","C: Lung tissue disease — expect crackles and diminished breath sounds.","D: Disordered control of breathing — expect an irregular respiratory pattern."],"correct":1,"explanation":"Stridor with a barking cough is classic for upper airway obstruction (e.g., croup). Since the child is still compensating well (alert, adequate oxygenation), the priority is keeping the child calm — agitation can worsen upper airway obstruction — with close monitoring rather than aggressive intervention.","clinicalPearl":"For upper airway obstruction, calm beats aggressive — crying and agitation can worsen the obstruction."},{"id":"c05_s03","title":"From Distress to Failure","presentation":"A 6-month-old with bronchiolitis has been tachypneic with nasal flaring and grunting for the past hour. On your arrival, the infant is now cyanotic around the lips, limp, and breathing irregularly with long pauses.","vitals":{"hr":"70 bpm","rr":"irregular with apneic pauses","spo2":"80% room air","appearance":"Limp, cyanotic"},"question":"What is the correct immediate field management?","options":["A: Continue observation since bronchiolitis is usually self-limited.","B: Provide assisted ventilation with bag-mask and high-flow oxygen, and initiate rapid transport.","C: Administer an oral bronchodilator and reassess in 15 minutes.","D: Withhold intervention until arrival at the hospital."],"correct":1,"explanation":"Cyanosis, limp appearance, bradycardia, and an irregular breathing pattern with apneic pauses indicate respiratory failure. This requires immediate assisted ventilation with high-flow oxygen and rapid transport; deeper arrest-specific airway management is covered by the PALS reviewer if arrest occurs.","clinicalPearl":"Bradycardia in a sick infant is a respiratory problem until proven otherwise — ventilate first."}]},"c06":{"chapter":"c06","cases":[{"id":"c06_s01","title":"Normal Blood Pressure, Abnormal Perfusion","presentation":"A 4-year-old has had three days of vomiting and diarrhea. She is irritable, has dry mucous membranes, capillary refill of 3 seconds, and cool extremities. Blood pressure is 92/60 mmHg.","vitals":{"hr":"150 bpm","bp":"92/60 mmHg","capRefill":"3 seconds","appearance":"Irritable"},"question":"How should this presentation be interpreted?","options":["A: No shock is present because the blood pressure is normal.","B: Compensated shock is present — tachycardia and delayed capillary refill indicate poor perfusion despite a normal blood pressure for age.","C: This is decompensated shock since the blood pressure is abnormal.","D: These findings are unrelated and require no action."],"correct":1,"explanation":"Tachycardia, delayed capillary refill, cool extremities, and irritability all indicate poor perfusion — compensated shock — even though the blood pressure remains normal for age. Waiting for hypotension would mean missing shock at a treatable stage.","clinicalPearl":"Normal blood pressure does not rule out shock in a child — it may just mean compensation hasn't failed yet."},{"id":"c06_s02","title":"Warm and Flushed, Not Reassuring","presentation":"A 7-year-old with a high fever is lethargic, with warm, flushed skin, bounding peripheral pulses, and a capillary refill that is brisk but the child remains difficult to arouse.","vitals":{"hr":"160 bpm","temp":"39.8°C","appearance":"Lethargic, difficult to arouse","skin":"Warm, flushed"},"question":"What should this presentation suggest?","options":["A: This cannot be shock since the skin is warm and pulses are bounding.","B: Early septic (distributive) shock, which can present with warm, flushed skin and bounding pulses rather than the cold, mottled pattern of hypovolemic shock.","C: Simple febrile illness requiring only antipyretics.","D: Cardiogenic shock from a primary cardiac problem."],"correct":1,"explanation":"Warm, flushed skin and bounding pulses can be misleadingly reassuring — combined with fever and altered mental status (lethargy), this presentation is consistent with early septic shock, a distributive shock subtype that does not always look like the classic cold, mottled hypovolemic pattern.","clinicalPearl":"Don't let warm skin fool you — early septic shock can look 'well-perfused' on the skin while the brain is already showing signs of poor perfusion."},{"id":"c06_s03","title":"Sudden Hypotension After Trauma","presentation":"A 10-year-old struck by a car has unilateral absent breath sounds on the right, tracheal deviation to the left, tachycardia, and a blood pressure that just dropped to 78/50 mmHg.","vitals":{"hr":"155 bpm","bp":"78/50 mmHg","breathSounds":"Absent on right","trachea":"Deviated left"},"question":"What is the most likely cause of shock, and what is the priority intervention?","options":["A: Hypovolemic shock from external bleeding — apply direct pressure and give fluids.","B: Obstructive shock from a tension pneumothorax — needle decompression per protocol, in addition to supportive care.","C: Anaphylactic shock — administer epinephrine.","D: This is a normal post-traumatic vital sign pattern requiring no intervention."],"correct":1,"explanation":"Unilateral absent breath sounds, tracheal deviation, and hypotension after trauma are classic for tension pneumothorax causing obstructive shock. Needle decompression per protocol is the priority intervention to relieve the obstruction, alongside oxygen and rapid transport.","clinicalPearl":"Tracheal deviation plus absent breath sounds plus shock after trauma — think tension pneumothorax and decompress, don't just give fluids."}]},"c07":{"chapter":"c07","cases":[{"id":"c07_s01","title":"The Bradycardic, Blue Infant","presentation":"A 2-month-old is found limp and dusky by a caregiver. Heart rate is 60 bpm, respiratory effort is minimal, and the infant is unresponsive to stimulation.","vitals":{"hr":"60 bpm","rr":"minimal effort","color":"Dusky/cyanotic","appearance":"Unresponsive"},"question":"What is the correct first priority?","options":["A: Immediately prepare for cardioversion.","B: Support oxygenation and ventilation first — bradycardia in this context is most likely due to hypoxia.","C: Give an antiarrhythmic medication before assessing breathing.","D: Wait for a 12-lead ECG before intervening."],"correct":1,"explanation":"A dusky, bradycardic infant with poor respiratory effort should be treated as a hypoxia-driven bradycardia — support oxygenation and ventilation immediately, since this is the most common and rapidly reversible cause. Rhythm-specific interventions are addressed in the PALS reviewer if bradycardia persists despite adequate oxygenation/ventilation.","clinicalPearl":"Bradycardia plus cyanosis plus poor effort in an infant is a breathing problem first — fix oxygenation before assuming a primary cardiac cause."},{"id":"c07_s02","title":"Sudden Rapid Heart Rate, No Trigger","presentation":"A previously well 4-month-old is fussy and poorly feeding. The monitor shows a heart rate fixed at 230 bpm that does not change with stimulation. There is no fever, and the caregiver reports no illness.","vitals":{"hr":"230 bpm, fixed","temp":"Afebrile","appearance":"Fussy, poor feeding"},"question":"What does this presentation most likely represent?","options":["A: Sinus tachycardia from an underlying fever.","B: Supraventricular tachycardia (SVT) — a fixed, very rapid rate with no clear trigger that does not vary with stimulation.","C: A normal finding in a 4-month-old.","D: Bradycardia."],"correct":1,"explanation":"A fixed, very rapid heart rate (over 220 bpm in an infant) that does not vary with stimulation, without a fever or other clear trigger, is characteristic of SVT rather than sinus tachycardia. This warrants rapid transport and notification of the receiving facility; specific rhythm management is detailed in the PALS reviewer.","clinicalPearl":"No fever, no clear cause, and a rate that won't budge with stimulation — think SVT, not sinus tachycardia."},{"id":"c07_s03","title":"Known Heart Disease, Different Baseline","presentation":"An 8-year-old with a history of repaired congenital heart disease is brought in after a minor fall, mildly anxious. Pulse oximetry reads 89%. The caregiver states this is normal for the child.","vitals":{"spo2":"89% (caregiver states this is baseline)","hr":"110 bpm","appearance":"Mildly anxious, otherwise well"},"question":"How should the SpO2 reading be interpreted?","options":["A: This must be treated as severe hypoxia requiring aggressive intervention regardless of history.","B: Compare it to the child's known personal baseline as reported by the caregiver — children with congenital heart disease may normally run lower saturations.","C: Ignore the reading since pulse oximetry is unreliable in children with heart disease.","D: Assume the caregiver is mistaken and treat as an emergency."],"correct":1,"explanation":"Children with congenital heart disease may have a baseline oxygen saturation that differs from typical norms. Providers should ask about and compare findings to the child's known baseline rather than assuming abnormality outright, while still monitoring for any acute change from that baseline.","clinicalPearl":"Always ask 'what's normal for this child?' when there's known congenital heart disease — a number that looks alarming may be their everyday baseline."}]},"c08":{"chapter":"c08","cases":[{"id":"c08_s01","title":"The Lethargic Toddler","presentation":"A 2-year-old is found unusually quiet and difficult to arouse by a caregiver. No fever is reported. A glucose meter is available on the unit.","vitals":{"avpu":"Responds to voice only","temp":"Afebrile","appearance":"Poor eye contact, decreased interactiveness"},"question":"What is the appropriate next step?","options":["A: Transport without further assessment since no fever is present.","B: Check the child's blood glucose, since hypoglycemia is a common and rapidly reversible cause of altered mental status.","C: Assume the child is simply tired and reassess in 30 minutes.","D: Withhold any intervention until arrival at the hospital."],"correct":1,"explanation":"Any altered child should have a glucose check when a meter is available, since hypoglycemia is common in children and rapidly reversible. This should be done promptly rather than assuming a benign cause without checking.","clinicalPearl":"Glucose check first, every time, when altered mental status is present and a meter is available — it's fast, easy, and can immediately explain (and treat) the problem."},{"id":"c08_s02","title":"Seizure at the Six-Minute Mark","presentation":"A 3-year-old has been having generalized tonic-clonic seizure activity for 6 minutes with no sign of stopping. The caregiver reports no fever and this has never happened before.","vitals":{"duration":"6 minutes and ongoing","temp":"Afebrile","activity":"Generalized tonic-clonic, continuous"},"question":"What does this presentation represent, and what is the priority?","options":["A: A simple febrile seizure requiring only observation.","B: Status epilepticus — a time-critical emergency requiring rapid escalation of care and transport.","C: A normal pediatric seizure pattern requiring no escalation.","D: This should be timed for another 10 minutes before taking any action."],"correct":1,"explanation":"A seizure lasting more than 5 minutes meets the definition of status epilepticus, a time-critical emergency. This is not a simple febrile seizure (there is no fever, and duration alone already exceeds the definition), and requires immediate escalation of care; benzodiazepine dosing is addressed in the PALS reviewer.","clinicalPearl":"Five minutes is the line — once a seizure crosses it, treat it as status epilepticus and escalate, don't keep waiting."},{"id":"c08_s03","title":"Bulging Fontanelle After a Fall","presentation":"A 5-month-old fell from a changing table an hour ago. The infant is increasingly difficult to arouse, has a bulging fontanelle, and now has an irregular breathing pattern.","vitals":{"fontanelle":"Bulging","rr":"Irregular pattern","appearance":"Decreasing responsiveness"},"question":"What should this presentation prompt, and what should be avoided?","options":["A: Suspicion for increased intracranial pressure — avoid hypoxia and hypotension, position to avoid jugular compression, and transport rapidly.","B: No specific concern since infants commonly have bulging fontanelles.","C: Aggressive fluid restriction and permissive hypoxia.","D: Delay transport until the fontanelle returns to normal."],"correct":0,"explanation":"A bulging fontanelle with decreasing responsiveness and an irregular respiratory pattern after a fall suggests increased intracranial pressure. Field priorities are avoiding hypoxia and hypotension (both worsen secondary brain injury), positioning to avoid jugular venous compression, and rapid transport.","clinicalPearl":"After head trauma, a bulging fontanelle plus a change in responsiveness is not incidental — treat it as rising intracranial pressure and protect the brain from secondary injury."}]},"c09":{"chapter":"c09","cases":[{"id":"c09_s01","title":"The Soft Abdomen","presentation":"A 6-year-old was struck by a bicycle handlebar in the abdomen 20 minutes ago. The abdomen appears soft and non-tender on exam, but the child is mildly tachycardic with slightly delayed capillary refill.","vitals":{"hr":"132 bpm","capRefill":"2.5 seconds","abdomen":"Soft, non-tender"},"question":"What is the appropriate interpretation and next step?","options":["A: The soft, non-tender abdomen rules out significant injury — no further concern needed.","B: The soft abdomen does not rule out significant occult abdominal injury, and the tachycardia/delayed capillary refill are early perfusion warning signs — treat as potential internal hemorrhage and transport promptly.","C: Reassess again in one hour before deciding on transport.","D: Only treat if the blood pressure drops."],"correct":1,"explanation":"A soft, non-tender abdomen can be falsely reassuring in pediatric blunt abdominal trauma, especially early on. The tachycardia and delayed capillary refill are perfusion findings that may be the first clue to significant blood loss, well before hypotension develops.","clinicalPearl":"Soft abdomen plus subtle perfusion changes after blunt trauma — trust the perfusion signs, not the abdominal exam alone."},{"id":"c09_s02","title":"A Single Rib Fracture","presentation":"An 8-year-old was involved in a moderate-speed motor vehicle collision. Exam reveals one tender rib on the left with normal breath sounds bilaterally and stable vital signs.","vitals":{"hr":"104 bpm","spo2":"98%","breathSounds":"Equal bilaterally"},"question":"How should this single rib fracture be interpreted?","options":["A: A single rib fracture with normal breath sounds means no further concern is needed.","B: Any rib fracture in a child signals a high-energy mechanism and warrants suspicion for underlying pulmonary or cardiac injury, even with currently reassuring findings.","C: Rib fractures are common and unimportant in pediatric trauma.","D: This finding should be disregarded since vital signs are stable."],"correct":1,"explanation":"Because a child's ribcage is pliable and normally resists fracture, any rib fracture indicates a high-energy mechanism and should raise suspicion for significant underlying chest injury (e.g., pulmonary contusion), even when initial vitals and breath sounds appear reassuring.","clinicalPearl":"In a child, a rib fracture is a marker of high-energy transfer — treat it as a warning sign, not a minor injury."},{"id":"c09_s03","title":"Positioning for Transport","presentation":"A 3-year-old requires spinal motion restriction after a fall from a second-story window. The crew places the child directly flat on a standard adult backboard.","vitals":{"positioning":"Flat on adult backboard, no padding"},"question":"What adjustment should be made to properly maintain spinal alignment?","options":["A: No adjustment needed — the standard backboard is appropriate as-is.","B: Add padding under the torso (not just the head) to compensate for the child's proportionally larger head and maintain neutral spinal alignment.","C: Remove all padding to keep the child as flat as possible.","D: Place padding only under the head."],"correct":1,"explanation":"A young child's proportionally larger head forces the neck into flexion when lying flat on a standard adult backboard. Padding under the torso (not just the head) helps achieve neutral spinal alignment during spinal motion restriction.","clinicalPearl":"Big head, flat board, flexed neck — pad the torso to correct for the mismatch and keep the spine neutral."}]},"c10":{"chapter":"c10","cases":[{"id":"c10_s01","title":"The Asymptomatic Battery Swallow","presentation":"A caregiver reports witnessing their 18-month-old put a small, round button battery from a remote control into their mouth about 30 minutes ago. The child appears completely well, playing normally with no distress.","vitals":{"appearance":"Well-appearing, playing normally","distress":"None currently"},"question":"What is the correct approach given the child's current well appearance?","options":["A: Reassure the caregiver and recommend no further action since the child is asymptomatic.","B: Treat this as a time-critical emergency requiring rapid transport and hospital notification, regardless of the child's current symptoms.","C: Advise the caregiver to monitor at home for 24 hours and call back only if symptoms develop.","D: Induce vomiting on scene to remove the battery."],"correct":1,"explanation":"Button battery ingestion is treated as time-critical regardless of current symptoms, because a lodged battery can cause severe electrical-current tissue injury within hours even in a child who currently appears completely well.","clinicalPearl":"A button battery doesn't wait for symptoms to cause damage — treat every suspected ingestion as urgent, no matter how the child looks."},{"id":"c10_s02","title":"Found in a Hot Car","presentation":"A 2-year-old is found in a car that has been parked in direct sun for 45 minutes. The child is lethargic, flushed, and hot to the touch, with dry mucous membranes.","vitals":{"temp":"40.5°C (104.9°F)","appearance":"Lethargic","skin":"Hot, flushed, dry"},"question":"What is the priority field management?","options":["A: Transport without any active cooling measures.","B: Remove from the hot environment immediately, begin active cooling measures, support ABCs, and transport promptly.","C: Cover the child in warm blankets to prevent shivering.","D: Delay treatment until arrival at the hospital."],"correct":1,"explanation":"This presentation is consistent with severe heat illness/heat stroke. Priority management includes immediate removal from the hot environment, active cooling measures, ABC support, and prompt transport — vehicle interiors can become life-threatening within minutes, and this presentation reflects that danger.","clinicalPearl":"A hot, flushed, altered child from a hot car needs cooling now, not just transport — every minute of delay matters."},{"id":"c10_s03","title":"The Well-Appearing Pool Rescue","presentation":"A 4-year-old was briefly submerged in a backyard pool and pulled out coughing but breathing well, with normal oxygen saturation and no distress. The family asks if transport is really necessary since the child 'seems totally fine now.'","vitals":{"spo2":"99% room air","rr":"Normal","appearance":"Alert, playful"},"question":"What is the correct recommendation?","options":["A: No transport is needed since the child currently appears completely normal.","B: Recommend transport for observation, since pulmonary complications after submersion can evolve over hours even in a currently well-appearing child.","C: Recommend transport only if the child develops a cough.","D: Recommend the family monitor at home overnight instead of transport."],"correct":1,"explanation":"Even a well-appearing child after a submersion event should be transported for observation, since drowning-related pulmonary complications can develop over the following hours despite an initially reassuring presentation.","clinicalPearl":"'Fine right now' isn't the same as 'fine' after a submersion — observation catches delayed pulmonary complications before they become dangerous."}]},"c11":{"chapter":"c11","cases":[{"id":"c11_s01","title":"The Vigorous Newborn","presentation":"You arrive to assist with an unplanned home delivery. The term newborn is immediately crying vigorously, with good tone and pink color.","vitals":{"gestation":"Term","tone":"Good","cry":"Vigorous"},"question":"What is the appropriate management for this newborn?","options":["A: Move the newborn to a warmer for the initial steps of stabilization.","B: The newborn can stay with the mother for routine care — dry, warm, and skin-to-skin.","C: Begin positive-pressure ventilation as a precaution.","D: Perform routine deep suctioning before any other action."],"correct":1,"explanation":"All three initial questions (term gestation, good tone, breathing/crying) are answered yes, so the newborn can remain with the mother for routine care rather than being moved to a warmer for stabilization steps.","clinicalPearl":"Term, good tone, vigorous cry — three yeses means routine care with mom, not intervention."},{"id":"c11_s02","title":"The Limp, Quiet Newborn","presentation":"A newborn delivered five minutes ago is limp, not crying, and has poor tone. The newborn is wet and uncovered on the bed.","vitals":{"tone":"Poor","cry":"None","color":"Pale"},"question":"What is the correct initial management sequence?","options":["A: Leave the newborn with the mother and reassess in 10 minutes.","B: Move to a warmer and begin the initial steps: provide warmth, position the airway, clear secretions if needed, dry, and stimulate.","C: Begin chest compressions immediately.","D: Delay any action until a full assessment is complete."],"correct":1,"explanation":"Poor tone and absence of crying are 'no' answers to the initial questions, indicating the newborn should be moved to a warmer to begin the initial steps of stabilization — warmth, airway positioning, secretion clearing if needed, drying, and stimulation — with warmth being a particular priority since the newborn is currently wet and uncovered.","clinicalPearl":"Wet, limp, and quiet — get this newborn to the warmer and start the initial steps without delay; heat loss is happening right now."},{"id":"c11_s03","title":"Persistent Bradycardia Despite Ventilation","presentation":"After the initial steps, a newborn remains apneic with a heart rate of 90 bpm. Positive-pressure ventilation is started. After 30 seconds of effective PPV, the heart rate is reassessed at 50 bpm.","vitals":{"hrBeforePPV":"90 bpm","hrAfter30secPPV":"50 bpm"},"question":"What is the correct next step?","options":["A: Continue PPV alone without adding any other intervention.","B: Begin chest compressions coordinated with continued PPV, since the heart rate remains below 60 bpm despite effective ventilation.","C: Stop resuscitation efforts.","D: Switch to abdominal thrusts."],"correct":1,"explanation":"Because the heart rate remains below 60 bpm despite 30 seconds of effective PPV, chest compressions are added, coordinated with continued ventilation, per the newborn resuscitation sequence.","clinicalPearl":"Ventilation first, always — but once you've given it 30 good seconds and the heart rate is still under 60, add compressions."}]},"c12":{"chapter":"c12","cases":[{"id":"c12_s01","title":"The Non-Mobile Infant's Fracture","presentation":"A caregiver reports their 3-month-old 'rolled off the changing table and broke their arm.' The infant shows no signs of being able to roll independently on exam or per developmental history.","vitals":{"age":"3 months","developmentalStage":"Not yet rolling independently"},"question":"How should this history be evaluated?","options":["A: Accept the history as given since falls are common in infants.","B: Recognize the inconsistency between the stated mechanism and the infant's developmental stage, document objectively, and report through appropriate channels.","C: Confront the caregiver immediately about the inconsistency.","D: Ignore the finding since a single detail should not raise concern."],"correct":1,"explanation":"A 3-month-old is not developmentally capable of rolling independently, making this history inconsistent with the injury mechanism. This should be documented objectively (exact quotes, findings) and reported through appropriate mandatory-reporting channels — not directly confronted on scene.","clinicalPearl":"When the story doesn't match the child's developmental stage, document the facts and report — don't accuse, and don't dismiss."},{"id":"c12_s02","title":"Changing History Between Caregivers","presentation":"One caregiver tells you the child 'fell down the stairs,' while another caregiver on scene separately says the child 'fell off a bike.' The child has a significant head injury.","vitals":{"history":"Inconsistent between two caregivers"},"question":"What should this inconsistency prompt?","options":["A: Dismissal, since caregivers often misremember details under stress.","B: Objective documentation of both accounts as given, continued standard medical care, and reporting through appropriate channels given the inconsistency.","C: Immediate accusation of one caregiver of lying.","D: Refusal to transport until the story is clarified."],"correct":1,"explanation":"A history that changes between different caregivers is a recognized concern-raising factor. The appropriate response is to document both accounts objectively and exactly as given, continue providing standard medical care, and report the inconsistency through appropriate channels — not to accuse anyone directly on scene or delay necessary care.","clinicalPearl":"Two different stories from two different caregivers is worth documenting precisely — let the receiving team and reporting process sort out the discrepancy."},{"id":"c12_s03","title":"Delay in Seeking Care","presentation":"A child has a fracture that appears, on exam, to be several days old, but the caregiver states the injury 'just happened this morning.'","vitals":{"injury":"Fracture with signs consistent with several days' healing","reportedTiming":"Said to have occurred this morning"},"question":"What should this discrepancy prompt?","options":["A: No action, since exact injury timing is often hard to determine.","B: Objective documentation of the discrepancy between exam findings and reported timing, continued care, and reporting through appropriate channels.","C: Immediate confrontation of the caregiver about the inconsistency.","D: Assumption that the caregiver caused the injury."],"correct":1,"explanation":"A delay in seeking care that is inconsistent with the reported timeline is a recognized concern-raising finding. The correct response is objective documentation of the discrepancy (exam findings vs. reported history), continued appropriate medical care, and reporting through the correct channel — without directly accusing the caregiver or assuming intent.","clinicalPearl":"An injury that looks older than the story suggests is a documentation-and-report finding, not a confrontation cue."}]},"c13":{"chapter":"c13","cases":[{"id":"c13_s01","title":"The Plugged Tracheostomy","presentation":"A 5-year-old with a chronic tracheostomy suddenly develops increased work of breathing and desaturation. The caregiver reports the tube was working fine an hour ago.","vitals":{"spo2":"85% (baseline reported as 98%)","appearance":"Increased work of breathing"},"question":"What is the correct first troubleshooting step?","options":["A: Immediately remove and replace the tracheostomy tube without any other assessment.","B: Attempt suctioning first to clear a possible mucus plug, the most common cause of sudden tracheostomy-related distress.","C: Transport without attempting any field intervention.","D: Cover the tracheostomy stoma completely and ventilate through the mouth instead."],"correct":1,"explanation":"Mucus plugging is the most common cause of sudden respiratory distress in a child with a tracheostomy, so suctioning is the appropriate first troubleshooting step, before considering tube replacement if suctioning does not resolve the problem.","clinicalPearl":"Suction first for sudden trach distress — it's the most common fixable cause and the fastest first step."},{"id":"c13_s02","title":"Headache and Vomiting With a Known Shunt","presentation":"A 6-year-old with a history of a VP shunt for hydrocephalus presents with a severe headache, repeated vomiting, and increasing lethargy over the past few hours.","vitals":{"appearance":"Increasingly lethargic","symptoms":"Headache, repeated vomiting"},"question":"What should this presentation suggest, and what is the appropriate field management?","options":["A: A benign viral illness requiring only supportive care at home.","B: Possible VP shunt malfunction with increased intracranial pressure — apply standard increased-ICP precautions and transport rapidly.","C: A feeding intolerance related to a G-tube.","D: No action needed since the child has a shunt and this is expected."],"correct":1,"explanation":"Headache, vomiting, and altered mental status in a child with a known VP shunt should raise strong suspicion for shunt malfunction with resulting increased intracranial pressure. Field management includes standard increased-ICP precautions (avoiding hypoxia/hypotension, appropriate positioning) and rapid transport, since shunt-specific correction is a hospital-level intervention.","clinicalPearl":"Known shunt plus headache, vomiting, and lethargy is shunt malfunction until proven otherwise — treat it as a rising-ICP emergency."},{"id":"c13_s03","title":"A Saturation That Isn't What It Seems","presentation":"A 4-year-old with chronic lung disease and home oxygen dependence has a pulse oximetry reading of 90%. The caregiver states this is the child's normal baseline saturation on room air with their usual supplemental oxygen in place.","vitals":{"spo2":"90% (caregiver-reported baseline)","appearance":"Comfortable, interactive"},"question":"How should this finding be interpreted?","options":["A: As an emergency requiring aggressive escalation regardless of history.","B: As the child's known personal baseline, to be compared against for any acute change rather than judged against typical population norms.","C: As proof that the pulse oximeter is malfunctioning.","D: As irrelevant since the child appears comfortable."],"correct":1,"explanation":"For CSHCN, personal baseline function is the most useful reference point. A caregiver-reported baseline SpO2 of 90% with a comfortable, interactive appearance should be compared against that baseline for any acute deterioration, rather than automatically treated as abnormal by typical pediatric standards.","clinicalPearl":"Ask 'what's normal for this child?' before reacting to a number that would be abnormal in a typically developing child."}]},"c14":{"chapter":"c14","cases":[{"id":"c14_s01","title":"Bypassing the Closer Hospital","presentation":"A 7-year-old with a severe traumatic brain injury is 8 minutes from a general community hospital and 18 minutes from a designated pediatric trauma center. Local protocol specifies pediatric trauma center bypass criteria for this injury severity.","vitals":{"gcs":"8","mechanism":"Severe head trauma"},"question":"What is the appropriate transport decision?","options":["A: Transport to the closer general hospital since it is nearer.","B: Follow local protocol and bypass to the pediatric trauma center, consulting medical direction as needed given the injury severity.","C: Let the family decide the destination.","D: Transport to whichever facility has shorter wait times."],"correct":1,"explanation":"When local protocol specifies pediatric trauma center bypass criteria for a given injury severity, that protocol should guide the transport decision even when a closer general facility is available, since pediatric-specific trauma resources significantly affect outcomes for severe pediatric trauma.","clinicalPearl":"Closer isn't always better for a critically injured child — follow your pediatric-capable destination protocol."},{"id":"c14_s02","title":"Applying JumpSTART at the Scene","presentation":"At a multi-vehicle MCI, a triage provider encounters a 4-year-old who is not walking, is breathing at a rate that would be considered abnormal only by pediatric standards (not adult standards), and has delayed capillary refill.","vitals":{"mobility":"Not walking","rr":"Abnormal for pediatric age, would appear normal by adult standards","capRefill":"Delayed"},"question":"How should this child be triaged?","options":["A: Using adult START respiratory rate thresholds, which would classify the rate as normal.","B: Using JumpSTART's pediatric-specific respiratory rate thresholds, correctly identifying the abnormal rate and assigning an appropriate triage category.","C: By skipping respiratory rate assessment entirely for young children.","D: By assuming all non-ambulatory children are automatically immediate regardless of other findings."],"correct":1,"explanation":"JumpSTART uses pediatric-specific respiratory rate thresholds rather than adult cutoffs. Applying adult START criteria here would misclassify this child as having a normal respiratory rate when, by pediatric standards, it is abnormal — potentially under-triaging a child who needs more urgent care.","clinicalPearl":"A rate that looks 'normal' by adult standards can be abnormal for a 4-year-old — always apply JumpSTART's pediatric thresholds, not adult ones."},{"id":"c14_s03","title":"The Apneic Child With a Pulse","presentation":"During MCI triage, a 6-year-old is found not breathing but has a palpable pulse. A new triage provider is about to categorize the child as expectant immediately.","vitals":{"breathing":"Apneic","pulse":"Present"},"question":"What should happen before this child is categorized as expectant?","options":["A: Categorize as expectant immediately without further intervention, matching adult START protocol for apnea.","B: Give five rescue breaths first, per JumpSTART, since pediatric arrest is often respiratory in origin and may be reversible.","C: Perform two minutes of CPR before reassessing.","D: Wait for additional personnel before taking any action."],"correct":1,"explanation":"JumpSTART specifically includes a step of giving five rescue breaths to an apneic child with a pulse before categorizing as expectant, reflecting that pediatric respiratory arrest is often reversible with ventilation alone — a key difference from adult START, where apnea alone typically leads directly to an expectant categorization.","clinicalPearl":"Apneic plus a pulse in a child means five rescue breaths first — don't skip straight to expectant like you would under adult START."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"Applying Anatomic/Developmental Context to Any Pediatric Encounter","description":"The foundational sequence for interpreting any pediatric finding in age- and development-appropriate context.","steps":["Identify the child's age band before interpreting any vital sign or exam finding.","Recall the anatomic differences relevant to the presenting complaint (airway: narrow/anterior/subglottic; breathing: high demand/low reserve; circulation: small volume/strong compensation).","Compare vital signs to the age-appropriate normal range, not an adult or generic pediatric reference.","Adapt your communication and exam approach to the child's developmental stage to maximize cooperation and accuracy.","Weigh all findings together (overall gestalt) rather than relying on any single number, especially blood pressure, which is a late sign in pediatric shock."]}]},"c02":{"chapter":"c02","algorithms":[{"id":"c02_alg01","title":"Performing the Pediatric Assessment Triangle","description":"The hands-off, from-the-doorway assessment performed within the first seconds of any pediatric encounter.","steps":["Approach the child without touching; observe from across the room.","Assess Appearance using TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","Assess Work of Breathing: listen for abnormal sounds (stridor, grunting, wheeze, muffled voice); look for abnormal positioning, retractions, nasal flaring, head bobbing.","Assess Circulation to Skin: look for pallor, mottling, or cyanosis compared to the child's baseline, in adequate lighting.","Combine all three legs into a pattern to identify the likely physiologic category and urgency.","Proceed immediately to the full hands-on primary assessment (ABCDE), paced according to the PAT's urgency level."]},{"id":"c02_alg02","title":"PAT Pattern-to-Category Recognition","description":"Translating the combination of abnormal PAT legs into a likely physiologic category.","steps":["Abnormal Appearance only → likely CNS/metabolic problem.","Abnormal Appearance + Work of Breathing → likely respiratory problem.","Abnormal Appearance + Circulation to Skin → likely shock/circulatory problem.","Abnormal Appearance + Work of Breathing + Circulation to Skin → cardiopulmonary failure (highest urgency).","All three legs normal → reassuring general impression; proceed to primary assessment at a routine pace."]}]},"c03":{"chapter":"c03","algorithms":[{"id":"c03_alg01","title":"Pediatric Primary Assessment (ABCDE) Sequence","description":"The hands-on structured exam following the PAT, with immediate treatment of any life threat found.","steps":["Airway: assess patency; open/clear/manage immediately if compromised.","Breathing: assess rate, effort, breath sounds, SpO2; assist ventilation immediately if inadequate.","Circulation: assess pulse, skin perfusion, capillary refill, external bleeding; control hemorrhage and support perfusion immediately if compromised.","Disability: rapid neurologic check (e.g., AVPU), pupils, glucose if altered.","Exposure: assess for injury/rash as needed, then re-cover to maintain warmth.","Assign overall priority (high vs. low acuity) based on combined PAT + ABCDE findings.","Proceed to secondary assessment (history-taking, focused exam) if priority allows, or continue rapid transport/intervention if high priority."]}]},"c04":{"chapter":"c04","algorithms":[{"id":"c04_alg01","title":"History-Taking and Secondary Assessment Sequence","description":"Gathering history and performing a developmentally appropriate exam after the primary assessment.","steps":["Obtain SAMPLE history, asking the child directly when developmentally appropriate and using the caregiver to supplement.","Add pediatric-specific elements: birth/developmental history (infants), immunizations, growth/weight trends.","Choose exam order by development: toe-to-head for infants/toddlers; head-to-toe for school-age/adolescents.","Perform a focused exam (stable/low-priority) or rapid exam (high-priority, often en route).","Apply family-centered care: keep a calm, cooperative caregiver present and involved where feasible.","Adapt communication for special needs: professional interpretation, hearing-impaired accommodations, developmental-difference considerations.","Integrate findings with the PAT and primary assessment to finalize the treatment and transport plan."]}]},"c05":{"chapter":"c05","algorithms":[{"id":"c05_alg01","title":"Categorizing and Managing Pediatric Respiratory Compromise","description":"Field approach to categorizing a respiratory complaint by mechanism and matching treatment accordingly.","steps":["Complete the PAT and primary assessment to identify a respiratory problem.","Listen and look for the category-defining pattern: stridor (upper airway), wheeze with prolonged expiration (lower airway), grunting/crackles/diminished sounds (lung tissue), or irregular pattern without classic sounds (disordered control).","For upper airway obstruction: keep the child calm, position of comfort with caregiver, minimize agitation, avoid invasive exam of the airway in the field.","For lower airway disease: consider nebulized bronchodilator per local protocol, position of comfort, monitor for fatigue.","For lung tissue disease: supplemental oxygen, position of comfort, monitor closely for hypoxia progression.","For disordered control of breathing: identify and address the underlying cause where possible (e.g., naloxone for suspected opioid exposure per protocol), support ventilation as needed.","Reassess PAT and vital signs frequently for any transition from distress toward failure."]},{"id":"c05_alg02","title":"Recognizing and Responding to Impending Respiratory Failure","description":"Sequence for identifying early warning signs of failure and escalating support before deterioration is severe.","steps":["Reassess a child in respiratory distress at frequent intervals, not just once.","Watch for new or worsening grunting.","Watch for decreasing work of breathing in a child who was previously struggling hard — treat this as a sign of exhaustion, not improvement, until proven otherwise.","Watch for a shift in PAT Appearance from anxious/agitated to lethargic.","Watch for a falling or irregular respiratory rate after a period of tachypnea.","If any of these signs are present, escalate immediately: assist ventilation with BVM and high-flow oxygen, prepare for rapid transport.","Do not wait for SpO2 to fall before escalating support — treat these clinical signs as leading indicators.","For drug-assisted airway management or arrest-specific ventilation parameters, refer to the PALS reviewer."]}]},"c06":{"chapter":"c06","algorithms":[{"id":"c06_alg01","title":"Pediatric Shock Recognition","description":"Sequence for recognizing shock from perfusion findings rather than waiting for hypotension.","steps":["Complete the PAT, noting Appearance and Circulation to Skin.","Assess perfusion directly: capillary refill, skin color/temperature, peripheral pulse quality compared to central pulses, mental status.","Check heart rate for tachycardia out of proportion to fever/anxiety.","Check blood pressure for age — remember normal BP does not exclude shock.","If perfusion findings are abnormal with normal BP: compensated shock — begin treatment now, do not wait for hypotension.","If perfusion findings are abnormal with low BP for age: decompensated shock — treat as a time-critical emergency and escalate immediately.","Reassess perfusion frequently throughout care and transport."]},{"id":"c06_alg02","title":"Category-Matched Shock Treatment","description":"Matching the suspected shock category to the appropriate field intervention.","steps":["Gather history and exam clues to identify the likely shock category: fluid/blood loss (hypovolemic), fever or allergen exposure (distributive), cardiac history (cardiogenic), trauma with unilateral chest findings (obstructive).","Hypovolemic or septic (distributive): administer isotonic fluid bolus per local protocol; reassess perfusion after each bolus.","Anaphylactic (distributive): administer epinephrine as the priority treatment.","Cardiogenic: give fluids cautiously, watching for signs of volume overload; avoid aggressive bolusing.","Obstructive from tension pneumothorax: perform needle decompression per protocol/scope of practice.","In all categories: supplemental oxygen, positioning, keep the child warm, and rapid transport.","For advanced resuscitation and drug dosing depth, refer to the PALS reviewer."]}]},"c07":{"chapter":"c07","algorithms":[{"id":"c07_alg01","title":"Pediatric Bradycardia Field Approach","description":"Sequence for recognizing and initially managing symptomatic pediatric bradycardia in the field.","steps":["Confirm bradycardia for age and assess perfusion (color, capillary refill, mental status).","Assess airway and breathing first — most pediatric bradycardia is caused by hypoxia.","Support oxygenation and ventilation immediately (supplemental oxygen, assisted ventilation if indicated).","Consider other reversible causes if oxygenation/ventilation does not resolve bradycardia: increased vagal tone, hypothermia, increased intracranial pressure.","If bradycardia with poor perfusion persists despite adequate oxygenation and ventilation, this is a time-critical emergency — refer to the PALS reviewer for arrest-level bradycardia algorithms and drug dosing.","Reassess continuously and transport rapidly."]},{"id":"c07_alg02","title":"Distinguishing and Responding to Pediatric Tachycardia","description":"Field approach to differentiating sinus tachycardia from SVT and responding appropriately.","steps":["Identify the heart rate and assess for a clear triggering cause (fever, pain, anxiety, dehydration, shock).","If the rate is variable and a clear trigger is present: treat as sinus tachycardia by addressing the underlying cause (e.g., antipyretics for fever per protocol, fluids for dehydration/shock).","If the rate is fixed, very rapid (often >220 bpm in infants, >180 bpm in older children), and does not vary with stimulation or have a clear trigger: suspect SVT.","For suspected SVT with adequate perfusion: supportive care, monitor closely, rapid transport, notify receiving facility.","For suspected SVT with poor perfusion or altered mental status: this is a time-critical emergency — refer to the PALS reviewer for rhythm-specific interventions (e.g., vagal maneuvers, cardioversion, adenosine dosing).","Reassess frequently during transport."]}]},"c08":{"chapter":"c08","algorithms":[{"id":"c08_alg01","title":"Pediatric Altered Mental Status Field Approach","description":"Sequence for evaluating and managing a child with altered mental status.","steps":["Note Appearance abnormalities on the PAT and confirm level of consciousness using AVPU.","Check blood glucose when a meter is available; treat hypoglycemia per protocol if present.","Work through AEIOU-TIPS to consider reversible causes: Alcohol/substance, Epilepsy/postictal, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke.","Assess for signs of increased intracranial pressure: bulging fontanelle, decreasing consciousness, irregular respirations, Cushing triad.","Support airway, breathing, and circulation as needed; avoid hypoxia and hypotension.","Reassess mental status serially and treat a worsening trend as more concerning than any single value.","Transport rapidly with continuous monitoring."]},{"id":"c08_alg02","title":"Pediatric Seizure Field Management","description":"Sequence for managing an actively seizing child and recognizing status epilepticus.","steps":["Protect the airway with positioning and suction as needed; do not place anything in the mouth.","Protect the child from injury during the seizure.","Check blood glucose when available.","Time the seizure from onset.","If the seizure resolves in under 5 minutes and the child returns to baseline, assess for simple vs complex febrile seizure criteria if fever is present, and transport for evaluation.","If the seizure lasts 5 minutes or longer, or seizures repeat without return to baseline, treat as status epilepticus — a time-critical emergency requiring immediate escalation (refer to PALS reviewer for benzodiazepine dosing).","Reassess airway, breathing, and mental status continuously during and after the seizure."]}]},"c09":{"chapter":"c09","algorithms":[{"id":"c09_alg01","title":"Pediatric Trauma Primary Assessment with Injury-Pattern Awareness","description":"Sequence for assessing a pediatric trauma patient with attention to pediatric-specific anatomic vulnerabilities.","steps":["Ensure scene safety and control obvious hemorrhage.","Perform primary assessment (ABCDE), watching for pediatric patterns: head injury dominance, chest injury without rib fractures, occult abdominal injury despite a soft exam.","Assess perfusion directly (heart rate, capillary refill, skin) rather than relying on blood pressure alone — significant blood loss can occur with a normal BP.","Check the fontanelle (infants) and trend mental status for evolving head injury.","Note any rib fracture as a marker of high-energy mechanism requiring heightened suspicion for chest injury.","Apply selective spinal motion restriction criteria, weighting mechanism and mental status heavily given limited reliability of pain reporting in young children.","Transport rapidly to an appropriate, ideally pediatric-capable, trauma center with continuous reassessment."]},{"id":"c09_alg02","title":"Pediatric Spinal Motion Restriction Positioning","description":"Steps for maintaining neutral spinal alignment in a young child requiring spinal motion restriction.","steps":["Determine the need for spinal motion restriction using selective criteria (mechanism, mental status, distracting injury, midline tenderness, neurologic complaint), weighting mechanism/mental status heavily in young children.","If restriction is indicated, prepare the backboard/device and recognize that a young child's proportionally larger head will force neck flexion if placed flat without adjustment.","Add padding under the torso (not just the head) to raise the torso relative to the head and restore neutral alignment.","Secure the child appropriately for age/size, avoiding excessive restriction that could compromise breathing.","Reassess neurovascular status and comfort throughout transport."]}]},"c10":{"chapter":"c10","algorithms":[{"id":"c10_alg01","title":"Suspected Pediatric Ingestion/Exposure Field Approach","description":"Sequence for assessing and managing a suspected toxic ingestion or exposure.","steps":["Ensure scene safety, especially for exposures involving chemicals or gases.","Identify the substance, amount, and time of exposure when possible; collect containers/pills/remnants to bring to the hospital.","Assess for toxidrome patterns (e.g., altered mental status + pinpoint pupils + respiratory depression suggesting opioid exposure) to guide urgency even without definitive identification.","If button battery ingestion is suspected: treat as a time-critical emergency regardless of current symptoms — rapid transport and hospital notification.","Support airway, breathing, and circulation as needed.","Transport promptly, bringing all identified substances/containers with the patient."]},{"id":"c10_alg02","title":"Pediatric Submersion (Drowning) Field Management","description":"Sequence for managing a child after a submersion event.","steps":["Ensure rescuer safety before entering the water/scene.","Remove the child from the water and begin airway/breathing support immediately — treat hypoxia as the core problem.","Apply spinal motion restriction only if the mechanism suggests trauma (e.g., diving injury).","Assess for hypothermia and begin gentle rewarming if present.","Transport for observation even if the child currently appears well, since pulmonary complications can evolve over hours.","Reassess respiratory status continuously during transport."]}]},"c11":{"chapter":"c11","algorithms":[{"id":"c11_alg01","title":"Newborn Resuscitation Initial Sequence","description":"Field sequence for assessing and stabilizing a newborn immediately after delivery.","steps":["Ask the three initial questions: Term gestation? Good tone? Breathing or crying?","If all three are yes: keep the newborn with the mother for routine care (dry, warm, skin-to-skin).","If any answer is no: move the newborn to a warmer.","Perform the initial steps over about 30 seconds: provide warmth, position the airway, clear secretions only if needed, dry thoroughly, and stimulate.","Reassess breathing and heart rate.","If breathing well and heart rate ≥100 bpm: continue routine care and monitoring.","If apneic/gasping or heart rate <100 bpm: begin positive-pressure ventilation (PPV).","Reassess heart rate after 30 seconds of effective PPV; if <60 bpm, begin chest compressions coordinated with PPV.","For detailed medication dosing and advanced steps, follow local neonatal resuscitation protocol (NRP)."]}]},"c12":{"chapter":"c12","algorithms":[{"id":"c12_alg01","title":"General Field Approach When Maltreatment Is a Concern","description":"General, educational sequence for handling a pediatric call where findings raise concern for possible maltreatment. Not a substitute for local mandatory-reporting law, agency policy, or child protective services training.","steps":["Provide standard medical care for the child's presenting condition without delay.","Note any inconsistency between the stated mechanism, the injury pattern, and the child's developmental capability.","Note any history that changes between tellings or between different caregivers.","Note any unexplained delay in seeking care.","Maintain calm, professional, non-accusatory communication with caregivers throughout.","Document objectively: exact quotes, observed findings, and scene details — avoid speculative conclusions.","Communicate findings factually during receiving-facility handoff.","Report reasonable suspicion through the appropriate channel per local mandatory-reporting law and agency policy, involving medical direction as indicated."]}]},"c13":{"chapter":"c13","algorithms":[{"id":"c13_alg01","title":"Tracheostomy Emergency Troubleshooting","description":"Field sequence for a child with a tracheostomy in respiratory distress.","steps":["Recognize respiratory distress in a child with a tracheostomy and engage the caregiver immediately for baseline and equipment information.","Attempt suctioning through the tracheostomy tube to clear a possible mucus plug.","If suctioning does not resolve distress, check for accidental decannulation (tube fully or partially displaced).","If decannulated, replace with a same-size tracheostomy tube (or appropriately sized endotracheal tube) if trained and equipped.","If the tube cannot be quickly replaced, provide supplemental oxygen/ventilation via the tracheostomy stoma.","Reassess oxygenation and work of breathing continuously; transport rapidly."]},{"id":"c13_alg02","title":"CSHCN Field Assessment Using Caregiver-Reported Baseline","description":"Approach for interpreting findings in a child with special healthcare needs by anchoring to personal baseline.","steps":["Ask the caregiver about the child's usual baseline vital signs, oxygen saturation, mental status, and typical emergency presentation.","Compare current findings to the reported baseline rather than typical population norms.","Identify any acute change from that baseline as the primary marker of a new problem.","Use the caregiver as an active partner in troubleshooting equipment (tracheostomy, ventilator, shunt, feeding tube, central line) throughout the call.","Communicate the child's baseline and any acute changes clearly during receiving-facility handoff."]}]},"c14":{"chapter":"c14","algorithms":[{"id":"c14_alg01","title":"JumpSTART Pediatric MCI Triage","description":"Sequence for triaging a pediatric patient at a mass casualty incident using the JumpSTART algorithm.","steps":["Assess ability to walk. If the child can walk, assign Minor (green) — but note that very young children may not yet walk independently at baseline, so use judgment for infants/toddlers.","If not walking, assess breathing. If not breathing, reposition the airway and reassess.","If breathing resumes after repositioning, assign Immediate (red).","If still not breathing and no pulse is present, assign Expectant (black/gray).","If still not breathing but a pulse is present, give five rescue breaths, then reassess.","If breathing resumes after rescue breaths, assign Immediate (red). If still apneic, assign Expectant (black/gray).","If breathing spontaneously, assess respiratory rate using pediatric-specific thresholds for age. If abnormal, assign Immediate (red).","If respiratory rate is normal for age, assess perfusion (peripheral pulse presence, capillary refill) and mental status using AVPU.","If perfusion or AVPU is abnormal, assign Immediate (red). If both are normal, assign Delayed (yellow).","Continue reassessment as resources and scene conditions allow."]},{"id":"c14_alg02","title":"Pediatric Transport Destination Decision","description":"Sequence for determining appropriate transport destination for a pediatric patient.","steps":["Assess the severity and type of the child's condition.","Identify nearby facilities and their pediatric-specific capabilities (pediatric trauma center, PICU, pediatric surgical subspecialists).","Apply local protocol criteria for pediatric-capable/pediatric trauma center bypass.","Consult medical direction if the decision is unclear or the situation falls outside routine protocol.","Transport to the destination indicated by protocol, even if a closer general facility is available, when bypass criteria are met."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"Age-Banded Normal Pediatric Vital Signs","headers":["Age Group","Heart Rate (bpm)","Respiratory Rate (breaths/min)","Systolic BP (mmHg)","Hypotension Threshold (SBP)"],"rows":[["Neonate (0–28 days)","100–160","30–60","60–80","< 60 mmHg"],["Infant (1–12 months)","100–160","24–40","70–100","< 70 mmHg"],["Toddler (1–3 years)","90–150","20–30","80–100","< 74 mmHg (70 + 2×2)"],["Preschool (4–5 years)","80–140","20–28","85–110","< 78–80 mmHg (70 + 2×[4–5])"],["School-age (6–12 years)","70–120","18–24","90–120","< 82–94 mmHg (70 + 2×[6–12])"],["Adolescent (13–18 years)","60–100","12–20","100–130","< 90 mmHg (adult threshold)"]]},{"id":"c01_t02","title":"Developmental Stage & Communication Approach","headers":["Stage","Typical Fears/Concerns","Assessment Approach"],"rows":[["Infant (0–12 mo)","Separation from caregiver, hunger, discomfort","Assess largely by observation; keep with caregiver; minimize handling"],["Toddler (1–3 yr)","Separation, strangers, unfamiliar equipment","Keep caregiver close; demonstrate equipment on doll/caregiver first; toe-to-head exam order"],["Preschool (4–5 yr)","Bodily injury, the unknown, magical thinking","Simple honest explanations; allow choices where possible; involve caregiver"],["School-age (6–12 yr)","Loss of control, being different from peers","Direct honest explanation; involve child in decisions; respect modesty"],["Adolescent (13–18 yr)","Privacy, body image, independence","Privacy and respect; consider interviewing partly apart from caregivers; honesty about findings"]]}]},"c02":{"chapter":"c02","tables":[{"id":"c02_t01","title":"Pediatric Assessment Triangle — Legs and Findings","headers":["Leg","Mnemonic/Focus","Normal","Abnormal"],"rows":[["Appearance","TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry","Alert, interactive, consolable, strong cry/speech","Limp, uninterested, inconsolable, weak/absent cry"],["Work of Breathing","Sounds, position, retractions, flaring, head bobbing","Quiet, comfortable position, no retractions","Stridor/grunting/wheeze, tripod position, retractions, flaring, head bobbing"],["Circulation to Skin","Color compared to baseline","Pink, normal color for the child","Pallor, mottling, cyanosis"]]},{"id":"c02_t02","title":"PAT Pattern → Likely Category","headers":["Abnormal Leg(s)","Likely Category","Urgency"],"rows":[["Appearance only","CNS/metabolic problem","Elevated"],["Appearance + Work of Breathing","Respiratory problem","Urgent"],["Appearance + Circulation to Skin","Shock/circulatory problem","Urgent"],["Appearance + Work of Breathing + Circulation to Skin","Cardiopulmonary failure","Highest — immediate action"],["None (all normal)","Reassuring general impression","Routine pace"]]}]},"c03":{"chapter":"c03","tables":[{"id":"c03_t01","title":"Pediatric ABCDE Primary Assessment Components","headers":["Step","What's Assessed","Immediate Action if Abnormal"],"rows":[["Airway","Patency, maintainability","Open/clear/position; adjunct if needed"],["Breathing","Rate, effort, sounds, SpO2","Assist ventilation; supplemental oxygen"],["Circulation","Pulse, perfusion, capillary refill, bleeding","Control hemorrhage; support perfusion"],["Disability","Neuro status (AVPU), pupils, glucose if altered","Treat identified cause (e.g., glucose for hypoglycemia)"],["Exposure","Injury/rash survey","Re-cover promptly to prevent heat loss"]]}]},"c04":{"chapter":"c04","tables":[{"id":"c04_t01","title":"SAMPLE History Components (Pediatric-Adapted)","headers":["Letter","Element","Pediatric Addition"],"rows":[["S","Signs/Symptoms","Ask the child directly when age-appropriate"],["A","Allergies","Include reactions to foods/environmental allergens common in childhood"],["M","Medications","Include dosing by weight where relevant"],["P","Past medical history","Birth history/developmental milestones (infants); immunization status"],["L","Last oral intake","Important for procedural/anesthesia planning"],["E","Events leading up to incident","Include caregiver supervision context where relevant"]]},{"id":"c04_t02","title":"Exam Order by Developmental Stage","headers":["Stage","Preferred Exam Order","Rationale"],"rows":[["Infant/Toddler","Toe-to-head","Less threatening areas first improves cooperation"],["Preschool","Toe-to-head, or head-to-toe with explanation","Some tolerance for direct explanation begins"],["School-age/Adolescent","Standard head-to-toe","Generally cooperative with direct explanation"]]}]},"c05":{"chapter":"c05","tables":[{"id":"c05_t01","title":"Four Categories of Pediatric Respiratory Compromise","headers":["Category","Classic Finding","Example Causes","Field Treatment Focus"],"rows":[["Upper airway obstruction","Stridor","Croup, foreign body, epiglottitis","Keep calm, position of comfort, minimize agitation"],["Lower airway disease","Wheeze, prolonged expiration","Asthma, bronchiolitis","Nebulized bronchodilator per protocol, position of comfort"],["Lung tissue (parenchymal) disease","Grunting, crackles, diminished breath sounds","Pneumonia, pulmonary edema","Supplemental oxygen, close monitoring for hypoxia"],["Disordered control of breathing","Irregular rate/pattern, no classic sound","CNS problem, toxin, neuromuscular disease","Address underlying cause where possible, support ventilation"]]},{"id":"c05_t02","title":"Respiratory Distress vs Respiratory Failure","headers":["Feature","Distress (Compensating)","Failure (Compensation Failed)"],"rows":[["Work of breathing","Increased (retractions, flaring, grunting)","May appear decreased due to exhaustion"],["Mental status","Generally normal/anxious","Altered — lethargic or unresponsive"],["Color","Usually normal or slightly pale","Cyanosis"],["Respiratory rate/pattern","Tachypnea, regular","Bradypnea or irregular, may have apnea"],["Field priority","Position of comfort, O2, targeted treatment, monitor","Assisted ventilation, rapid transport"]]}]},"c06":{"chapter":"c06","tables":[{"id":"c06_t01","title":"Compensated vs Decompensated Shock","headers":["Feature","Compensated Shock","Decompensated Shock"],"rows":[["Blood pressure","Normal for age","Low for age (late finding)"],["Heart rate","Elevated (tachycardia)","Elevated, may become bradycardic terminally"],["Capillary refill","Delayed (>2 sec)","Markedly delayed"],["Mental status","May be normal or mildly irritable","Often altered — lethargic or unresponsive"],["Field urgency","Treat now — do not wait for BP to drop","Time-critical emergency, immediate escalation"]]},{"id":"c06_t02","title":"Categories of Pediatric Shock","headers":["Category","Mechanism","Example Causes","Priority Field Treatment"],"rows":[["Hypovolemic","Fluid/blood volume loss","Dehydration (vomiting/diarrhea), hemorrhage, burns","Isotonic fluid bolus per protocol"],["Distributive","Abnormal vessel tone/permeability","Septic shock, anaphylactic shock, neurogenic shock (rare)","Fluid bolus (septic); epinephrine (anaphylactic)"],["Cardiogenic","Pump failure","Congenital heart disease, myocarditis, arrhythmia","Cautious fluids, avoid volume overload"],["Obstructive","Physical obstruction to blood flow","Tension pneumothorax, cardiac tamponade, massive PE (rare)","Needle decompression (tension pneumothorax) per protocol"]]}]},"c07":{"chapter":"c07","tables":[{"id":"c07_t01","title":"Sinus Tachycardia vs Supraventricular Tachycardia (SVT)","headers":["Feature","Sinus Tachycardia","SVT"],"rows":[["Rate pattern","Variable, changes with stimulation/treatment","Fixed, does not vary with stimulation"],["Typical rate","Rarely exceeds ~220 bpm (infants)","Often >220 bpm (infants), >180 bpm (older children)"],["Trigger","Clear cause: fever, pain, anxiety, dehydration, shock","Often no clear trigger, may be sudden onset"],["Response to treating cause","Resolves as underlying cause is treated","Does not resolve by treating a triggering illness"],["Field approach","Treat underlying cause","Supportive care; refer to PALS for rhythm-specific treatment if poorly perfusing"]]},{"id":"c07_t02","title":"BLS vs ALS Scope of Practice — Pediatric Cardiac Emergencies","headers":["Intervention","BLS Scope","ALS Scope"],"rows":[["Oxygen administration / BVM ventilation","Yes","Yes"],["AED use for pulseless arrest","Yes","Yes"],["Cardiac monitoring / rhythm interpretation","Limited/not typical","Yes"],["IV/IO access","No","Yes"],["Antiarrhythmic medication administration","No","Yes (per PALS protocols)"],["Manual defibrillation / synchronized cardioversion","No","Yes (per PALS protocols)"]]}]},"c08":{"chapter":"c08","tables":[{"id":"c08_t01","title":"AEIOU-TIPS: Reversible Causes of Altered Mental Status","headers":["Letter","Cause"],"rows":[["A","Alcohol/substance use"],["E","Epilepsy/seizure (postictal state)"],["I","Infection"],["O","Overdose/opioids"],["U","Uremia/metabolic derangement"],["T","Trauma/temperature (hyperthermia/hypothermia)"],["I","Insulin/hypoglycemia"],["P","Psychiatric"],["S","Shock/stroke"]]},{"id":"c08_t02","title":"Simple vs Complex Febrile Seizure","headers":["Feature","Simple Febrile Seizure","Complex Febrile Seizure"],"rows":[["Pattern","Generalized","May be focal"],["Duration","Less than 15 minutes","More than 15 minutes"],["Recurrence","Does not recur within 24 hours","May recur within 24 hours"],["Return to baseline","Yes, afterward","May not return promptly to baseline"],["Level of concern","Generally benign","Warrants higher level of concern/evaluation"]]}]},"c09":{"chapter":"c09","tables":[{"id":"c09_t01","title":"Pediatric vs Adult Trauma Anatomic Differences","headers":["Region","Pediatric Difference","Clinical Implication"],"rows":[["Head","Larger head-to-body ratio","Head injury dominates; increased cervical spine leverage"],["Chest","More pliable, elastic ribcage","Internal injury (pulmonary contusion) can occur without rib fractures"],["Abdomen","Proportionally larger liver/spleen, less ribcage protection","Higher risk of occult blunt abdominal injury; soft exam does not exclude it"],["Overall","Effective compensatory mechanisms","Normal BP can mask significant blood loss; watch perfusion signs"]]}]},"c10":{"chapter":"c10","tables":[{"id":"c10_t01","title":"Common Pediatric Toxidromes","headers":["Toxidrome","Key Findings","Example Exposure"],"rows":[["Opioid","Altered mental status, pinpoint pupils, respiratory depression","Opioid medication"],["Anticholinergic","Altered mental status, dilated pupils, dry flushed skin, tachycardia","Antihistamines, certain plants"],["Cholinergic","Salivation, lacrimation, urination, defecation, GI upset, bradycardia","Organophosphate pesticides"],["Sympathomimetic","Agitation, tachycardia, hypertension, diaphoresis, dilated pupils","Stimulant medications"]]},{"id":"c10_t02","title":"Pediatric Heat Illness vs Hypothermia — Key Field Differences","headers":["Feature","Heat Illness","Hypothermia"],"rows":[["Skin","Hot, flushed (or pale/clammy in heat exhaustion)","Cool/cold, pale"],["Mental status","May be altered in severe heat stroke","May be altered in severe hypothermia"],["Key risk factor","Hot vehicle, high ambient temperature, limited sweating","Cold exposure, limited shivering (infants)"],["Field priority","Remove from heat, active cooling, ABC support","Remove from cold, gentle rewarming, ABC support"]]}]},"c11":{"chapter":"c11","tables":[{"id":"c11_t01","title":"Newborn Resuscitation Decision Thresholds","headers":["Finding","Threshold","Action"],"rows":[["Initial questions","Term + good tone + breathing/crying, all yes","Routine care with mother"],["Initial questions","Any answer is no","Move to warmer, begin initial steps"],["Heart rate after initial steps","< 100 bpm, or apneic/gasping","Begin positive-pressure ventilation (PPV)"],["Heart rate after 30 sec effective PPV","< 60 bpm","Begin chest compressions coordinated with PPV"],["Heart rate after 30 sec effective PPV","≥ 60 bpm","Continue PPV, reassess frequently"]]}]},"c12":{"chapter":"c12","tables":[{"id":"c12_t01","title":"General Concern-Raising Categories (Educational, Non-Diagnostic)","headers":["Category","Example","Appropriate Provider Response"],"rows":[["History-injury-developmental inconsistency","Non-mobile infant reportedly 'rolled off' furniture and fractured a limb","Document objectively, continue care, report per policy"],["Changing history","Different accounts from different caregivers or over time","Document each account exactly as given, report per policy"],["Unexplained delay in seeking care","Significant injury with care sought well after expected","Document timeline discrepancy, continue care, report per policy"],["Unusual injury pattern/location","Pattern atypical for the reported mechanism","Document objectively, avoid speculative conclusions, report per policy"]]}]},"c13":{"chapter":"c13","tables":[{"id":"c13_t01","title":"Common Pediatric Medical Technology and Field Concerns","headers":["Device","Purpose","Common Field Concerns"],"rows":[["Tracheostomy","Surgical airway bypassing upper airway","Mucus plugging, accidental decannulation, tube malposition"],["Gastrostomy (G-) tube","Enteral feeding into the stomach","Dislodgement, leakage; rarely acute unless peritoneal signs present"],["Ventriculoperitoneal (VP) shunt","Diverts CSF to treat hydrocephalus","Malfunction causing increased intracranial pressure"],["Central venous catheter","Vascular access for frequent IV therapy","Infection signs, line malfunction"],["Home ventilator","Mechanical ventilation via tracheostomy","Device-specific malfunction; caregiver usually expert in troubleshooting"]]}]},"c14":{"chapter":"c14","tables":[{"id":"c14_t01","title":"JumpSTART Pediatric MCI Triage Categories","headers":["Category","Color","Criteria"],"rows":[["Minor","Green","Able to walk (use judgment for infants/toddlers not yet walking at baseline)"],["Immediate","Red","Apneic but breathing resumes with airway repositioning or 5 rescue breaths; abnormal respiratory rate for age; abnormal perfusion or AVPU with normal respiratory rate"],["Delayed","Yellow","Normal respiratory rate for age, normal perfusion, and normal AVPU"],["Expectant","Black/Gray","Apneic with no pulse; or apneic with pulse that does not resume breathing after 5 rescue breaths"]]},{"id":"c14_t02","title":"JumpSTART vs Adult START — Key Differences","headers":["Feature","Adult START","JumpSTART (Pediatric)"],"rows":[["Respiratory rate threshold","Adult-specific cutoff (e.g., >30/min = immediate)","Pediatric-specific thresholds by age"],["Apneic patient with a pulse","Reposition airway once; if still apneic, expectant","Reposition airway; if still apneic, give 5 rescue breaths before expectant"],["Mental status assessment","Ability to follow commands","AVPU scale (developmentally appropriate)"],["Rationale for adjustments","N/A","Reflects that pediatric arrest is often respiratory in origin and potentially reversible"]]}]}}};
